const QDATA={"items": [{"id": "U115-1", "year": 115, "no": 1, "type": "詞彙", "stem": "The mayor has such a ___ schedule that it takes weeks to arrange an interview with her.", "options": ["hasty", "tight", "diligent", "routine"], "answer": "B", "passageRef": null, "explain": "市長行程滿檔到「要等好幾週才約得到訪問」，所以要選 tight（緊湊的），tight schedule 是英文常見搭配詞組。hasty 是「匆忙草率的」、diligent 是「勤勉的」、routine 是「例行的」，都跟「滿檔、排不進去」的語意不合。", "keyPoint": "字義：tight schedule 行程緊湊", "skip": false}, {"id": "U115-2", "year": 115, "no": 2, "type": "詞彙", "stem": "Jane started as an ___ art designer, but now she has a professional studio of her own.", "options": ["official", "instant", "amateur", "elementary"], "answer": "C", "passageRef": null, "explain": "句子前後有明顯對比：一開始是 ___ art designer，但現在（now）已經有自己的專業工作室，可推知一開始是「業餘的」amateur，才會跟後面 professional 形成反差。official 是「官方的」、instant 是「立即的」、elementary 是「初階／基礎的」，都不符合這種今昔對比。", "keyPoint": "字義：amateur 業餘的（對比 professional）", "skip": false}, {"id": "U115-3", "year": 115, "no": 3, "type": "詞彙", "stem": "The teaching ___ at the famous high school soon attracted more than a dozen well-qualified applicants.", "options": ["career", "vacancy", "expectation", "inspiration"], "answer": "B", "passageRef": null, "explain": "句意是「這所名校的教職 ___ 很快吸引了十幾位條件優秀的應徵者」，applicants（應徵者）呼應的一定是「職缺」vacancy。career 是「生涯」、expectation 是「期望」、inspiration 是「靈感」，都不是應徵者會去應徵的對象。", "keyPoint": "字義：vacancy 職缺", "skip": false}, {"id": "U115-4", "year": 115, "no": 4, "type": "詞彙", "stem": "Designed by a young engineer, the new product has created far more profit than ___ expected.", "options": ["initially", "genuinely", "alternatively", "fundamentally"], "answer": "A", "passageRef": null, "explain": "句意是「這項新產品所創造的利潤，遠超過『當初』預期」，用 initially 才能點出「一開始預期 vs. 後來實際結果」的落差。genuinely「真正地」、alternatively「另一方面／作為替代」、fundamentally「根本上」，語意都對不上這種時間對比。", "keyPoint": "字義：initially 起初（暗示與後來結果的落差）", "skip": false}, {"id": "U115-5", "year": 115, "no": 5, "type": "詞彙", "stem": "It has been confirmed that a balanced ___ of fruit and vegetables is a key element to good health.", "options": ["dimension", "integration", "provision", "consumption"], "answer": "D", "passageRef": null, "explain": "句意是「均衡『攝取』蔬果是健康的關鍵」，consumption 在飲食脈絡中指「攝取量」，是固定用法（如 food consumption）。dimension 是「面向」、integration 是「整合」、provision 是「供應／準備」，都不是「吃下多少」的意思。", "keyPoint": "字義：consumption 攝取（飲食用法）", "skip": false}, {"id": "U115-6", "year": 115, "no": 6, "type": "詞彙", "stem": "As a shy boy afraid of making public appearances, Timmy ___ the thought of speaking before large audiences.", "options": ["dreads", "stresses", "wanders", "escapes"], "answer": "A", "passageRef": null, "explain": "前面已經說 Timmy 是「害怕公開露面的害羞男孩」（afraid of making public appearances），所以他一想到要在大眾面前演講就會 dread（害怕、畏懼）這個念頭，前後呼應。stresses 是「強調」、wanders 是「遊蕩」、escapes 是「逃離」，都不合邏輯。", "keyPoint": "字義：dread 害怕（呼應 afraid）", "skip": false}, {"id": "U115-7", "year": 115, "no": 7, "type": "詞彙", "stem": "To the newly-crowned winner of the piano competition, music is his life's ___, which he has devoted himself to whole-heartedly.", "options": ["resource", "impact", "passion", "emphasis"], "answer": "C", "passageRef": null, "explain": "句意是「音樂是他人生的 ___，他全心投入其中」，passion（熱情）才能跟「全心投入」whole-heartedly 呼應。resource 是「資源」、impact 是「影響」、emphasis 是「強調重點」，都不是「全心投入的對象」該用的詞。", "keyPoint": "字義：passion 熱情", "skip": false}, {"id": "U115-8", "year": 115, "no": 8, "type": "詞彙", "stem": "The drunk driver who shouted at passers-by and ___ them with glass bottles was quickly arrested by the police.", "options": ["shattered", "assaulted", "overturned", "condemned"], "answer": "B", "passageRef": null, "explain": "句意是「這名酒駕者對路人大吼，並用玻璃瓶『攻擊』他們」，assault 專門用於攻擊「人」，符合受詞是 passers-by（路人）。shattered 通常是「打碎（物品）」、overturned 是「推翻／打翻」、condemned 是「譴責」，語意或搭配都不合。", "keyPoint": "字義：assault 攻擊（人）", "skip": false}, {"id": "U115-9", "year": 115, "no": 9, "type": "詞彙", "stem": "There were so many people at the bus station that I had to ___ my way through the crowd to board the bus in time.", "options": ["crash", "tumble", "elbow", "struggle"], "answer": "C", "passageRef": null, "explain": "elbow 當動詞指「用手肘推擠」，elbow my way through the crowd 是固定說法，形容人多時擠過人群趕上公車。crash 是「猛撞」、tumble 是「跌倒翻滾」、struggle 雖然也表示「掙扎」，但慣用搭配應是 elbow one's way，語感最貼切具體。", "keyPoint": "片語：elbow one's way through 用手肘擠出一條路", "skip": false}, {"id": "U115-10", "year": 115, "no": 10, "type": "詞彙", "stem": "Deadly shootings on US campuses have raised ___ concerns about how to prevent such tragic incidents from happening again.", "options": ["swift", "brutal", "harsh", "grave"], "answer": "D", "passageRef": null, "explain": "句意是「校園槍擊案引發了人們對如何防止悲劇再發生的 ___ 疑慮」，grave 作形容詞時意思是「嚴重的」，grave concerns 是常見搭配。swift 是「迅速的」、brutal 是「殘暴的」、harsh 是「嚴厲的」，都不是形容「疑慮程度深」的正確用字。", "keyPoint": "字義：grave concerns 嚴重的疑慮", "skip": false}, {"id": "U115-11", "year": 115, "no": 11, "type": "綜合測驗", "stem": "White rhinoceroses, ___, do the same thing—only their choice of meeting place is a giant pile of poop.", "options": ["what is more", "it turns out", "in other words", "all in all"], "answer": "B", "passageRef": "115-P1", "explain": "前段講人類會聚在一起分享消息，這句用插入語 it turns out（結果、原來如此）帶出一個令人意外的事實：白犀牛也做同樣的事，只是聚會地點是糞堆。what is more「此外」、in other words「換句話說」、all in all「總而言之」都不是用來引出新發現、轉折語氣不對。", "keyPoint": "插入語：it turns out 結果原來", "skip": false}, {"id": "U115-12", "year": 115, "no": 12, "type": "綜合測驗", "stem": "A new study indicates that rhinos have a smelly way to ___.", "options": ["demonstrate", "immigrate", "communicate", "manipulate"], "answer": "C", "passageRef": "115-P1", "explain": "全段主旨就是犀牛用糞便留言、彼此溝通，所以是「用臭臭的方式來 communicate（溝通）」，緊扣後文 leave messages in their poop。demonstrate 是「展示」、immigrate 是「遷移」、manipulate 是「操控」，都偏離「傳遞訊息」這個主題。", "keyPoint": "字義：communicate 溝通（呼應下文 leave messages）", "skip": false}, {"id": "U115-13", "year": 115, "no": 13, "type": "綜合測驗", "stem": "different rhinos leave different chemicals in their poop, which provide important ___ about the age, sex, general health, and reproductive conditions", "options": ["doubts", "icons", "matches", "clues"], "answer": "D", "passageRef": "115-P1", "explain": "不同犀牛糞便中的化學物質提供了關於年齡、性別、健康、繁殖狀況等重要「線索」clues，讓其他犀牛能判讀資訊。doubts 是「疑慮」、icons 是「圖示」、matches 是「火柴／比賽」，都不符合「提供資訊」的語境。", "keyPoint": "字義：clues 線索", "skip": false}, {"id": "U115-14", "year": 115, "no": 14, "type": "綜合測驗", "stem": "When all members in a group know what's going on with each other, it is ___ that they will fight.", "options": ["hardly surprising", "more acceptable", "truly important", "less likely"], "answer": "D", "passageRef": "115-P1", "explain": "前面說糞便訊息有助於維持群體和諧（peace and harmony），所以當大家都清楚彼此狀況時，理應「較不可能」less likely 打架，因果邏輯通順。hardly surprising「一點都不意外」語意矛盾、more acceptable「更可以接受」與 truly important「真的很重要」都文不對題。", "keyPoint": "邏輯：因果關係（互相了解 → 較不會打架）", "skip": false}, {"id": "U115-15", "year": 115, "no": 15, "type": "綜合測驗", "stem": "dominant males are particularly ___ the \"fake poop\" that carries chemicals from females ready to mate.", "options": ["responsive to", "annoyed at", "considerate of", "tolerant with"], "answer": "A", "passageRef": "115-P1", "explain": "後文描述雄犀牛對假糞便嗅聞更久、更頻繁回訪，顯示牠們對含有母犀牛發情化學物質的假糞便「反應強烈」，responsive to 正是「對……敏感有反應」。annoyed at「生氣」、considerate of「體貼」、tolerant with「容忍」都不符合牠們主動、積極的反應。", "keyPoint": "片語：responsive to 對……有反應", "skip": false}, {"id": "U115-16", "year": 115, "no": 16, "type": "綜合測驗", "stem": "Teahouses thus sprang up to ___ the weary travelers, offering them a cup of tea to help them regain energy.", "options": ["accommodate", "compensate", "anticipate", "reinforce"], "answer": "A", "passageRef": "115-P2", "explain": "茶館興起是為了「招待、照顧」accommodate 疲憊的旅人，提供茶水讓他們恢復元氣，語意通順。compensate 是「補償」、anticipate 是「預期」、reinforce 是「加強」，都不是「開店服務旅人」該用的字。", "keyPoint": "字義：accommodate 提供服務／照顧需求", "skip": false}, {"id": "U115-17", "year": 115, "no": 17, "type": "綜合測驗", "stem": "But the culinary art of dim sum ___, for it was considered inappropriate to pair tea with food.", "options": ["would hardly develop", "had yet to develop", "was fast developing", "had almost developed"], "answer": "B", "passageRef": "115-P2", "explain": "for 引導的原因子句說明「當時認為茶配食物不恰當」，所以點心的烹飪藝術當時「尚未發展」had yet to develop，固定句型 have/had yet to + 原形（表「尚未…」）表示在那個時間點之前還沒發生。would hardly develop（幾乎不會發展）語氣太絕對、was fast developing（正快速發展）與 had almost developed（幾乎已發展完成）都跟後面「因為不搭配」的原因矛盾。", "keyPoint": "固定句型 had yet to（尚未）", "skip": false}, {"id": "U115-18", "year": 115, "no": 18, "type": "綜合測驗", "stem": "Dim sum is more than just an example of Chinese cuisine. It is ___ an enjoyable dining experience that can span hours.", "options": ["passed on to", "brought up as", "thought to have", "meant to be"], "answer": "D", "passageRef": "115-P2", "explain": "前一句說點心不只是一種中式料理，這句用 meant to be（其本質／用意是要成為）帶出「它其實是一種可以耗上數小時的愉快用餐體驗」，語氣強調本質。passed on to「傳承給」、brought up as「被養育／提出為」、thought to have「被認為擁有」，搭配或語意都不通順。", "keyPoint": "片語：meant to be 本質上是／意在成為", "skip": false}, {"id": "U115-19", "year": 115, "no": 19, "type": "綜合測驗", "stem": "The small portions were designed to merely \"touch the heart,\" as the name literally means, and ___ were first enjoyed as snacks.", "options": ["if so", "as such", "by then", "in that"], "answer": "B", "passageRef": "115-P2", "explain": "as such 指代前面提到的性質（份量小、只求「觸動人心」），意思是「正因如此」，所以點心最初才被當作零食享用，前後承接自然。if so「如果是這樣」、by then「到那時」、in that「因為」(通常接子句)，用法或邏輯都不搭配這裡的句型。", "keyPoint": "轉承語：as such 就此而言／因此", "skip": false}, {"id": "U115-20", "year": 115, "no": 20, "type": "綜合測驗", "stem": "It is customary for big groups to enjoy simple dishes together as ___.", "options": ["a widely known delicacy", "an intimate romantic dinner", "a joyful social activity", "an amazing local cuisine"], "answer": "C", "passageRef": "115-P2", "explain": "全文強調點心的重點是「用餐體驗」而非食物本身，大團體一起吃簡單的點心，正是一種「歡樂的社交活動」a joyful social activity，呼應主旨。a widely known delicacy「知名佳餚」偏向食物本身、an intimate romantic dinner「浪漫晚餐」不合大團體情境、an amazing local cuisine「特色在地料理」同樣偏重食物而非社交，皆不合。", "keyPoint": "語意呼應：社交活動而非單純美食", "skip": false}, {"id": "U115-21", "year": 115, "no": 21, "type": "文意選填", "stem": "Taking a nap in the middle of the day is by no means (21).", "options": ["retain", "depend on", "atmosphere", "delay", "unproductive", "risk", "function", "minimal", "dramatic", "point to"], "answer": "E", "passageRef": "115-P3", "explain": "句意是「白天小睡『絕不是』___ 的」，by no means 後面接形容詞，語氣是為午睡「平反」——很多人覺得罪惡感，但其實午睡並非沒有用（unproductive），呼應後文「讓身心充電」的正面說法。", "keyPoint": "詞彙選填：unproductive 沒有生產力的（形容詞）", "skip": false}, {"id": "U115-22", "year": 115, "no": 22, "type": "文意選填", "stem": "Research has shown that napping is linked with brain size and (22); specifically, it can boost our cognition and memory.", "options": ["retain", "depend on", "atmosphere", "delay", "unproductive", "risk", "function", "minimal", "dramatic", "point to"], "answer": "G", "passageRef": "115-P3", "explain": "brain size and (22) 是兩個並列名詞，且下文說可以提升認知與記憶，所以應填「腦部功能」function，與 brain size 平行對應，指午睡跟腦的大小與功能都有關聯。", "keyPoint": "詞彙選填：function 功能（名詞，與 brain size 並列）", "skip": false}, {"id": "U115-23", "year": 115, "no": 23, "type": "文意選填", "stem": "our brain starts shrinking, which gradually slows cognition and increases dementia (23) in later life.", "options": ["retain", "depend on", "atmosphere", "delay", "unproductive", "risk", "function", "minimal", "dramatic", "point to"], "answer": "F", "passageRef": "115-P3", "explain": "句意是「腦部萎縮會逐漸減緩認知能力，並提高日後罹患失智症的 ___」，dementia risk（失智症風險）是常見搭配，符合「增加風險」increases...risk 的用法。", "keyPoint": "詞彙選填：risk 風險（搭配 dementia risk）", "skip": false}, {"id": "U115-24", "year": 115, "no": 24, "type": "文意選填", "stem": "This suggests that napping may significantly (24) age-related brain shrinkage, and thus lower the possibility of developing dementia.", "options": ["retain", "depend on", "atmosphere", "delay", "unproductive", "risk", "function", "minimal", "dramatic", "point to"], "answer": "D", "passageRef": "115-P3", "explain": "承接上文，習慣午睡者腦部萎縮較輕，所以此句推論午睡可能「顯著延緩」delay 與年齡相關的腦部萎縮，進而降低失智風險，因果邏輯清楚。", "keyPoint": "詞彙選填：delay 延緩（動詞）", "skip": false}, {"id": "U115-25", "year": 115, "no": 25, "type": "文意選填", "stem": "For students cramming for college exams, napping will help (25) acquired knowledge and learned skills.", "options": ["retain", "depend on", "atmosphere", "delay", "unproductive", "risk", "function", "minimal", "dramatic", "point to"], "answer": "A", "passageRef": "115-P3", "explain": "句意是「午睡有助於 ___ 已習得的知識與技能」，retain（保留、記住）正好呼應前文提到午睡能增強記憶力與學習效果，是準備考試的學生最需要的效果。", "keyPoint": "詞彙選填：retain 保留（記憶、知識）", "skip": false}, {"id": "U115-26", "year": 115, "no": 26, "type": "文意選填", "stem": "Some studies recommend napping for 20 to 40 minutes, while others (26) shorter naps, such as 15 to 20 minutes.", "options": ["retain", "depend on", "atmosphere", "delay", "unproductive", "risk", "function", "minimal", "dramatic", "point to"], "answer": "J", "passageRef": "115-P3", "explain": "前半句說有些研究建議睡 20-40 分鐘，此句用 while others (26) shorter naps 表示「其他研究則指向／建議」較短的午睡時間（15-20分鐘），point to 帶有「指出、建議」的意思，與 recommend 同義呼應。", "keyPoint": "詞彙選填：point to 指向、建議", "skip": false}, {"id": "U115-27", "year": 115, "no": 27, "type": "文意選填", "stem": "The best nap length, however, may (27) a person's physical condition and fatigue level.", "options": ["retain", "depend on", "atmosphere", "delay", "unproductive", "risk", "function", "minimal", "dramatic", "point to"], "answer": "B", "passageRef": "115-P3", "explain": "句意是「最佳午睡長度可能『取決於』一個人的身體狀況與疲勞程度」，depend on 後面直接接受詞（a person's physical condition...），語法與語意都通順。", "keyPoint": "詞彙選填：depend on 取決於", "skip": false}, {"id": "U115-28", "year": 115, "no": 28, "type": "文意選填", "stem": "For some people, even a five-minute nap can bring about surprisingly (28) benefits.", "options": ["retain", "depend on", "atmosphere", "delay", "unproductive", "risk", "function", "minimal", "dramatic", "point to"], "answer": "I", "passageRef": "115-P3", "explain": "句意是「即使只睡五分鐘，也可能帶來令人驚訝地 ___ 的好處」，surprisingly 修飾的形容詞應選 dramatic（顯著、驚人的），強調效果出乎意料地明顯。", "keyPoint": "詞彙選填：dramatic 顯著的、戲劇性的", "skip": false}, {"id": "U115-29", "year": 115, "no": 29, "type": "文意選填", "stem": "So, find yourself a quiet place with (29) light or with blackout curtains.", "options": ["retain", "depend on", "atmosphere", "delay", "unproductive", "risk", "function", "minimal", "dramatic", "point to"], "answer": "H", "passageRef": "115-P3", "explain": "句意是「找一個光線 ___ 或有遮光窗簾的安靜地方」，minimal light（極少的光線）符合「找暗室午睡」的建議，與後面 blackout curtains（遮光窗簾）並列呼應。", "keyPoint": "詞彙選填：minimal 極少的（修飾 light）", "skip": false}, {"id": "U115-30", "year": 115, "no": 30, "type": "文意選填", "stem": "You can also add some soothing nature sounds to create a relaxing (30), which can make your naps more effective.", "options": ["retain", "depend on", "atmosphere", "delay", "unproductive", "risk", "function", "minimal", "dramatic", "point to"], "answer": "C", "passageRef": "115-P3", "explain": "句意是「加入舒緩的大自然聲音，營造放鬆的 ___」，create a relaxing atmosphere（營造放鬆氛圍）是常見搭配，呼應前面談論午睡環境的段落主旨。", "keyPoint": "詞彙選填：atmosphere 氛圍", "skip": false}, {"id": "U115-31", "year": 115, "no": 31, "type": "篇章結構", "stem": "第31格（第二段開頭）：___ In the West, for example, portraits of men and women before the 1700s typically depicted them with a serious, unsmiling expression.", "options": ["Another crucial factor is a society's immigration diversity.", "Various factors have thus contributed to the phenomenon of smiling.", "For most of recorded human history, the open smile has been deeply unfashionable.", "A genuine smile indicates contentment, while a forced smile suggests underlying distress.", "In fact, there is a well-known Russian proverb that goes, \"Smiling with no reason is a sign of stupidity.\""], "answer": "C", "passageRef": "115-P4", "explain": "第二段接下來馬上用 In the West, for example 舉例，說明 1700 年以前歐美肖像畫都是嚴肅不笑的臉，因此空格要填一個能被「舉例」支撐的主題句：『在人類大部分的歷史紀錄中，開懷大笑一直是不流行的』(C)，才能順接後面的西方例子。", "keyPoint": "篇章結構：主題句＋舉例（For example 呼應）", "skip": false}, {"id": "U115-32", "year": 115, "no": 32, "type": "篇章結構", "stem": "第32格（第三段末）：in certain cultures the same person can be judged as less intelligent when smiling. ___", "options": ["Another crucial factor is a society's immigration diversity.", "Various factors have thus contributed to the phenomenon of smiling.", "For most of recorded human history, the open smile has been deeply unfashionable.", "A genuine smile indicates contentment, while a forced smile suggests underlying distress.", "In fact, there is a well-known Russian proverb that goes, \"Smiling with no reason is a sign of stupidity.\""], "answer": "E", "passageRef": "115-P4", "explain": "前一句說某些文化認為笑代表不聰明，接著需要一個具體佐證，選項 E「俄羅斯有句諺語：『無故發笑是愚蠢的象徵』」正好是最直接的實例，呼應並強化前一句的說法。", "keyPoint": "篇章結構：具體例證（諺語）", "skip": false}, {"id": "U115-33", "year": 115, "no": 33, "type": "篇章結構", "stem": "第33格（第四段中）：the needs and rights of the individual take precedence over those of the group. ___ Newcomers from different parts of the world are found to smile more.", "options": ["Another crucial factor is a society's immigration diversity.", "Various factors have thus contributed to the phenomenon of smiling.", "For most of recorded human history, the open smile has been deeply unfashionable.", "A genuine smile indicates contentment, while a forced smile suggests underlying distress.", "In fact, there is a well-known Russian proverb that goes, \"Smiling with no reason is a sign of stupidity.\""], "answer": "A", "passageRef": "115-P4", "explain": "前面在講個人主義高、人口少的國家人們笑得比較多，此句需要轉入下一個影響因素，選項 A「另一個關鍵因素是社會的移民多樣性」剛好承接後面『來自不同地方的新移民笑得更多』的敘述，是銜接段落的過渡句。", "keyPoint": "篇章結構：新因素承接（immigration diversity → newcomers）", "skip": false}, {"id": "U115-34", "year": 115, "no": 34, "type": "篇章結構", "stem": "第34格（末段開頭）：___ As many psychologists now point out, this simple gesture is in fact far more complicated than it may appear.", "options": ["Another crucial factor is a society's immigration diversity.", "Various factors have thus contributed to the phenomenon of smiling.", "For most of recorded human history, the open smile has been deeply unfashionable.", "A genuine smile indicates contentment, while a forced smile suggests underlying distress.", "In fact, there is a well-known Russian proverb that goes, \"Smiling with no reason is a sign of stupidity.\""], "answer": "B", "passageRef": "115-P4", "explain": "末段開頭需要先總結前面提到的牙齒衛生、文化觀念、個人主義、移民多樣性等各種因素，選項 B「各種因素因此造就了微笑這個現象」正好統整全文重點，再接下句『心理學家指出這個簡單手勢其實遠比看起來複雜』。", "keyPoint": "篇章結構：末段總結句", "skip": false}, {"id": "U115-35", "year": 115, "no": 35, "type": "閱讀測驗", "stem": "What is this passage mainly about?", "options": ["A renowned Antarctic explorer.", "The extreme weather in Antarctica.", "A challenging voyage to Antarctica.", "The amazing discovery of a sunken ship."], "answer": "C", "passageRef": "115-P5", "explain": "全文雖以沉船被發現開場，但主體大篇幅描述 Shackleton 團隊受困浮冰、棄船、划船求生、跨海求援的艱辛過程，主旨應是「一趟充滿挑戰的南極航程」(C)。選項 A 過於侷限在人物介紹、B 只是文中一個細節（極端氣候）、D 只是文章的引子而非全文重點，故不選。", "keyPoint": "主旨題", "skip": false}, {"id": "U115-36", "year": 115, "no": 36, "type": "閱讀測驗", "stem": "Which of the following idioms is closest in meaning to \"exacerbated the situation\" in the third paragraph?", "options": ["Broke the ice.", "Cost an arm and a leg.", "Missed the boat.", "Added fuel to the fire."], "answer": "D", "passageRef": "115-P5", "explain": "exacerbate the situation 意思是「使情況惡化」，最貼近的成語是 add fuel to the fire（火上加油，讓情況更糟）。break the ice 是「打破僵局」、cost an arm and a leg 是「代價很高」、miss the boat 是「錯失良機」，語意都不同。", "keyPoint": "同義片語：exacerbate ≈ add fuel to the fire", "skip": false}, {"id": "U115-37", "year": 115, "no": 37, "type": "閱讀測驗", "stem": "According to the passage, which of the following is true about Shackleton and his Antarctic expedition?", "options": ["His journey lasted more than two years.", "He was the first man to cross over the Antarctic.", "His team camped out on Elephant Island for five months.", "He sent five crew members on a lifeboat to get help from a whaling station."], "answer": "A", "passageRef": "115-P5", "explain": "遠征從 1914年8月4日出發，直到 1916年8月30日才成功救回全員，前後超過兩年，故選 A。B 錯：他們的目標是首次橫越南極，但因船沉未能達成；C 錯：他們是在浮冰上（不是象島）紮營五個月；D 錯：是 Shackleton 本人帶五名船員出海求救，不是「派遣」他人。", "keyPoint": "細節題：時間跨度超過兩年", "skip": false}, {"id": "U115-38", "year": 115, "no": 38, "type": "閱讀測驗", "stem": "Which of the following shows the correct route of the Endurance after leaving South Georgia? (地圖選項)", "options": ["地圖 A", "地圖 B", "地圖 C", "地圖 D"], "answer": "C", "passageRef": "115-P5", "explain": "（本題須參照原卷地圖，官方答案 C）Endurance「船」的航線是：南喬治亞島→向南受困浮冰→被冰北推→最終沉沒於 Weddell Sea，全程未抵象島；抵達象島並折返南喬治亞島的是船員駕救生艇的逃生路線，勿與船的航線混淆。", "keyPoint": "地圖判讀題：依文中航線敘述比對路線圖", "skip": true}, {"id": "U115-39", "year": 115, "no": 39, "type": "閱讀測驗", "stem": "Which question can the passage answer?", "options": ["Where was the first spiral staircase constructed?", "Who was the first designer of the spiral staircase?", "What is the world's most famous spiral staircase?", "Why is the spiral staircase popular in modern times?"], "answer": "D", "passageRef": "115-P6", "explain": "文章末段解釋了鑄鐵、鋼架等新材料如何讓螺旋梯成本降低、更普及，並成為現代豪宅、辦公室愛用的設計，正好回答「為何螺旋梯在現代很受歡迎」(D)。文中並未明確指出「世界第一座」建於何處、設計者是誰，也未提「世界最著名」的螺旋梯，故 A、B、C 皆無法從文中找到答案。", "keyPoint": "主旨／細節題：末段解釋現代普及原因", "skip": false}, {"id": "U115-40", "year": 115, "no": 40, "type": "閱讀測驗", "stem": "What does \"them\" in the third paragraph refer to?", "options": ["Stairs.", "Confines.", "Attackers.", "Defenders."], "answer": "A", "passageRef": "115-P6", "explain": "原句「The defenders...were familiar with the stair pattern and could retreat up them very swiftly」中，them 所指的就是前面提到的 stairs（樓梯），意思是守城者熟悉階梯規律，能迅速沿著樓梯往上撤退，故答案為 A。", "keyPoint": "代名詞指涉：them = stairs（樓梯）", "skip": false}, {"id": "U115-41", "year": 115, "no": 41, "type": "閱讀測驗", "stem": "According to the passage, which is a correct time sequence of the materials used in making spiral staircases?", "options": ["stone → iron → steel → glass", "stone → wood → iron → steel", "iron → marble → wood → glass", "marble → wood → stone → concrete"], "answer": "A", "passageRef": "115-P6", "explain": "依文章時間順序：最古老現存的是石頭／大理石雕刻的圖拉真柱樓梯（stone），維多利亞時代流行鑄鐵（iron），20世紀後半鋼架（steel）成本降低而普及，近年才出現玻璃（glass）材質，故正確順序為 stone → iron → steel → glass (A)。", "keyPoint": "細節題：材質時間順序 stone→iron→steel→glass", "skip": false}, {"id": "U115-42", "year": 115, "no": 42, "type": "閱讀測驗", "stem": "Which of the following statements can be inferred about spiral staircases in the Medieval Ages?", "options": ["The staircase was too narrow to allow any quick retreat.", "The clockwise design favored right-handed castle defenders.", "The uneven steps made it easier to ascend than descend the stairs.", "The staircase was dark enough for defenders to hide from attackers."], "answer": "B", "passageRef": "115-P6", "explain": "文中說樓梯設計成順時針向上，往上爬的人（攻擊者）右手會被夾在最窄、靠近中央柱的一側，難以揮劍；反之，防守者由上往下退時，右手反而在外側、靠牆的寬闊處，可自由揮劍，這正是「順時針設計對慣用右手的守城者有利」(B) 的推論依據。", "keyPoint": "推論題：順時針設計對右撇子守方有利", "skip": false}, {"id": "U115-43", "year": 115, "no": 43, "type": "閱讀測驗", "stem": "What is the passage mainly about?", "options": ["Why east is referred to as the \"Orient.\"", "How maps differ from GPS in function.", "How map orientation evolved over time.", "Why maps were important during the age of exploration."], "answer": "C", "passageRef": "115-P7", "explain": "全文依時間順序介紹地圖朝向的演變：古代東方朝上、古埃及／阿拉伯南方朝上、大航海時代後北方朝上，到現代 GPS 動態朝向，主旨是「地圖方向如何隨時間演變」(C)。其餘選項都只是文中的局部細節，不是全文主旨。", "keyPoint": "主旨題：地圖方向的歷史演變", "skip": false}, {"id": "U115-44", "year": 115, "no": 44, "type": "閱讀測驗", "stem": "What does \"this\" refer to in the second paragraph?", "options": ["The word dakshina.", "Physical evidence.", "Ancient India.", "East-orientation of maps."], "answer": "D", "passageRef": "115-P7", "explain": "第二段先說古印度的地圖很可能以東方朝上，接著寫「雖然沒有實體證據支持 this」，this 指涉的正是前面提到的「地圖以東方為上」這個說法，故答案為 D。", "keyPoint": "代名詞指涉：this = 地圖以東方為上（East-orientation of maps）", "skip": false}, {"id": "U115-45", "year": 115, "no": 45, "type": "閱讀測驗", "stem": "Which of the following is closest in meaning to \"a blip\" in the last paragraph?", "options": ["A temporary state.", "An urgent need.", "A critical decision.", "An advanced system."], "answer": "A", "passageRef": "115-P7", "explain": "a blip 原指雷達螢幕上一閃即逝的訊號點，引申為「短暫、暫時的現象」。文末說「北方朝上或許與其說是規則，不如說只是 a blip」，意思是這個做法只是歷史上暫時流行的現象，並非永恆定律，故最接近的是 A「暫時的狀態」。", "keyPoint": "字義：a blip 短暫的現象", "skip": false}, {"id": "U115-46", "year": 115, "no": 46, "type": "閱讀測驗", "stem": "Which of the following statements is true?", "options": ["Sailors took the North Star as their final destination.", "The GPS system has a fixed direction for orientation.", "South was placed at the top of maps in the pre-Biblical era.", "Old Islamic maps put south at the top for religious purposes."], "answer": "D", "passageRef": "115-P7", "explain": "文中提到「阿拉伯的地圖製作者也把南方畫在上方，因為最早的穆斯林住在麥加以北，南方朝上的地圖能讓信徒『抬頭』望向聖城」，符合選項 D。A 錯：北極星是用來導航定位，不是「最終目的地」；B 錯：GPS 方向是動態隨行進方向改變，並非固定；C 錯：文中提到「東方朝上」才是舊約時代（pre-Biblical）的做法，南方朝上是埃及／阿拉伯的做法。", "keyPoint": "細節題：阿拉伯地圖南方朝上的宗教因素", "skip": false}, {"id": "U115-50", "year": 115, "no": 50, "type": "閱讀測驗", "stem": "While visiting Wonder Village, the Chen family decide to buy: (1) a 19th century oil lamp (2) recycled plastic sunglasses (3) an aboriginal wooden beads necklace. Which stores should they go to for these items? (多選題)", "options": ["Oh Eco", "After Work", "Aroma Paradise", "Something Different", "Beyond World", "The Pinery"], "answer": "A", "passageRef": "115-P8", "explain": "19世紀油燈屬於古董家飾，應到經營傳統風格古董家飾（自1996年營業）的 Something Different (D)；回收塑膠材質太陽眼鏡屬於環保商品，應到販售環保回收商品（如環保瓶、竹牙刷）的 Oh Eco (A)；原住民木珠項鍊屬於在地原住民工藝品，應到只賣在地原住民工匠製品的 Beyond World (E)。故正確答案為 A、D、E。", "keyPoint": "細節配對：依商店特色對應購買需求", "skip": true}, {"id": "U114-1", "year": 114, "no": 1, "type": "詞彙", "stem": "If you put a ______ under a leaking faucet, you will be surprised at the amount of water collected in 24 hours.", "options": ["border", "timer", "container", "marker"], "answer": "C", "passageRef": null, "explain": "句意是「把容器放在漏水的水龍頭下」，用來裝接漏下來的水，所以選 container（容器）。border 是邊界、timer 是計時器、marker 是簽字筆／記號，語意上都無法「接水」，故不選。", "keyPoint": "字義:container 容器", "skip": false}, {"id": "U114-2", "year": 114, "no": 2, "type": "詞彙", "stem": "The local farmers' market is popular as it offers a variety of fresh seasonal ______ to people in the community.", "options": ["produce", "fashion", "brand", "trend"], "answer": "A", "passageRef": null, "explain": "本題 produce 當名詞用，重音在前，意思是「農產品」，農夫市集賣的當然是 fresh seasonal produce（新鮮當季農產品）。fashion 流行、brand 品牌、trend 趨勢都跟「市場賣的東西」對不上，只有 produce 符合。", "keyPoint": "字義:produce 農產品", "skip": false}, {"id": "U114-3", "year": 114, "no": 3, "type": "詞彙", "stem": "As the years have passed by, many of my childhood memories are already ______; I can no longer recall clearly what happened back then.", "options": ["blurring", "trimming", "draining", "glaring"], "answer": "A", "passageRef": null, "explain": "隨著時間過去，童年記憶「已經模糊」，記不清楚細節，故選 blurring（使模糊）。trimming 是修剪、draining 是排乾／耗盡精力、glaring 是刺眼的／怒視的，都不符合「記憶變得不清楚」的語意。", "keyPoint": "字義:blur 模糊", "skip": false}, {"id": "U114-4", "year": 114, "no": 4, "type": "詞彙", "stem": "Racist remarks are by nature ______ and hurtful, and should be avoided on all occasions.", "options": ["excessive", "furious", "offensive", "stubborn"], "answer": "C", "passageRef": null, "explain": "種族歧視言論本質上是「冒犯人的、傷人的」，故選 offensive，且句中 and hurtful（傷人的）也提供對等語意線索。excessive 過度的、furious 狂怒的、stubborn 頑固的都與「言語傷人」無關。", "keyPoint": "字義:offensive 冒犯的", "skip": false}, {"id": "U114-5", "year": 114, "no": 5, "type": "詞彙", "stem": "Not satisfied with the first ______ of her essay, Mary revised it several times before turning it in to the teacher.", "options": ["text", "brush", "draft", "plot"], "answer": "C", "passageRef": null, "explain": "Mary 對論文「第一次的草稿」不滿意，改了好幾次才交出去，故選 draft（草稿）。text 是文本、brush 是畫筆、plot 是故事情節，都不是「寫作過程中會反覆修改的東西」。", "keyPoint": "字義:draft 草稿", "skip": false}, {"id": "U114-6", "year": 114, "no": 6, "type": "詞彙", "stem": "Left ______ for years, the deserted house was filled with a thick coating of dust and a smell of old damp wood.", "options": ["casual", "fragile", "remote", "vacant"], "answer": "D", "passageRef": null, "explain": "房子多年「無人居住、空著」才會積滿灰塵，故選 vacant（空置的）。casual 隨意的、fragile 易碎的、remote 偏遠的都無法形容「多年沒人住」這件事。", "keyPoint": "字義:vacant 空置的", "skip": false}, {"id": "U114-7", "year": 114, "no": 7, "type": "詞彙", "stem": "The high school student showed ______ courage when she helped the old man escape from the fire.", "options": ["gigantic", "exclusive", "multiple", "enormous"], "answer": "D", "passageRef": null, "explain": "enormous courage（極大的勇氣）是常見搭配，可修飾抽象名詞如courage、pressure等；gigantic 雖然也是「巨大的」，但通常形容具體龐大的物體（如建築物），較少接courage。exclusive 獨家的、multiple 多個的則語意不合，故選 enormous。", "keyPoint": "字義:enormous 巨大的(修飾抽象名詞)", "skip": false}, {"id": "U114-8", "year": 114, "no": 8, "type": "詞彙", "stem": "Publicly financed projects are often ______ or delayed during tough economic times due to a lack of resources.", "options": ["halted", "hatched", "possessed", "reinforced"], "answer": "A", "passageRef": null, "explain": "經濟不景氣時，公共建設常「被迫停止」或延後，故選 halted（and delayed 前後為對等的負面結果）。hatched 是孵化／策劃（陰謀）、possessed 是擁有／附身、reinforced 是加強，語意都不合。", "keyPoint": "字義:halt 停止", "skip": false}, {"id": "U114-9", "year": 114, "no": 9, "type": "詞彙", "stem": "Despite his busy schedule, the President ______ the school's graduation ceremony with his presence and a heartwarming speech.", "options": ["praised", "graced", "addressed", "credited"], "answer": "B", "passageRef": null, "explain": "grace + 場合 + with one's presence 是固定用法，意指「賞光／蒞臨某場合」，符合總統百忙之中出席畢業典禮的語境，故選 graced。praised 稱讚、addressed 對…發表演說、credited 把功勞歸於，用法或語意都對不上這個句型。", "keyPoint": "片語:grace ... with one's presence 蒞臨", "skip": false}, {"id": "U114-10", "year": 114, "no": 10, "type": "詞彙", "stem": "The manager of the company was sued for ______ abusing his colleagues, calling them \"hopeless losers.\"", "options": ["verbally", "dominantly", "legitimately", "relevantly"], "answer": "A", "passageRef": null, "explain": "經理被控告「用言語辱罵」同事，罵他們是魯蛇，故選 verbally（口頭地／言語上）。dominantly 支配性地、legitimately 合法地、relevantly 相關地都與「言語辱罵」的方式無關。", "keyPoint": "字義:verbally 言語上地", "skip": false}, {"id": "U114-11", "year": 114, "no": 11, "type": "綜合測驗", "stem": "a social innovation that ______ rapidly around the world", "options": ["had spread", "would spread", "had been spreading", "would have spread"], "answer": "B", "passageRef": "114-P1", "explain": "站在 1995 年那個時間點看「後來會發生的事」，敘述時態要用過去式視角下的未來，即 would + 原形動詞，故選 would spread。had spread／had been spreading 是過去完成式，表示比過去更早發生，語意不合；would have spread 是與過去事實相反的假設，也不對。", "keyPoint": "文法:過去未來式 would + 原形V", "skip": false}, {"id": "U114-12", "year": 114, "no": 12, "type": "綜合測驗", "stem": "With their plan ______ by the rain, the participants squeezed into the living room", "options": ["facilitated", "disrupted", "disclosed", "fulfilled"], "answer": "B", "passageRef": "114-P1", "explain": "原本要在花園辦大型圓桌討論，卻突然下雨，計畫被「打亂」了，才會擠進客廳，故選 disrupted。facilitated 促進、disclosed 揭露、fulfilled 實現都是正面或中性的意思，跟下雨造成的困擾相反。", "keyPoint": "字義:disrupt 打亂", "skip": false}, {"id": "U114-13", "year": 114, "no": 13, "type": "綜合測驗", "stem": "switch tables so the insights and ideas might ______ and deepen", "options": ["circulate", "emphasize", "recover", "preserve"], "answer": "A", "passageRef": "114-P1", "explain": "與會者不斷換桌交流，讓想法能「流通」並加深，故選 circulate（流通、傳播），和後面 deepen（加深）並列，形容想法擴散又深化的過程。emphasize 強調、recover 恢復、preserve 保存都不符合「想法在人群間流動」的概念。", "keyPoint": "字義:circulate 流通/傳播", "skip": false}, {"id": "U114-14", "year": 114, "no": 14, "type": "綜合測驗", "stem": "the innovative discussion process ______ a new form of collective effort", "options": ["made up for", "kept track of", "gave rise to", "looked out for"], "answer": "C", "passageRef": "114-P1", "explain": "這個創新的討論過程「催生／引發」了一種全新的集體合作形式，故選 gave rise to（引發、產生）。made up for 彌補、kept track of 追蹤記錄、looked out for 留意提防，語意皆不合。", "keyPoint": "片語:give rise to 引發", "skip": false}, {"id": "U114-15", "year": 114, "no": 15, "type": "綜合測驗", "stem": "The World Café was ______ created", "options": ["still", "also", "further", "thus"], "answer": "D", "passageRef": "114-P1", "explain": "前文說明因下雨而意外促成了換桌交流的創新討論方式，這裡用 thus（因此）承接前因後果，總結「世界咖啡館」就是這樣被創造出來的。still 仍然、also 也、further 進一步，都不能表達「因果總結」的邏輯關係。", "keyPoint": "轉承語:thus 因此", "skip": false}, {"id": "U114-16", "year": 114, "no": 16, "type": "綜合測驗", "stem": "It can ______ suddenly, progressing from a feeling of uneasiness to a cold sweat", "options": ["crash", "flush", "burst", "strike"], "answer": "D", "passageRef": "114-P2", "explain": "strike 常用來形容疾病、災難等「突然來襲」，暈車感覺可能瞬間發作，從不適感一路惡化到冒冷汗，故選 strike。crash 是撞毀、flush 是沖水／臉紅發熱、burst 是爆裂，都不是形容「症狀發作」的慣用字。", "keyPoint": "字義:strike 突然侵襲/發作", "skip": false}, {"id": "U114-17", "year": 114, "no": 17, "type": "綜合測驗", "stem": "when the signals your brain receives from your eyes, ears, and body ______", "options": ["are not regular", "can hardly move", "do not match", "are rarely cued"], "answer": "C", "passageRef": "114-P2", "explain": "暈車是因為眼睛、耳朵、身體傳給大腦的訊號「不一致、對不上」，大腦因此無法判斷到底有沒有在動，故選 do not match。are not regular 不規律、can hardly move 幾乎不能動、are rarely cued 很少被提示，都無法準確表達「訊號互相矛盾」的意思。", "keyPoint": "字義:match 吻合", "skip": false}, {"id": "U114-18", "year": 114, "no": 18, "type": "綜合測驗", "stem": "one part detects that your body is moving, but the other parts ______", "options": ["aren't", "won't", "don't", "haven't"], "answer": "C", "passageRef": "114-P2", "explain": "前半句說一部分感覺系統偵測到身體在動（detects），but 之後另一部分「沒有偵測到」，用助動詞 don't 代替省略的 don't detect，且主詞 parts 為複數、現在式，故選 don't。aren't／won't／haven't 在時態或動詞替代上都不吻合。", "keyPoint": "文法:助動詞代替前述動詞 don't", "skip": false}, {"id": "U114-19", "year": 114, "no": 19, "type": "綜合測驗", "stem": "You can take some ______ to help avoid the discomfort", "options": ["special opportunities", "preventive measures", "potential risks", "significant advantages"], "answer": "B", "passageRef": "114-P2", "explain": "後文緊接著列出「坐前排、看遠方、吃藥」等具體做法，可知這裡是指採取「預防性措施」來避免不適，故選 preventive measures。special opportunities 特殊機會、potential risks 潛在風險、significant advantages 顯著優勢，皆與「預防暈車的方法」無關。", "keyPoint": "詞組:preventive measures 預防措施", "skip": false}, {"id": "U114-20", "year": 114, "no": 20, "type": "綜合測驗", "stem": "Looking out into the distance from the vehicle can help ______", "options": ["as well", "by far", "at least", "after all"], "answer": "A", "passageRef": "114-P2", "explain": "前文已提到「坐在震動感最小的位置」是一種方法，這句再補充「看向遠方也有幫助」，as well（也、同樣）用來表示並列的另一個有效方法。by far 遠遠地（強調最高級）、at least 至少、after all 畢竟，語意都不合。", "keyPoint": "副詞片語:as well 也", "skip": false}, {"id": "U114-21", "year": 114, "no": 21, "type": "文意選填", "stem": "第21格：this medieval cathedral is ______ for its intricate architecture", "options": ["reference", "bearing", "familiar", "retained", "faithful", "survived", "celebration", "restoration", "noted", "silent"], "answer": "I", "passageRef": "114-P3", "explain": "be noted for 是固定用法，意為「以…聞名」，正好用來形容聖母院以精緻建築、彩繪玻璃和鐘聲聞名於世，故選 noted。", "keyPoint": "文意選填:be noted for 以...聞名", "skip": false}, {"id": "U114-22", "year": 114, "no": 22, "type": "文意選填", "stem": "第22格：there is documented ______ to the ringing of bells", "options": ["reference", "bearing", "familiar", "retained", "faithful", "survived", "celebration", "restoration", "noted", "silent"], "answer": "A", "passageRef": "114-P3", "explain": "documented reference（有文獻紀錄的提及）表示早在教堂完工前，就已有文獻「提到」鐘聲的存在，故選 reference。", "keyPoint": "文意選填:reference 提及/記載", "skip": false}, {"id": "U114-23", "year": 114, "no": 23, "type": "文意選填", "stem": "第23格：The 10 bells vary in size, each ______ a name", "options": ["reference", "bearing", "familiar", "retained", "faithful", "survived", "celebration", "restoration", "noted", "silent"], "answer": "B", "passageRef": "114-P3", "explain": "each bearing a name 是分詞構句，bearing 在此意為「帶有、擁有」，說明每口鐘都各自「帶有」一個名字，故選 bearing。", "keyPoint": "文意選填:bearing a name 帶有名字", "skip": false}, {"id": "U114-24", "year": 114, "no": 24, "type": "文意選填", "stem": "第24格：the only one of the whole group that ______ the French Revolution", "options": ["reference", "bearing", "familiar", "retained", "faithful", "survived", "celebration", "restoration", "noted", "silent"], "answer": "F", "passageRef": "114-P3", "explain": "只有 Emmanuel 這口鐘「撐過了」法國大革命，其餘都被熔掉做武器，故選 survived（倖存、撐過），符合 the only one that... 的語意。", "keyPoint": "文意選填:survive 度過/倖存", "skip": false}, {"id": "U114-25", "year": 114, "no": 25, "type": "文意選填", "stem": "第25格：except for Emmanuel, which ______ its renowned, excellent sound", "options": ["reference", "bearing", "familiar", "retained", "faithful", "survived", "celebration", "restoration", "noted", "silent"], "answer": "D", "passageRef": "114-P3", "explain": "2013年除了 Emmanuel 之外的鐘都因音質不佳被換掉，唯獨 Emmanuel「保留」了它著名的優美音色，故選 retained。", "keyPoint": "文意選填:retain 保留", "skip": false}, {"id": "U114-26", "year": 114, "no": 26, "type": "文意選填", "stem": "第26格：the bells have become a ______ part of life in Paris", "options": ["reference", "bearing", "familiar", "retained", "faithful", "survived", "celebration", "restoration", "noted", "silent"], "answer": "C", "passageRef": "114-P3", "explain": "數百年來鐘聲已成為巴黎人生活中「熟悉」的一部分，故選 familiar，呼應後文「被稱為大教堂的聲音」。", "keyPoint": "文意選填:familiar 熟悉的", "skip": false}, {"id": "U114-27", "year": 114, "no": 27, "type": "文意選填", "stem": "第27格：to call the ______ to prayer", "options": ["reference", "bearing", "familiar", "retained", "faithful", "survived", "celebration", "restoration", "noted", "silent"], "answer": "E", "passageRef": "114-P3", "explain": "call the faithful to prayer 意為「召喚信徒前來禱告」，faithful 在此轉品作名詞，指「信徒」，故選 faithful。", "keyPoint": "文意選填:the faithful 信徒(形容詞轉名詞)", "skip": false}, {"id": "U114-28", "year": 114, "no": 28, "type": "文意選填", "stem": "第28格：They have also rung in times of ______ and of mourning", "options": ["reference", "bearing", "familiar", "retained", "faithful", "survived", "celebration", "restoration", "noted", "silent"], "answer": "G", "passageRef": "114-P3", "explain": "此處與 mourning（哀悼）並列對比，形容鐘聲既為皇室婚禮、加冕等「慶典」時刻敲響，也為喪禮哀悼而鳴，故選 celebration。", "keyPoint": "文意選填:celebration 慶祝(與mourning對比)", "skip": false}, {"id": "U114-29", "year": 114, "no": 29, "type": "文意選填", "stem": "第29格：after the devastating fire, the bells fell ______", "options": ["reference", "bearing", "familiar", "retained", "faithful", "survived", "celebration", "restoration", "noted", "silent"], "answer": "J", "passageRef": "114-P3", "explain": "fall + 形容詞表示「變得…」，2019年大火後鐘聲「陷入沉寂」，故選 silent（沉默的），對應後段修復完成後鐘聲才「再度響起」的呼應。", "keyPoint": "文意選填:fall silent 陷入沉默", "skip": false}, {"id": "U114-30", "year": 114, "no": 30, "type": "文意選填", "stem": "第30格：The building went through a complex and time-consuming process of ______", "options": ["reference", "bearing", "familiar", "retained", "faithful", "survived", "celebration", "restoration", "noted", "silent"], "answer": "H", "passageRef": "114-P3", "explain": "教堂經歷了一段複雜又耗時的「修復」過程才在2024年重新開放，故選 restoration（修復），與前面 fell silent（鐘聲沉寂）前後呼應。", "keyPoint": "文意選填:restoration 修復", "skip": false}, {"id": "U114-31", "year": 114, "no": 31, "type": "篇章結構", "stem": "第31格（第1段末）：these hotels were initially meant for business professionals... ______", "options": ["In response to rising demands, these hotels are embracing a wave of innovation.", "The room's thin plastic walls easily transmit the sound of snoring made by neighboring guests.", "The chambers are stacked side-by-side, two units high, with the upper rooms reached by a ladder.", "Today, they provide low-budget, overnight lodging in commerce centers in large cities worldwide."], "answer": "D", "passageRef": "114-P4", "explain": "前句說膠囊旅館「起初」是為商務人士設計，選項 D「如今，它們在全球各大城市的商業中心提供低價過夜住宿」正好用 Today 呼應 initially，形成時間對比的承接，故選 D。", "keyPoint": "篇章結構:承接「當初 vs 現今」的轉折", "skip": false}, {"id": "U114-32", "year": 114, "no": 32, "type": "篇章結構", "stem": "第32格：walls... are often fiberglass or plastic. ______ Each capsule is equipped with a mattress...", "options": ["In response to rising demands, these hotels are embracing a wave of innovation.", "The room's thin plastic walls easily transmit the sound of snoring made by neighboring guests.", "The chambers are stacked side-by-side, two units high, with the upper rooms reached by a ladder.", "Today, they provide low-budget, overnight lodging in commerce centers in large cities worldwide."], "answer": "C", "passageRef": "114-P4", "explain": "前句描述牆壁材質常是玻璃纖維或塑膠，選項 C「房間如上下舖般並排堆疊，上層需爬梯進入」進一步具體描述膠囊房的空間配置，緊接著下一句又接著描述房內設備（床墊、燈），前後銜接自然，故選 C。", "keyPoint": "篇章結構:承接房間外觀描述細節", "skip": false}, {"id": "U114-33", "year": 114, "no": 33, "type": "篇章結構", "stem": "第33格：big cities like New York, London, and Paris. ______ Instead of the traditional bare pod-sized style...", "options": ["In response to rising demands, these hotels are embracing a wave of innovation.", "The room's thin plastic walls easily transmit the sound of snoring made by neighboring guests.", "The chambers are stacked side-by-side, two units high, with the upper rooms reached by a ladder.", "Today, they provide low-budget, overnight lodging in commerce centers in large cities worldwide."], "answer": "A", "passageRef": "114-P4", "explain": "前句提到膠囊旅館已擴展到歐美各大城市，選項 A「為回應需求增加，這些旅館正掀起一波創新」正好引出下一句「不再是傳統簡樸樣式，而加入吸引數位旅客的室內設計」，故選 A。", "keyPoint": "篇章結構:呼應後文的「創新」", "skip": false}, {"id": "U114-34", "year": 114, "no": 34, "type": "篇章結構", "stem": "第34格：Some hotels may not provide air conditioning... leading to poor air flow. ______ Also, you may have to share common facilities...", "options": ["In response to rising demands, these hotels are embracing a wave of innovation.", "The room's thin plastic walls easily transmit the sound of snoring made by neighboring guests.", "The chambers are stacked side-by-side, two units high, with the upper rooms reached by a ladder.", "Today, they provide low-budget, overnight lodging in commerce centers in large cities worldwide."], "answer": "B", "passageRef": "114-P4", "explain": "前句提到有些膠囊旅館沒有空調、通風差，選項 B「房間單薄的塑膠牆很容易傳出鄰房打鼾聲」是再舉一個缺點（隔音差），與後句 Also, you may have to share... 的並列缺點列舉語氣一致，故選 B。", "keyPoint": "篇章結構:並列另一項缺點", "skip": false}, {"id": "U114-35", "year": 114, "no": 35, "type": "閱讀測驗", "stem": "What is this passage mainly about?", "options": ["The evolution of traffic control systems.", "The inventors of traffic lights in history.", "The functions of different traffic signals.", "The development of modern transportation."], "answer": "A", "passageRef": "114-P5", "explain": "全文從Knight仿鐵路號誌設計的手臂式紅綠燈，講到美國紅黃綠三色燈的發明，再談到自駕車時代交通號誌可能被淘汰，主線是「交通號誌系統的演變」，故選 A。B只談發明者太窄，C只談功能、D範圍太廣（整體交通運輸發展），皆不符全文重點。", "keyPoint": "主旨題", "skip": false}, {"id": "U114-36", "year": 114, "no": 36, "type": "閱讀測驗", "stem": "Which of the following pictures shows Knight's proposed traffic signal? (圖示題)", "options": ["(圖A)", "(圖B)", "(圖C)", "(圖D)"], "answer": "C", "passageRef": "114-P5", "explain": "（本題須參照原卷圖片，此處僅供對答案）文中描述Knight的號誌：手臂水平伸出表示停(stop)，手臂放低到45度角表示通行(move on)，模仿交通指揮手勢，並在夜間加上紅綠燈。符合此描述的圖為(圖C)，故選 C。", "keyPoint": "圖示理解題", "skip": true}, {"id": "U114-37", "year": 114, "no": 37, "type": "閱讀測驗", "stem": "Which of the following statements is true, according to the passage?", "options": ["Knight was injured in the explosion of his traffic light.", "Potts' traffic light was the first one to appear in the USA.", "The first traffic signal originated from the idea of a traffic director.", "Future vehicles may not need traffic lights to cross an intersection."], "answer": "D", "passageRef": "114-P5", "explain": "文末提到隨著自駕車出現，研究者認為未來路口可能不再需要紅綠燈，車輛自動調整車速通過，故選 D。A錯，受傷的是操作號誌的警察而非Knight本人；B錯，文中未說Potts的號誌是美國第一個；C錯，Knight的設計是仿照鐵路訊號臂，只是「像」交通指揮手勢，並非源自交通指揮員。", "keyPoint": "細節/推論題", "skip": false}, {"id": "U114-38", "year": 114, "no": 38, "type": "閱讀測驗", "stem": "Here is a sentence: \"This design was adopted in later traffic light designs across the world.\" Which paragraph is most suitable to have it as the final sentence?", "options": ["Paragraph 1.", "Paragraph 2.", "Paragraph 3.", "Paragraph 4."], "answer": "C", "passageRef": "114-P5", "explain": "「這個設計後來被世界各地的紅綠燈設計採用」最適合放在第三段末，因為第三段最後提到Potts發明的三色（紅黃綠）號誌系統，正是後來被全球廣泛採用的設計，故選 Paragraph 3（C）。", "keyPoint": "文章結構/插入句題", "skip": false}, {"id": "U114-39", "year": 114, "no": 39, "type": "閱讀測驗", "stem": "What field of study does the research mentioned in the passage most likely belong to?", "options": ["Psychology.", "Education.", "Philosophy.", "Communication."], "answer": "A", "passageRef": "114-P6", "explain": "文中研究內容涉及恐懼、焦慮、情緒宣洩、心理創傷等主題，明顯屬於心理學（Psychology）研究範疇，故選 A。教育、哲學、傳播學都與文章討論的內容不符。", "keyPoint": "推論題:研究領域", "skip": false}, {"id": "U114-40", "year": 114, "no": 40, "type": "閱讀測驗", "stem": "What does the author mean by \"learning vicariously\" in the second paragraph?", "options": ["Making inquiries without reservation.", "Gaining knowledge through observation.", "Acquiring insights by face-to-face interaction.", "Obtaining information from personal experience."], "answer": "B", "passageRef": "114-P6", "explain": "文中說觀眾代入角色視角、無意識地演練劇情，是「透過觀察」他人（劇中角色）處理威脅的方式來學習，而非親身經歷，故選 B（Gaining knowledge through observation，透過觀察獲得知識）。", "keyPoint": "字義理解:learning vicariously 替代式學習", "skip": false}, {"id": "U114-41", "year": 114, "no": 41, "type": "閱讀測驗", "stem": "Which of the following statements about horror movies can be inferred from the passage?", "options": ["Most horror movie lovers are prone to aggressive behavior.", "There are far more benefits to horror movies than disadvantages.", "COVID-19 was an important source of inspiration for horror movies.", "Watching horror movies may have a long-term effect on personality."], "answer": "D", "passageRef": "114-P6", "explain": "文末提到14歲以下兒童看恐怖片，成年後罹患焦慮症風險較高，且可能對暴力較不敏感——這些都是「長期影響性格/心理」的證據，故選 D。A、C過度推論原文未明說的因果，B與文章「有利有弊」的論述相反。", "keyPoint": "推論題", "skip": false}, {"id": "U114-42", "year": 114, "no": 42, "type": "閱讀測驗", "stem": "How does the author develop the ideas in this passage?", "options": ["By defining and illustrating a concept.", "By showing opposing views of an issue.", "By presenting cause and effect of a problem.", "By providing steps for settling a disagreement."], "answer": "B", "passageRef": "114-P6", "explain": "文章先列出恐怖片的多項好處（safe fear、替代學習、情緒宣洩），接著另起段落說明其負面影響（焦慮、創傷、睡眠、對兒童的影響），是典型「呈現一議題的正反兩面」寫法，故選 B。", "keyPoint": "寫作手法題:正反並陳", "skip": false}, {"id": "U114-43", "year": 114, "no": 43, "type": "閱讀測驗", "stem": "What is the main purpose of the second paragraph in the passage?", "options": ["To discuss the content of alcoholic drinks in ancient Europe.", "To highlight the French impact on Russians' drinking habits.", "To argue against the assumption that Russians are born drinkers.", "To link Russians' vodka consumption to their adoption of Christianity."], "answer": "C", "passageRef": "114-P7", "explain": "第二段用史實說明：基督教傳入前古俄羅斯沒有葡萄園、沒有酒，伏特加也是後來從法國傳入的葡萄酒精，用意在反駁「俄羅斯人天生愛喝酒」的刻板印象，故選 C。", "keyPoint": "段落主旨題", "skip": false}, {"id": "U114-44", "year": 114, "no": 44, "type": "閱讀測驗", "stem": "Which of the following is true about vodka production?", "options": ["Vodka production in Russia started in the 15th century.", "The first vodka made from wheat was imported from France.", "Germany was the biggest vodka producer in medieval Europe.", "Russian people were encouraged to make their own vodka in the 19th century."], "answer": "A", "passageRef": "114-P7", "explain": "文中明白寫道「The first Russian-made vodka appeared in the 15th century」，即俄羅斯製伏特加始於15世紀，故選 A。B錯，最初傳入的是葡萄酒精而非小麥製；C錯，中世紀歐洲飲酒最兇的是德國人，但文中未說德國是「產量最大」；D錯，19世紀是政府壟斷生產，並非鼓勵人民自製。", "keyPoint": "細節查找題", "skip": false}, {"id": "U114-45", "year": 114, "no": 45, "type": "閱讀測驗", "stem": "What does \"This\" in the fourth paragraph refer to?", "options": ["The alcohol.", "The government.", "The illegal production.", "The state monopoly."], "answer": "D", "passageRef": "114-P7", "explain": "This 指的是前一句「只有政府被允許生產酒精」這件事，也就是「國家專賣制度（state monopoly）」，因此「This」讓國庫充實但也助長了伏特加消費，故選 D。", "keyPoint": "代名詞指涉題", "skip": false}, {"id": "U114-46", "year": 114, "no": 46, "type": "閱讀測驗", "stem": "How does the author conclude the passage in the last paragraph?", "options": ["By providing further facts.", "By summarizing the main ideas.", "By raising a new problem.", "By making a future prediction."], "answer": "A", "passageRef": "114-P7", "explain": "最後一段並沒有做總結性的評論，而是持續補充新事實：反酗酒運動持續進行、問題依然存在、俄羅斯人均飲酒量雖非世界第一但接近頂端，屬於「提供更多事實資訊」的收尾方式，故選 A。", "keyPoint": "篇章結尾寫作手法題", "skip": false}, {"id": "U114-50", "year": 114, "no": 50, "type": "閱讀測驗", "stem": "From (A) to (J) in the forum discussion, which ONES show a positive attitude toward zoos?（多選題）", "options": ["Amy", "Ben", "Cathy", "Daniel", "Eddie", "Frank", "George", "Henry", "Irene", "Jack"], "answer": "C", "passageRef": "114-P8", "explain": "Cathy(C)認為動物園是傳統、是有意義的家庭活動；Daniel(D)認為動物園有助瀕危物種配對繁殖；George(G)強調動物園的教育功能；Irene(I)認為近距離接觸動物能培養同理心，這四人皆對動物園表達支持或肯定的態度，故選 C、D、G、I。其餘如Amy、Ben、Eddie、Henry偏反對，Frank、Jack則屬條件式或中立客觀陳述，不算明確正面支持。", "keyPoint": "多選題:找出對動物園持正面態度者", "skip": true}, {"id": "U113-1", "year": 113, "no": 1, "type": "詞彙", "stem": "People who desire a ______ figure should exercise regularly and maintain healthy eating habits.", "options": ["spicy", "slender", "slight", "slippery"], "answer": "B", "passageRef": null, "explain": "想要「苗條」身材要靠運動與健康飲食，故選 slender(苗條的)。spicy 辛辣的、slight 輕微的/瘦小的（多修飾程度而非體態）、slippery 滑溜的，皆不符合「身材」的語境。（slight 雖也可指瘦小身形，但語感偏天生纖弱；此處靠運動飲食達成的理想苗條身材慣用 slender。）", "keyPoint": "字義：slender 苗條的", "skip": false}, {"id": "U113-2", "year": 113, "no": 2, "type": "詞彙", "stem": "Watching the sun ______ from a sea of clouds is a must-do activity for all visitors to Ali Mountain.", "options": ["emerging", "flashing", "rushing", "floating"], "answer": "A", "passageRef": null, "explain": "看日出時，太陽從雲海中「浮現、升起」最自然，故選 emerging。flashing 閃爍（太陽不會一閃一閃）、rushing 衝、猛然前進（太突兀）、floating 漂浮（較適合形容雲本身，不是太陽升起的動作），語意都不如 emerge 貼切。", "keyPoint": "字義：emerge 浮現、升起", "skip": false}, {"id": "U113-3", "year": 113, "no": 3, "type": "詞彙", "stem": "Do you know what time the next bus is ______? I've been waiting here for more than 30 minutes.", "options": ["apt", "due", "bound", "docked"], "answer": "B", "passageRef": null, "explain": "the bus is due 表示公車「預定、應該」要到了，是問時刻表固定用法，故選 due。apt 恰當的、bound 前往（要接 for）、docked 停靠（多用於船隻），都不能用來問公車的預定到站時間。", "keyPoint": "片語：be due (表定要抵達/發生)", "skip": false}, {"id": "U113-4", "year": 113, "no": 4, "type": "詞彙", "stem": "The roasting heat and high ______ made me feel hot and sticky, no matter what I did to cool off.", "options": ["density", "humidity", "circulation", "atmosphere"], "answer": "B", "passageRef": null, "explain": "「悶熱又黏答答」通常是因為濕度高，故選 humidity。density 密度、circulation 流通/循環、atmosphere 氣氛或大氣，都與「又熱又黏」的感覺無關。", "keyPoint": "字義：humidity 濕度", "skip": false}, {"id": "U113-5", "year": 113, "no": 5, "type": "詞彙", "stem": "Artwork created by truly great artists such as Picasso and Monet will no doubt ______ the test of time.", "options": ["stay", "take", "serve", "stand"], "answer": "D", "passageRef": null, "explain": "「經得起時間考驗」是固定搭配 stand the test of time，故選 stand。stay、take、serve 都不能與 the test of time 搭配成慣用語。", "keyPoint": "片語：stand the test of time 經得起考驗", "skip": false}, {"id": "U113-6", "year": 113, "no": 6, "type": "詞彙", "stem": "In some countries, military service is ______ for men only; women do not have to serve in the military.", "options": ["forceful", "realistic", "compulsory", "distinctive"], "answer": "C", "passageRef": null, "explain": "「只有男性需服兵役、女性不用」表示兵役是「強制性」的，故選 compulsory。forceful 強而有力的、realistic 現實的、distinctive 獨特的，都不能表達「義務、強制」之意。", "keyPoint": "字義：compulsory 強制性的", "skip": false}, {"id": "U113-7", "year": 113, "no": 7, "type": "詞彙", "stem": "The team complained that its leader always took the ______ for all the hard work done by the team members.", "options": ["advantage", "revenge", "remedy", "credit"], "answer": "D", "passageRef": null, "explain": "團隊抱怨領導人總是把大家辛苦的成果「歸功於自己」，即 take the credit(居功)，故選 credit。advantage 優勢、revenge 報復、remedy 補救辦法，都套不進 take the ___ 這個慣用語。", "keyPoint": "片語：take the credit 居功", "skip": false}, {"id": "U113-8", "year": 113, "no": 8, "type": "詞彙", "stem": "Located at the center of the city, the business hotel ______ not only good service but also convenient public transport.", "options": ["proposes", "contains", "promises", "confirms"], "answer": "C", "passageRef": null, "explain": "旅館「保證」提供好服務與便利交通，用 promises(保證)最合適。proposes 提議、contains 包含（語氣生硬不自然）、confirms 確認，都不如 promise 貼近「向顧客承諾」的語感。", "keyPoint": "字義：promise 保證有", "skip": false}, {"id": "U113-9", "year": 113, "no": 9, "type": "詞彙", "stem": "As blood supplies have fallen to a critically low level, many hospitals are making an ______ for the public to donate blood.", "options": ["appeal", "approach", "operation", "observation"], "answer": "A", "passageRef": null, "explain": "血庫存量過低，醫院向大眾「呼籲」捐血，make an appeal for 是固定用法，故選 appeal。approach 方法、operation 行動或手術、observation 觀察，語意都不符。", "keyPoint": "片語：make an appeal for 呼籲", "skip": false}, {"id": "U113-10", "year": 113, "no": 10, "type": "詞彙", "stem": "David felt disappointed when he found out that he could not choose his study partners, but would be ______ placed in a study group.", "options": ["eligibly", "randomly", "apparently", "consequently"], "answer": "B", "passageRef": null, "explain": "David 不能自選讀書夥伴，而是被「隨機」分配到小組，故選 randomly。eligibly（合格地，用法罕見）、apparently 顯然地、consequently 因此，皆不符合「隨機分組」的意思。", "keyPoint": "字義：randomly 隨機地", "skip": false}, {"id": "U113-11", "year": 113, "no": 11, "type": "綜合測驗", "stem": "mystery shoppers ______ regular customers to purchase items, eat in restaurants...", "options": ["call for", "pose as", "attend to", "engage in"], "answer": "B", "passageRef": "113-P1", "explain": "神秘客會「假扮成」一般顧客去消費、用餐、詢問或退貨，故選 pose as。call for 要求、attend to 照料、engage in 從事，語意都與「偽裝身分」不同。", "keyPoint": "片語：pose as 假扮成", "skip": false}, {"id": "U113-12", "year": 113, "no": 12, "type": "綜合測驗", "stem": "...environment of the stores ______ they are assigned.", "options": ["in that", "with which", "for that", "to which"], "answer": "D", "passageRef": "113-P1", "explain": "空格前是 the environment of the stores，後面完整句意為「他們被指派到(be assigned to)的店家」，故關係代名詞前要用介系詞 to，選 to which。in that、with which、for that 皆不符合 assign to 的固定搭配。", "keyPoint": "介系詞+關係代名詞：assigned to", "skip": false}, {"id": "U113-13", "year": 113, "no": 13, "type": "綜合測驗", "stem": "...have to follow certain standard procedures to avoid ______.", "options": ["keen competitions", "financial hardship", "racial conflicts", "personal bias"], "answer": "D", "passageRef": "113-P1", "explain": "神秘客要遵守標準流程，是為了避免評分時摻入「個人偏見」，故選 personal bias。keen competitions 激烈競爭、financial hardship 財務困難、racial conflicts 種族衝突，都與評鑑客觀性無關。", "keyPoint": "字義：personal bias 個人偏見", "skip": false}, {"id": "U113-14", "year": 113, "no": 14, "type": "綜合測驗", "stem": "They may also pretend to be ______ customers, arguing with a salesperson without a good reason.", "options": ["difficult", "potential", "constant", "anonymous"], "answer": "A", "passageRef": "113-P1", "explain": "後文「無理由地跟店員爭吵」正是「難搞顧客」的行為，故選 difficult。potential 潛在的、constant 一直不斷的、anonymous 匿名的，都無法呼應「無理取鬧」這個具體行為。", "keyPoint": "字義：difficult customer 難搞的顧客", "skip": false}, {"id": "U113-15", "year": 113, "no": 15, "type": "綜合測驗", "stem": "mystery shoppers can identify areas for ______ and thereby help enhance the quality of products and services.", "options": ["distribution", "expectation", "improvement", "management"], "answer": "C", "passageRef": "113-P1", "explain": "蒐集到的資料能找出「可改進」的地方，進而提升品質，故選 improvement。distribution 配銷、expectation 期望、management 管理，都不符合「找出待改善點」的邏輯。", "keyPoint": "片語：areas for improvement 待改善之處", "skip": false}, {"id": "U113-16", "year": 113, "no": 16, "type": "綜合測驗", "stem": "They ______ alarm clocks because adjustable alarms had been invented by the mid-19th century.", "options": ["must be using", "could have used", "had hardly used", "were mostly using"], "answer": "B", "passageRef": "113-P2", "explain": "此句與後文「但這新裝置仍昂貴又不可靠」對比，表示鬧鐘在19世紀中期雖已發明、人們「本可以使用」卻未必普遍使用，故用 could have used 表示過去的可能性。must be using 時態不合、had hardly used(幾乎沒用過)與 could 的語氣不同、were mostly using(大多在使用)則與後文「不可靠」矛盾。", "keyPoint": "時態語意：could have + p.p.（過去本可能發生卻未必如此）", "skip": false}, {"id": "U113-17", "year": 113, "no": 17, "type": "綜合測驗", "stem": "______ sticks or pea shooters, the human alarms would tour the streets...", "options": ["Aimed at", "Trained for", "Equipped with", "Exhausted by"], "answer": "C", "passageRef": "113-P2", "explain": "人肉鬧鐘「配備著」棍子或豌豆槍去敲窗戶叫醒客人，故選 Equipped with。Aimed at 瞄準、Trained for 受訓練從事、Exhausted by 因…而筋疲力盡，語意皆不符合「隨身攜帶工具」的情境。", "keyPoint": "字義：equipped with 配備著", "skip": false}, {"id": "U113-18", "year": 113, "no": 18, "type": "綜合測驗", "stem": "knockers-up became ______ throughout the United Kingdom.", "options": ["familiar presences", "distant memories", "vague images", "public eyesores"], "answer": "A", "passageRef": "113-P2", "explain": "knocker-up 每天出現在大街小巷叫醒顧客，成為英國各地「熟悉的身影」，故選 familiar presences。distant memories 遙遠的回憶、vague images 模糊的印象、public eyesores 公共眼中釘，語意都不符合「常見且熟悉」的正面描述。", "keyPoint": "片語：familiar presence 熟悉的身影", "skip": false}, {"id": "U113-19", "year": 113, "no": 19, "type": "綜合測驗", "stem": "While the practice continued... until the 1970s, it ______ as alarm clocks became more widespread and affordable.", "options": ["remained", "dismissed", "revised", "declined"], "answer": "D", "passageRef": "113-P2", "explain": "隨著鬧鐘越來越普及便宜，這個行業自然「式微」，故選 declined。remained 維持不變、dismissed 解散/開除、revised 修訂，都與「因替代品出現而消失」的邏輯不符。", "keyPoint": "字義：decline 衰落、式微", "skip": false}, {"id": "U113-20", "year": 113, "no": 20, "type": "綜合測驗", "stem": "However, they cannot ______ the personal attention coming from the distinctive tap of a pea shooter.", "options": ["forget", "change", "match", "regret"], "answer": "C", "passageRef": "113-P2", "explain": "現代鬧鐘雖方便，卻「比不上」人肉鬧鐘的人情味，故選 match(比得上)。forget 忘記、change 改變、regret 後悔，皆非「相比、匹敵」之意。", "keyPoint": "字義：match 比得上", "skip": false}, {"id": "U113-21", "year": 113, "no": 21, "type": "文意選填", "stem": "第21格：connect family members to their ______ loved ones who died in the tsunami", "options": ["passed on", "bridge", "sorrow", "hope", "departed", "mechanism", "housed", "manageable", "fateful", "brought forth"], "answer": "E", "passageRef": "113-P3", "explain": "空格修飾 loved ones，指在海嘯中「已故的」親人，departed 作形容詞表示「已逝的」，故選 (E) departed。與 passed on(已故，動詞片語，詞性不合)相比，departed 才能直接修飾名詞。", "keyPoint": "文意選填：departed 已故的", "skip": false}, {"id": "U113-22", "year": 113, "no": 22, "type": "文意選填", "stem": "第22格：to say the words they never got to say on that ______ day.", "options": ["passed on", "bridge", "sorrow", "hope", "departed", "mechanism", "housed", "manageable", "fateful", "brought forth"], "answer": "I", "passageRef": "113-P3", "explain": "「那決定命運的一天」指海嘯發生、奪走許多性命的那一天，fateful day 是常見搭配，故選 (I) fateful。", "keyPoint": "文意選填：fateful 決定命運的", "skip": false}, {"id": "U113-23", "year": 113, "no": 23, "type": "文意選填", "stem": "第23格：The idea for the wind phone was first ______ by a Japanese garden designer", "options": ["passed on", "bridge", "sorrow", "hope", "departed", "mechanism", "housed", "manageable", "fateful", "brought forth"], "answer": "J", "passageRef": "113-P3", "explain": "風之電話的構想最初是由庭園設計師「提出、催生」的，was first brought forth by 表示被動產生，故選 (J) brought forth。", "keyPoint": "文意選填：brought forth 被提出、產生", "skip": false}, {"id": "U113-24", "year": 113, "no": 24, "type": "文意選填", "stem": "第24格：a private space to help him navigate through the ______", "options": ["passed on", "bridge", "sorrow", "hope", "departed", "mechanism", "housed", "manageable", "fateful", "brought forth"], "answer": "C", "passageRef": "113-P3", "explain": "他需要私人空間來幫助自己度過「悲傷」，navigate through sorrow 語意通順，故選 (C) sorrow。", "keyPoint": "文意選填：sorrow 悲傷", "skip": false}, {"id": "U113-25", "year": 113, "no": 25, "type": "文意選填", "stem": "第25格：The booth he built ______ only an old dial phone with a disconnected phone line.", "options": ["passed on", "bridge", "sorrow", "hope", "departed", "mechanism", "housed", "manageable", "fateful", "brought forth"], "answer": "G", "passageRef": "113-P3", "explain": "他蓋的電話亭裡只「裝有」一支舊撥號電話，house 當動詞表示「容納、裝設」，故選 (G) housed。", "keyPoint": "文意選填：house (v.) 收容、裝設", "skip": false}, {"id": "U113-26", "year": 113, "no": 26, "type": "文意選填", "stem": "第26格：Because my thoughts couldn't be ______ through a regular phone line", "options": ["passed on", "bridge", "sorrow", "hope", "departed", "mechanism", "housed", "manageable", "fateful", "brought forth"], "answer": "A", "passageRef": "113-P3", "explain": "「我的想法無法透過一般電話線被傳達」，couldn't be passed on 表示訊息傳遞，故選 (A) passed on。", "keyPoint": "文意選填：pass on 傳達", "skip": false}, {"id": "U113-27", "year": 113, "no": 27, "type": "文意選填", "stem": "第27格：renders the grieving process more ______ for him.", "options": ["passed on", "bridge", "sorrow", "hope", "departed", "mechanism", "housed", "manageable", "fateful", "brought forth"], "answer": "H", "passageRef": "113-P3", "explain": "這個裝置讓悲傷的過程對他而言變得更「可以承受、可控」，故選 (H) manageable。", "keyPoint": "文意選填：manageable 可控的、可承受的", "skip": false}, {"id": "U113-28", "year": 113, "no": 28, "type": "文意選填", "stem": "第28格：the booth has become a ______ between the living and the dead.", "options": ["passed on", "bridge", "sorrow", "hope", "departed", "mechanism", "housed", "manageable", "fateful", "brought forth"], "answer": "B", "passageRef": "113-P3", "explain": "電話亭成為生者與死者之間的「橋樑」，a bridge between A and B 是常見搭配，故選 (B) bridge。", "keyPoint": "文意選填：bridge 橋樑", "skip": false}, {"id": "U113-29", "year": 113, "no": 29, "type": "文意選填", "stem": "第29格：Grieving is a natural ______ for coping with loss of a loved one", "options": ["passed on", "bridge", "sorrow", "hope", "departed", "mechanism", "housed", "manageable", "fateful", "brought forth"], "answer": "F", "passageRef": "113-P3", "explain": "「悲傷是應對失去親人的一種天然機制」，natural mechanism for coping with 語意通順，故選 (F) mechanism。", "keyPoint": "文意選填：mechanism 機制", "skip": false}, {"id": "U113-30", "year": 113, "no": 30, "type": "文意選填", "stem": "第30格：For those who speak into the wind phone, ______ is always there", "options": ["passed on", "bridge", "sorrow", "hope", "departed", "mechanism", "housed", "manageable", "fateful", "brought forth"], "answer": "D", "passageRef": "113-P3", "explain": "對著風之電話說話的人，心中始終存有「希望」，相信訊息終能傳達給逝者，故選 (D) hope。", "keyPoint": "文意選填：hope 希望", "skip": false}, {"id": "U113-31", "year": 113, "no": 31, "type": "篇章結構", "stem": "第31格（第二段開頭）：______ When people have sprained a muscle or tendon, they are usually advised not to go right back to exercising...", "options": ["For example, an injured runner might end up cycling and swimming instead of running.", "Over time, researchers have come to realize the importance of exercising when injured.", "Many suggest that most patients can continue with the sport they love.", "This seems to run counter to the common practice."], "answer": "D", "passageRef": "113-P4", "explain": "前段講醫師受傷後照樣去跑步、感覺良好，第二段接著說一般人受傷通常被建議「不要」馬上運動，兩者形成對比，因此段落開頭該填「這似乎與一般常見做法相反」，故選 (D) This seems to run counter to the common practice。", "keyPoint": "篇章結構：轉折句銜接（與常規做法相反）", "skip": false}, {"id": "U113-32", "year": 113, "no": 32, "type": "篇章結構", "stem": "第32格：...advice can differ from specialist to specialist. ______ They nevertheless caution that a cutback may be necessary...", "options": ["For example, an injured runner might end up cycling and swimming instead of running.", "Over time, researchers have come to realize the importance of exercising when injured.", "Many suggest that most patients can continue with the sport they love.", "This seems to run counter to the common practice."], "answer": "C", "passageRef": "113-P4", "explain": "空格後用 They nevertheless caution...，代名詞 They 需有明確指涉對象，前面應先提出「許多人建議患者可以繼續從事喜愛的運動」，才能接「他們(這些人)仍提醒需要減量」，故選 (C) Many suggest that most patients can continue with the sport they love。", "keyPoint": "篇章結構：舉出主流建議＋Their 指代", "skip": false}, {"id": "U113-33", "year": 113, "no": 33, "type": "篇章結構", "stem": "第33格：...cross-train all the time until the pain is gone. ______ Their consensus, however, is that...", "options": ["For example, an injured runner might end up cycling and swimming instead of running.", "Over time, researchers have come to realize the importance of exercising when injured.", "Many suggest that most patients can continue with the sport they love.", "This seems to run counter to the common practice."], "answer": "A", "passageRef": "113-P4", "explain": "前一句提到「有人建議一直都做交叉訓練直到不痛為止」，此處適合舉一個具體例子說明什麼是交叉訓練，故選 (A) For example, an injured runner might end up cycling and swimming instead of running，緊接著再用 Their consensus 總結各家專家的共識。", "keyPoint": "篇章結構：舉例說明 cross-train", "skip": false}, {"id": "U113-34", "year": 113, "no": 34, "type": "篇章結構", "stem": "第34格（第四段開頭）：______ Thus, more and more patients are now advised to keep moving despite the pain.", "options": ["For example, an injured runner might end up cycling and swimming instead of running.", "Over time, researchers have come to realize the importance of exercising when injured.", "Many suggest that most patients can continue with the sport they love.", "This seems to run counter to the common practice."], "answer": "B", "passageRef": "113-P4", "explain": "第四段以 Thus 承接，說明「因此越來越多患者被建議帶傷持續運動」，前面須先鋪陳「研究者逐漸體認到受傷時運動的重要性」這個因，故選 (B) Over time, researchers have come to realize the importance of exercising when injured。", "keyPoint": "篇章結構：段落主旨句（研究者觀念轉變）", "skip": false}, {"id": "U113-35", "year": 113, "no": 35, "type": "閱讀測驗", "stem": "Which of the following pictures shows de Mestral's invention?", "options": ["(圖A)", "(圖B)", "(圖C)", "(圖D)"], "answer": "B", "passageRef": "113-P5", "explain": "文章描述魔鬼氈(Velcro)的原理是「一面布滿小鉤子(hooks)、另一面則是許多小環圈(loops)」，兩面貼合即可牢牗固定又能輕鬆撕開，故正確圖片須呈現「一面有密集小鉤、一面有密集小環」的搭扣結構，符合此特徵的即為答案 (B)。", "keyPoint": "主旨題", "skip": true}, {"id": "U113-36", "year": 113, "no": 36, "type": "閱讀測驗", "stem": "What does the author mean by \"a lightbulb moment\" in the first paragraph?", "options": ["A blessing in disguise.", "A happy ending.", "An unpredictable future.", "A sudden inspiration."], "answer": "D", "passageRef": "113-P5", "explain": "de Mestral 急忙拿顯微鏡觀察芒刺，這個「感覺靈光乍現要來了」的瞬間指的是他即將領悟出鉤環原理的「突發靈感」，故選 (D) A sudden inspiration。A blessing in disguise(塞翁失馬)、A happy ending(圓滿結局)、An unpredictable future(不可預知的未來)都不是這個片語的意思。", "keyPoint": "片語意義：a lightbulb moment 靈光一閃", "skip": false}, {"id": "U113-37", "year": 113, "no": 37, "type": "閱讀測驗", "stem": "Which of the following statements about Velcro is true?", "options": ["It has been a market favorite since its first appearance.", "Cotton was not durable enough to be used as its materials.", "It was given a French name because it was first produced in France.", "The design was intended to look as shiny and smooth as velvet."], "answer": "B", "passageRef": "113-P5", "explain": "文中明確寫道 \"He first tried cotton, but it proved too soft and could not withstand repeated openings and closures.\"，正好對應選項 (B)。Velcro 一開始並不受歡迎(A 錯)；命名來自法文 velours+crochet 兩字組合，並非因為在法國生產(C 錯)；設計初衷是功能性的鉤環結構，並非追求絲絨般光滑外觀(D 錯)。", "keyPoint": "細節查找：cotton 材質不耐用", "skip": false}, {"id": "U113-38", "year": 113, "no": 38, "type": "閱讀測驗", "stem": "Which of the following fields is NOT mentioned for Velcro uses in the passage?", "options": ["Civil engineering.", "Aerospace industry.", "Medical technology.", "Sports and recreation."], "answer": "A", "passageRef": "113-P5", "explain": "文章提到 Velcro 用於運動器材(athletic equipment)、太空裝備(NASA)、醫療器材(blood pressure cuffs, surgeons' gowns, artificial heart)，唯獨沒有提到「土木工程」，故答案為 (A) Civil engineering。", "keyPoint": "細節查找：文中未提及的應用領域", "skip": false}, {"id": "U113-39", "year": 113, "no": 39, "type": "閱讀測驗", "stem": "What can we learn from the passage?", "options": ["How national parks around the world were established.", "How Yellowstone's natural features were formed.", "Why Moran's family moved to the United States.", "Why Moran started painting Yellowstone."], "answer": "D", "passageRef": "113-P6", "explain": "文章交代 Moran 因受邀繪製《The Wonders of Yellowstone》插畫、被書中描述深深吸引，才「渴望親眼見識」這片奇異之地，這正是他開始繪製黃石風景的原因，故選 (D)。文章重點不在解釋國家公園制度、黃石地貌成因或全家搬遷美國的理由，A、B、C 皆非文章主旨所在。", "keyPoint": "主旨題：Moran 為何開始畫黃石", "skip": false}, {"id": "U113-40", "year": 113, "no": 40, "type": "閱讀測驗", "stem": "Why does the author use \"the blackened heart\" in paragraph 2 to describe Moran's hometown?", "options": ["The place was severely polluted.", "The town was filled with darkened holes.", "There were many evil-hearted industry owners.", "The laborers mostly wore dark and dirty uniforms."], "answer": "A", "passageRef": "113-P6", "explain": "文中緊接著描述該地「主街是一個陰暗醜陋的洞、河流是一條髒水」，可見 the blackened heart 是用來形容工業革命核心地帶「遭受嚴重污染」的意象，故選 (A)。", "keyPoint": "修辭理解：the blackened heart 隱喻嚴重污染", "skip": false}, {"id": "U113-41", "year": 113, "no": 41, "type": "閱讀測驗", "stem": "Which of the following statements is true about the Yellowstone National Park?", "options": ["Its establishment was proposed by Langford.", "Americans knew little about its beauty before the 1870s.", "The government project was started due to its rich natural resources.", "It was the only national park established because of Moran's works."], "answer": "B", "passageRef": "113-P6", "explain": "文中提到「在 Moran 抵達之前，黃石在大眾想像中只是個充滿滾燙熱水與蒸氣、地獄般的荒野」，直到他的畫作出現，黃石才被視為如畫般的仙境，可見美國人在此之前對其美景所知甚少，故選 (B)。國家公園是由國會立法設立，並非 Langford 提議（A 錯）；文章重點在美學價值而非天然資源開發（C 錯）；文末提到 Moran 後來還畫過其他成為國家公園/紀念地的地區，可見黃石並非唯一因他而設立的公園（D 錯）。", "keyPoint": "細節判斷：Moran 畫作出現前大眾對黃石美景所知有限", "skip": false}, {"id": "U113-42", "year": 113, "no": 42, "type": "閱讀測驗", "stem": "What can be inferred from the passage?", "options": ["Scribner's Monthly was a magazine promoting national parks.", "Moran had visited Yellowstone before he started painting its landscapes.", "Color photos were not common when Moran started painting Yellowstone.", "Watercolor was the most popular form of landscape painting in the 19th century."], "answer": "C", "passageRef": "113-P6", "explain": "文中特別強調 Moran 的水彩畫是「該地區第一批彩色影像(the first color renderings)」，並與 Jackson 的照片並列呈現給國會，暗示當時攝影技術仍只有黑白照片，尚無彩色照片，故選 (C)。", "keyPoint": "推論題：當時尚無彩色照片", "skip": false}, {"id": "U113-43", "year": 113, "no": 43, "type": "閱讀測驗", "stem": "What is the primary goal of 100% Fish?", "options": ["To advance ocean technology.", "To reduce food crises worldwide.", "To enhance cross-industry cooperation.", "To make the most of marine resources."], "answer": "D", "passageRef": "113-P7", "explain": "文中明白指出該計畫 \"aims to encourage full utilization of each fish caught\"，也就是充分利用每一條漁獲、把海洋資源用到極致，故選 (D) To make the most of marine resources。減緩食物危機、跨業合作、海洋科技提升都只是附帶效果或手段，並非最核心目標。", "keyPoint": "主旨題：100% Fish 的核心目標", "skip": false}, {"id": "U113-44", "year": 113, "no": 44, "type": "閱讀測驗", "stem": "What does \"this pioneering procedure\" in the second paragraph refer to?", "options": ["100% Fish's mission.", "Oddsson's skin transplant.", "A fundamental change in seafood business.", "A new approach to protect the environment."], "answer": "B", "passageRef": "113-P7", "explain": "第一段先描述 Oddsson 因電擊重傷、靠「鱈魚皮移植」保命，第二段開頭 \"Oddsson's fish skin transplantation was actually part of...\" 緊接著用 this pioneering procedure 回指同一件事，故選 (B) Oddsson's skin transplant。", "keyPoint": "代名詞指涉：this pioneering procedure 指鱈魚皮移植", "skip": false}, {"id": "U113-45", "year": 113, "no": 45, "type": "閱讀測驗", "stem": "Which of the following is true according to the passage?", "options": ["Iceland has increased their fish catch by 30% in the last 20 years.", "Petur Oddsson was an important member of the Icelandic project.", "Cross-field collaboration has proved to be very fruitful for 100% Fish.", "100% Fish is a big international enterprise marketing seafood products."], "answer": "C", "passageRef": "113-P7", "explain": "文末段描述 100% Fish 促成漁業公司與學界、新創公司、研發團隊之間的合作，透過知識分享開發出許多創新產品，可見跨領域合作確實成效豐碩，故選 (C)。文中是「利用率」提高到95%，並非「漁獲量」增加30%（A 錯，且30%指的是每條鱈魚多創造的價值）；Oddsson 只是受惠者而非計畫成員（B 錯）；100% Fish 是促進合作與研發的計畫，並非行銷海鮮的跨國企業（D 錯）。", "keyPoint": "細節判斷：跨產業合作成效卓著", "skip": false}, {"id": "U113-46", "year": 113, "no": 46, "type": "閱讀測驗", "stem": "Here is a sentence: \"Almost nothing of a fish is left for the trash bin.\" Which paragraph is most suitable to have it as the final sentence?", "options": ["Paragraph 1.", "Paragraph 2.", "Paragraph 3.", "Paragraph 4."], "answer": "C", "passageRef": "113-P7", "explain": "「幾乎沒有魚的任何部位被丟進垃圾桶」正好總結第三段列舉的各種鱈魚利用實例（鈣質補充品、能量飲、皮膚移植、魚頭魚骨出口做湯底、Omega-3 膠囊、感冒噴劑、狗零食），作為該段的總結句最恰當，故選 Paragraph 3 (C)。", "keyPoint": "段落主旨句安插：呼應第三段各種鱈魚副產品", "skip": false}, {"id": "U113-49", "year": 113, "no": 49, "type": "閱讀測驗", "stem": "From (A) to (F) below, choose the ONES that are true for both jackdaws and turtle ants.（多選題）", "options": ["They have special strategies to locate food sources.", "They have complex interactions led by a leader.", "They share information with their group members.", "They establish rules to stay away from enemies.", "They change their nesting sites from time to time.", "They show behavior governed by a unique system of communication."], "answer": "C", "passageRef": "113-P8", "explain": "選 (C)(F)：椋鳥(jackdaws)靠觀察周圍鳥隻的相對位置資訊調整飛行、龜蟻(turtle ants)靠費洛蒙路徑讓同伴跟隨，兩者都屬於「與同伴分享資訊」(C)，也都靠「一套獨特的溝通系統」在支配行為(F)：椋鳥是視覺定位系統，龜蟻是費洛蒙路徑系統。至於(A)找食物特殊策略只提到龜蟻、沒提到椋鳥有此策略；(B)沒有任一動物提到「由領袖主導」；(D)只有椋鳥提到躲避掠食者、龜蟻沒提及天敵；(E)兩者皆未提到會更換築巢地點，故均不選。", "keyPoint": "多選題：找出「兩種動物都符合」的共同敘述", "skip": true}, {"id": "U112-1", "year": 112, "no": 1, "type": "詞彙", "stem": "The bus driver often complains about chewing gum found under passenger seats because it is ___ and very hard to remove.", "options": ["sticky", "greasy", "clumsy", "mighty"], "answer": "A", "passageRef": null, "explain": "口香糖黏在座位下、很難清除，形容它「黏黏的」要用 sticky，正好對應句尾 hard to remove 的線索。greasy 是「油膩的」（多用於食物、頭髮），clumsy 是「笨拙的」（形容人的動作），mighty 是「強大的、有力的」，三者都跟「黏、難清」無關，故答案為 (A) sticky。", "keyPoint": "字義：sticky 黏的", "skip": false}, {"id": "U112-2", "year": 112, "no": 2, "type": "詞彙", "stem": "Jesse is a talented model. He can easily adopt an elegant ___ for a camera shoot.", "options": ["clap", "toss", "pose", "snap"], "answer": "C", "passageRef": null, "explain": "模特兒在鏡頭前擺出優雅的「姿勢」，英文用 pose（名詞，姿勢／姿態），最符合 for a camera shoot 的情境。clap 是「拍手」，toss 是「投擲、丟」，snap 常指「拍照的快照」或「啪一聲折斷」，都不是「擺姿勢」的意思，故選 (C) pose。", "keyPoint": "字義：pose 姿勢", "skip": false}, {"id": "U112-3", "year": 112, "no": 3, "type": "詞彙", "stem": "In order to draw her family tree, Mary tried to trace her ___ back to their arrival in North America.", "options": ["siblings", "commuters", "ancestors", "instructors"], "answer": "C", "passageRef": null, "explain": "畫家族樹（family tree）是要追溯「祖先」到抵達北美的那一代，英文是 ancestors。siblings 是「兄弟姊妹」，commuters 是「通勤者」，instructors 是「教練／指導者」，都與「畫家族樹追溯血緣」無關，故選 (C) ancestors。", "keyPoint": "字義：ancestors 祖先", "skip": false}, {"id": "U112-4", "year": 112, "no": 4, "type": "詞彙", "stem": "Upon the super typhoon warning, Nancy rushed to the supermarket—only to find the shelves almost ___ and the stock nearly gone.", "options": ["blank", "bare", "hollow", "queer"], "answer": "B", "passageRef": null, "explain": "颱風警報一發布大家搶購，貨架幾乎「空了」，貨也幾乎沒了，英文用 bare（架上空蕩蕩、光禿禿），和後面 the stock nearly gone 語意呼應。blank 通常指「（紙張、表格）空白的」，hollow 是「中空的」（如空心的物體），queer 是「奇怪的」，都不合句意，故選 (B) bare。", "keyPoint": "字義：bare 空的、光禿禿的", "skip": false}, {"id": "U112-5", "year": 112, "no": 5, "type": "詞彙", "stem": "Even though Jack said \"Sorry!\" to me in person, I did not feel any ___ in his apology.", "options": ["liability", "generosity", "integrity", "sincerity"], "answer": "D", "passageRef": null, "explain": "Jack 雖然當面說了 Sorry，但「我」感覺不到他道歉裡有「真誠」，英文是 sincerity，呼應 apology（道歉）這個字。liability 是「責任／負債」，generosity 是「慷慨」，integrity 是「正直、廉正」，都和「道歉夠不夠真心」搭不起來，故選 (D) sincerity。", "keyPoint": "字義：sincerity 真誠", "skip": false}, {"id": "U112-6", "year": 112, "no": 6, "type": "詞彙", "stem": "My grandfather has astonishing powers of ___. He can still vividly describe his first day at school as a child.", "options": ["resolve", "fraction", "privilege", "recall"], "answer": "D", "passageRef": null, "explain": "祖父有驚人的「回憶力」，還能生動描述小時候上學第一天，powers of recall 就是「回想的能力」。resolve 是「決心」，fraction 是「片段、分數」，privilege 是「特權」，都與記憶、回想無關，故選 (D) recall。", "keyPoint": "字義：recall 回想（力）", "skip": false}, {"id": "U112-7", "year": 112, "no": 7, "type": "詞彙", "stem": "Recent research has found lots of evidence to ___ the drug company's claims about its \"miracle\" tablets for curing cancer.", "options": ["provoke", "counter", "expose", "convert"], "answer": "B", "passageRef": null, "explain": "研究找到很多證據來「反駁」藥廠對神奇藥丸能治癌的宣稱，英文用 counter（動詞，反駁、對抗說法）。provoke 是「激怒」，expose 是「揭露」，convert 是「使轉變、改信」，語意都對不上「拿證據去反駁宣稱」，故選 (B) counter。", "keyPoint": "字義：counter 反駁", "skip": false}, {"id": "U112-8", "year": 112, "no": 8, "type": "詞彙", "stem": "Corrupt officials and misguided policies have ___ the country's economy and burdened its people with enormous foreign debts.", "options": ["crippled", "accelerated", "rendered", "ventured"], "answer": "A", "passageRef": null, "explain": "貪腐官員與錯誤政策「重創」了國家經濟，還讓人民背負龐大外債，crippled 原意是「使殘廢」，引申為「嚴重損害」，符合負面因果語境。accelerated 是「加速」，rendered 是「使成為」，ventured 是「冒險」，都不符合「經濟被搞垮」的意思，故選 (A) crippled。", "keyPoint": "字義：crippled 重創、使殘廢", "skip": false}, {"id": "U112-9", "year": 112, "no": 9, "type": "詞彙", "stem": "As a record number of fans showed up for the baseball final, the highways around the stadium were ___ with traffic all day.", "options": ["choked", "disturbed", "enclosed", "injected"], "answer": "A", "passageRef": null, "explain": "大量球迷湧入棒球總決賽，球場周邊的高速公路整天都「塞爆了車潮」，choked with traffic 就是「被車流塞滿」的固定用法。disturbed 是「被打擾」，enclosed 是「被圍住」，injected 是「被注入」，都不是「塞車」的意思，故選 (A) choked。", "keyPoint": "字義：choked 塞滿、阻塞", "skip": false}, {"id": "U112-10", "year": 112, "no": 10, "type": "詞彙", "stem": "Studies show that the ___ unbiased media are in fact often deeply influenced by political ideology.", "options": ["undoubtedly", "roughly", "understandably", "supposedly"], "answer": "D", "passageRef": null, "explain": "研究顯示「號稱」公正客觀的媒體，其實常深受政治意識形態影響，supposedly 表示「大家以為／表面上如此，但實際未必」，正好呼應後半的轉折語氣。undoubtedly 是「無疑地」（肯定語氣，與後文反差矛盾），roughly 是「大約地」，understandably 是「可以理解地」，皆不符合「表面看似客觀、實則有偏見」的反諷語感，故選 (D) supposedly。", "keyPoint": "字義：supposedly 據稱、據說", "skip": false}, {"id": "U112-11", "year": 112, "no": 11, "type": "綜合測驗", "stem": "each branch growing just perfectly so it almost, (11), touches the neighboring tree", "options": ["in no time", "by all means", "but not quite", "and pretty much"], "answer": "C", "passageRef": "112-P1", "explain": "前面說樹枝長得剛剛好，「幾乎」要碰到鄰樹，但事實上留有縫隙（crown shyness 的縫隙現象），所以要接一個表示「差一點點卻沒真的碰到」的轉折語，(C) but not quite（但並非真的）最貼切，almost...but not quite 是常見搭配。in no time（很快）、by all means（當然可以）、and pretty much（而且幾乎）都無法表達「差一點沒碰到」的語意反差。", "keyPoint": "克漏字：but not quite 幾乎但沒有真的", "skip": false}, {"id": "U112-12", "year": 112, "no": 12, "type": "綜合測驗", "stem": "proposing (12) explanations for the phenomenon", "options": ["universal", "productive", "conventional", "multiple"], "answer": "D", "passageRef": "112-P1", "explain": "後文接著列出好幾種不同學者的解釋（有人說是為了防止碰撞受損，有人說是為了搶資源、防病蟲害），可見科學家提出的是「多種」解釋，故選 (D) multiple。universal（普遍的）、productive（有生產力的）、conventional（傳統的）都不符合「多元並陳的理論」這個邏輯。", "keyPoint": "克漏字：multiple 多種的", "skip": false}, {"id": "U112-13", "year": 112, "no": 13, "type": "綜合測驗", "stem": "plants, like animals, (13) resources—nutrients, water, space, and light", "options": ["get over", "compete for", "give way to", "make up for"], "answer": "B", "passageRef": "112-P1", "explain": "此句說植物和動物一樣要「爭奪」養分、水、空間和光線等資源，(B) compete for 意思是「競爭、爭奪」，符合後文「intense struggle for these resources」的呼應。get over（克服）、give way to（讓位給）、make up for（彌補）都與「爭奪資源」的意思不符。", "keyPoint": "克漏字：compete for 競爭、爭奪", "skip": false}, {"id": "U112-14", "year": 112, "no": 14, "type": "綜合測驗", "stem": "may allow trees to increase their (14) light and enhance photosynthesis", "options": ["reliance on", "exposure to", "sensitivity to", "reflection on"], "answer": "B", "passageRef": "112-P1", "explain": "樹冠之間留有縫隙，可以讓樹木增加對「光照」的接觸，進而提升光合作用，exposure to light 是固定搭配，表示「接受日照」。reliance on（依賴）、sensitivity to（敏感度）、reflection on（對…的反思）在文法可通、但語意不符本文，故選 (B) exposure to。", "keyPoint": "克漏字：exposure to 接觸、暴露於", "skip": false}, {"id": "U112-15", "year": 112, "no": 15, "type": "綜合測驗", "stem": "(15) decades of investigation, there is no consensus", "options": ["For", "Besides", "Despite", "Concerning"], "answer": "C", "passageRef": "112-P1", "explain": "此句是「儘管經過數十年研究，科學界仍無共識」的讓步語氣，(C) Despite（儘管）最符合這種「研究很久卻沒有結論」的轉折邏輯。For（表原因或期間長度，但語意不通）、Besides（此外）、Concerning（關於）都無法表達「儘管…卻…」的對比，故選 (C) Despite。", "keyPoint": "介系詞片語：Despite 儘管", "skip": false}, {"id": "U112-16", "year": 112, "no": 16, "type": "綜合測驗", "stem": "a rocket could shoot (16) Earth's pull in order to land humans on the moon", "options": ["back to", "free of", "long before", "straight on"], "answer": "B", "passageRef": "112-P2", "explain": "早期太空人想讓火箭「擺脫」地球引力才能登陸月球，shoot free of Earth's pull 表示「射脫地心引力」，(B) free of 符合語意。back to（回到）、long before（早在…之前）、straight on（一直向前）都無法表達「掙脫引力」的意思，故選 (B) free of。", "keyPoint": "克漏字：free of 擺脫、脫離", "skip": false}, {"id": "U112-17", "year": 112, "no": 17, "type": "綜合測驗", "stem": "how reduced gravity affects the astronauts' (17) condition", "options": ["physical", "perceptual", "mental", "external"], "answer": "A", "passageRef": "112-P2", "explain": "此段之後都在談失重、微重力對「身體」的影響（體液分布改變、臉部浮腫等生理現象），所以太空人的 condition 應該是「身體」狀況，故選 (A) physical。perceptual（知覺的）、mental（心智的）、external（外部的）都與後文描述的生理變化不符。", "keyPoint": "克漏字：physical 身體的", "skip": false}, {"id": "U112-18", "year": 112, "no": 18, "type": "綜合測驗", "stem": "our body fluids (18), shifting toward the upper body and the head", "options": ["redistribute", "redistributed", "redistributing", "being redistributed"], "answer": "A", "passageRef": "112-P2", "explain": "正解 redistribute。此句 our body fluids redistribute, shifting toward... 中，redistribute 是句子主要動詞（主詞 fluids 為複數、用原形現在式），shifting 是伴隨狀態的現在分詞構句，修飾主要動作，兩者並非對等並列（對等需 and 連接或同為限定動詞）。", "keyPoint": "主要動詞 vs 分詞構句", "skip": false}, {"id": "U112-19", "year": 112, "no": 19, "type": "綜合測驗", "stem": "This \"Charlie Brown effect\" will be more (19) when the astronauts go on their Mars missions", "options": ["contagious", "unusual", "severe", "aggressive"], "answer": "C", "passageRef": "112-P2", "explain": "火星任務比登月任務時間長得多（約三年），所以 Charlie Brown effect（臉部浮腫效應）會更「嚴重」，故選 (C) severe，呼應後文提到這是太空人健康的頭號風險。contagious（會傳染的）、unusual（不尋常的）、aggressive（有攻擊性的）都不符合「症狀因時間拉長而加劇」的邏輯。", "keyPoint": "克漏字：severe 嚴重的", "skip": false}, {"id": "U112-20", "year": 112, "no": 20, "type": "綜合測驗", "stem": "the effect is often (20) space motion sickness, headaches, and nausea", "options": ["varied with", "brought about", "transferred from", "accompanied by"], "answer": "D", "passageRef": "112-P2", "explain": "此效應常常「伴隨」太空暈眩、頭痛、噁心等症狀出現，(D) accompanied by（伴隨著）最符合「一種症狀跟著另外幾種症狀一起出現」的語意。varied with（隨…而變化）、brought about（被引起）、transferred from（從…轉移而來）皆不符合「伴隨出現」的搭配，故選 (D) accompanied by。", "keyPoint": "克漏字：accompanied by 伴隨著", "skip": false}, {"id": "U112-21", "year": 112, "no": 21, "type": "文意選填", "stem": "is water always the healthiest drink we can (21)?", "options": ["absorption", "active", "alert", "combat", "option", "effective", "even", "status", "pass through", "reach for"], "answer": "J", "passageRef": "112-P3", "explain": "此句問「水是否永遠是我們可以『選擇拿取』的最健康飲品？」，reach for 有「伸手去拿、選擇」的意思，符合 drink 的動作感。故選 J reach for。", "keyPoint": "文意選填：reach for 伸手拿、選擇", "skip": false}, {"id": "U112-22", "year": 112, "no": 22, "type": "文意選填", "stem": "a physically (22) person with an outdoor job under the sun", "options": ["absorption", "active", "alert", "combat", "option", "effective", "even", "status", "pass through", "reach for"], "answer": "B", "passageRef": "112-P3", "explain": "此處形容一個「身體上活躍、常在戶外工作曬太陽的人」，需要一個形容詞修飾 physically，active（活躍的）最符合，對比後文提到坐辦公室吹冷氣的人。故選 B active。", "keyPoint": "文意選填：active 活動量大的", "skip": false}, {"id": "U112-23", "year": 112, "no": 23, "type": "文意選填", "stem": "To (23) things out, the body will get rid of water by producing urine", "options": ["absorption", "active", "alert", "combat", "option", "effective", "even", "status", "pass through", "reach for"], "answer": "G", "passageRef": "112-P3", "explain": "身體為了「使（水與鹽的比例）平衡」，會透過排尿把多餘的水分排掉，even things out 是慣用片語，意思是「使…平衡、扯平」。故選 G even。", "keyPoint": "文意選填：even out 使平衡", "skip": false}, {"id": "U112-24", "year": 112, "no": 24, "type": "文意選填", "stem": "milk can actually be more (24) than drinking water", "options": ["absorption", "active", "alert", "combat", "option", "effective", "even", "status", "pass through", "reach for"], "answer": "F", "passageRef": "112-P3", "explain": "此句說牛奶其實可能比喝水「更有效」（能同時補充水分和鹽分、乳糖），effective 符合「補水效果更好」的語意，且與 more 搭配成比較級。故選 F effective。", "keyPoint": "文意選填：effective 有效的", "skip": false}, {"id": "U112-25", "year": 112, "no": 25, "type": "文意選填", "stem": "a sugar which the human body needs in small amounts to help stimulate water (25)", "options": ["absorption", "active", "alert", "combat", "option", "effective", "even", "status", "pass through", "reach for"], "answer": "A", "passageRef": "112-P3", "explain": "乳糖能刺激身體對水分的「吸收」，water absorption 是常見搭配，指身體吸收水分的過程。故選 A absorption。", "keyPoint": "文意選填：absorption 吸收", "skip": false}, {"id": "U112-26", "year": 112, "no": 26, "type": "文意選填", "stem": "at restoring and maintaining a normal fluid (26) after exercise", "options": ["absorption", "active", "alert", "combat", "option", "effective", "even", "status", "pass through", "reach for"], "answer": "H", "passageRef": "112-P3", "explain": "椰子水有助於運動後恢復並維持正常的體液「狀態」，fluid status 指身體水分平衡的狀態。故選 H status。", "keyPoint": "文意選填：status 狀態", "skip": false}, {"id": "U112-27", "year": 112, "no": 27, "type": "文意選填", "stem": "water remains a very good (27) for keeping hydrated", "options": ["absorption", "active", "alert", "combat", "option", "effective", "even", "status", "pass through", "reach for"], "answer": "E", "passageRef": "112-P3", "explain": "對一般人來說，水仍然是維持水分的很好「選擇」，a good option 符合「水是不錯的選項」這個語意。故選 E option。", "keyPoint": "文意選填：option 選項", "skip": false}, {"id": "U112-28", "year": 112, "no": 28, "type": "文意選填", "stem": "significant changes in your body for it to eventually (28) your consciousness", "options": ["absorption", "active", "alert", "combat", "option", "effective", "even", "status", "pass through", "reach for"], "answer": "C", "passageRef": "112-P3", "explain": "身體要等到已經產生明顯變化，才會終於「驚動、提醒」你的意識感到口渴，alert your consciousness 意思是「引起你的知覺注意」。故選 C alert。", "keyPoint": "文意選填：alert 使警覺、提醒", "skip": false}, {"id": "U112-29", "year": 112, "no": 29, "type": "文意選填", "stem": "can cause more water to (29) the body quickly and come out as urine", "options": ["absorption", "active", "alert", "combat", "option", "effective", "even", "status", "pass through", "reach for"], "answer": "I", "passageRef": "112-P3", "explain": "一次喝很多水會讓過多水分很快「通過」身體，然後變成尿液排出，pass through the body 是「穿過身體」的意思，正好呼應後面 come out as urine。故選 I pass through。", "keyPoint": "文意選填：pass through 通過、穿過", "skip": false}, {"id": "U112-30", "year": 112, "no": 30, "type": "文意選填", "stem": "To (30) this, you need to drink water throughout the day", "options": ["absorption", "active", "alert", "combat", "option", "effective", "even", "status", "pass through", "reach for"], "answer": "D", "passageRef": "112-P3", "explain": "為了「解決」一次喝太多水馬上排掉的問題，建議要一整天分次喝水，combat this 意思是「對抗/克服這個問題」。故選 D combat。", "keyPoint": "文意選填：combat 對抗、解決", "skip": false}, {"id": "U112-31", "year": 112, "no": 31, "type": "篇章結構", "stem": "第31格：段首，之後接「In the early 1990s, however, scientists noticed that synesthetic colors do not change over time.」", "options": ["This consistency serves as a proof that synesthesia is real.", "Meanwhile, environmental influences seem to shape a person's synesthesia.", "People with synesthesia used to be accused of making their experiences up.", "Some studies even show that people may all be synesthetic to some degree."], "answer": "C", "passageRef": "112-P4", "explain": "此格在段落開頭，後面用 however 轉折接「直到1990年代科學家才發現通感者的顏色感受歷年不變」，可推知前面必須先講一個「與後面『被證實一致』相反的舊觀念」，也就是「以前的人認為通感者是在編造經驗」，故選 (C) People with synesthesia used to be accused of making their experiences up，這樣 however 才能形成「以前被質疑造假→後來被證實一致」的邏輯反轉。", "keyPoint": "篇章結構：承先啟後的轉折（however）", "skip": false}, {"id": "U112-32", "year": 112, "no": 32, "type": "篇章結構", "stem": "第32格：前句「would persistently give the same answer even if tested months or years apart.」後接「The most compelling support, however, comes from brain scans...」", "options": ["This consistency serves as a proof that synesthesia is real.", "Meanwhile, environmental influences seem to shape a person's synesthesia.", "People with synesthesia used to be accused of making their experiences up.", "Some studies even show that people may all be synesthetic to some degree."], "answer": "A", "passageRef": "112-P4", "explain": "前句提到通感者多年後仍給出一致答案，之後用 however 接「更有力的證據來自腦部掃描」，可知空格要先為這個「一致性」下一個小結論，(A) This consistency serves as a proof that synesthesia is real 正好承接「顏色感受一致→證明通感是真實的」，再用 however 帶出「而更強的證據是腦部掃描」的遞進關係。", "keyPoint": "篇章結構：however 承接更強的證據", "skip": false}, {"id": "U112-33", "year": 112, "no": 33, "type": "篇章結構", "stem": "第33格：前句「But an actual synesthesia gene (or genes) has not been identified yet.」後接「For example, the flavors people with taste-word synesthesia experience are usually childhood flavors...」", "options": ["This consistency serves as a proof that synesthesia is real.", "Meanwhile, environmental influences seem to shape a person's synesthesia.", "People with synesthesia used to be accused of making their experiences up.", "Some studies even show that people may all be synesthetic to some degree."], "answer": "B", "passageRef": "112-P4", "explain": "前句說「還沒找到真正的通感基因」，後面舉例說明通感者的味覺常和「童年」的味道有關、音樂通感者多半「從小」學過音樂，這些都是後天環境造成的例子，因此空格要先講「環境因素也會影響通感」這個主題句，故選 (B) Meanwhile, environmental influences seem to shape a person's synesthesia，才能自然接上後面 For example 的舉例。", "keyPoint": "篇章結構：舉例前的主題句", "skip": false}, {"id": "U112-34", "year": 112, "no": 34, "type": "篇章結構", "stem": "第34格：前句「synesthesia is now found to affect about one to four percent of the population.」後接「As is often observed, most of us tend to associate lower notes with darker colors...」", "options": ["This consistency serves as a proof that synesthesia is real.", "Meanwhile, environmental influences seem to shape a person's synesthesia.", "People with synesthesia used to be accused of making their experiences up.", "Some studies even show that people may all be synesthetic to some degree."], "answer": "D", "passageRef": "112-P4", "explain": "後句說「大多數人都傾向把低音配深色、高音配亮色」（as is often observed, most of us…），代表這種通感傾向其實普遍存在於一般人身上，因此空格要先提出這個觀點，(D) Some studies even show that people may all be synesthetic to some degree 正好引出「連一般人也有某種程度通感」，與後面「most of us」呼應。", "keyPoint": "篇章結構：連接到「多數人」的觀察", "skip": false}, {"id": "U112-35", "year": 112, "no": 35, "type": "閱讀測驗", "stem": "What question does the passage answer?", "options": ["How was the word \"hula-hooping\" derived?", "Why did Wham-O start making hula hoops?", "Where did Hawaiian hula dancing come from?", "What was the favorite toy of ancient Egyptian kids?"], "answer": "A", "passageRef": "112-P5", "explain": "整篇文章花大量篇幅解釋 hula 和 hoop 兩字如何結合成 hula hooping（水手在夏威夷看到草裙舞的動作像轉呼拉圈，因而得名），這正是文章要回答的核心問題，故選 (A)。(B)(C)(D) 都只是文中提到的部分細節，並非全文主旨所在的問題。", "keyPoint": "主旨題", "skip": false}, {"id": "U112-36", "year": 112, "no": 36, "type": "閱讀測驗", "stem": "Which of the following statements is true about use of the hoop in history?", "options": ["The British used it for medical purposes.", "Native Americans used it to train animals.", "Ancient Greeks used it as a tool for workout.", "Hawaiian dancers used it to represent the circle of life."], "answer": "C", "passageRef": "112-P5", "explain": "文中明白寫道古希臘的金屬圈「served as exercise devices as well」，不只是兒童玩具，也是運動器材，故選 (C)。(A) 英國是因為過度玩耍導致背部脫臼、心臟病，並非「醫療用途」；(B) 是原住民用小蘆葦圈象徵動物，而非「訓練」動物；(D) 象徵生命之環的是美洲原住民，不是夏威夷舞者，皆為選項的偷換對象。", "keyPoint": "閱讀理解：細節查找（古希臘用於運動）", "skip": false}, {"id": "U112-37", "year": 112, "no": 37, "type": "閱讀測驗", "stem": "Which of the following is NOT mentioned as a way of enjoying hula hoop fun?", "options": ["Striking.", "Twirling.", "Spinning.", "Kicking."], "answer": "D", "passageRef": "112-P5", "explain": "文章提到 threw, jumped, slung（丟、跳、甩繞）、struck（用棍子打，使其滾動）、twirled（轉動於腰間）、spun（旋轉）等玩法，唯獨沒有提到「踢（kicking）」，故選 (D) Kicking 為未提及的方式。", "keyPoint": "閱讀理解：NOT 提及題（找出未提到的動作）", "skip": false}, {"id": "U112-38", "year": 112, "no": 38, "type": "閱讀測驗", "stem": "According to the passage, what materials have been used for making hoops?", "options": ["reed, grapevine, bamboo, plastic", "reed, grapevine, plastic, metal", "reed, bamboo, plastic, animal skin", "grapevine, plastic, metal, animal skin"], "answer": "B", "passageRef": "112-P5", "explain": "文章分別提到埃及的乾葡萄藤（dried grapevine）、希臘的金屬（metal）、美洲原住民的蘆葦（reed）、Wham-O 的塑膠（plastic），四種材質合起來是 reed, grapevine, plastic, metal，故選 (B)。其餘選項摻雜了文章從未提到的「竹子（bamboo）」或「動物皮（animal skin）」，屬於干擾項。", "keyPoint": "閱讀理解：材質整理（跨段落統整）", "skip": false}, {"id": "U112-39", "year": 112, "no": 39, "type": "閱讀測驗", "stem": "Why do farmers in Assam dig trenches in tea gardens?", "options": ["To protect tea trees.", "To trap elephants.", "To expand tea farms.", "To mark boundaries of tea gardens."], "answer": "A", "passageRef": "112-P6", "explain": "文章說「farmers must dig drainage trenches to prevent water from accumulating and hurting the shrubs」，也就是挖溝渠是為了排水、保護茶樹（shrubs）不被積水傷害，故選 (A) To protect tea trees。挖溝渠反而意外變成大象的死亡陷阱，這是「後果」不是「目的」，(B)(C)(D) 都不是文章給出的挖溝理由。", "keyPoint": "閱讀理解：因果關係（挖溝渠的原因）", "skip": false}, {"id": "U112-40", "year": 112, "no": 40, "type": "閱讀測驗", "stem": "Why are baby elephants easily injured in the Assam tea gardens according to the passage?", "options": ["They cannot find a safe shelter when climbing out of the trenches.", "They cannot locate the landmarks while trying to navigate forests.", "They are trapped by the sharp branches of the tea trees.", "They have difficulties moving around the uneven fields."], "answer": "D", "passageRef": "112-P6", "explain": "文章說小象「not used to negotiating rough ground」，因此容易跌落溝渠受傷，也就是牠們在崎嶇不平的地面上行走有困難，對應選項 (D) They have difficulties moving around the uneven fields。(A)(B)(C) 都是張冠李戴或文章未提及的說法。", "keyPoint": "閱讀理解：因果關係（小象受傷原因）", "skip": false}, {"id": "U112-41", "year": 112, "no": 41, "type": "閱讀測驗", "stem": "Which of the following statements about elephants and the tea gardens is true according to the passage?", "options": ["The elephants use the trenches to roam around the tea gardens.", "The fast growth of the tea gardens destroys the elephants' food source.", "Elephants are unwilling to leave their injured members behind in the tea gardens.", "Pregnant elephants avoid delivering babies in the tea gardens for fear of being disturbed."], "answer": "C", "passageRef": "112-P6", "explain": "文章明確提到「elephants are known to resist leaving their sick or dying behind」，象群不願拋下受傷或垂死的同伴，對應 (C) Elephants are unwilling to leave their injured members behind。(A) 大象是把茶園當地標，不是利用溝渠移動；(B) 文章講的是溝渠造成的死亡風險，而非茶園擴張破壞食物來源；(D) 懷孕母象其實是「因為人少」才選茶園當安全庇護所生產，並非「避免」在此生產，皆與原文相反或無據，故正解為 (C)。", "keyPoint": "閱讀理解：篩選正確敘述", "skip": false}, {"id": "U112-42", "year": 112, "no": 42, "type": "閱讀測驗", "stem": "What does \"it\" in the last paragraph refer to?", "options": ["To certify elephant-friendly trenches and organizations.", "To reward tea growers for protecting the environment.", "To encourage consumers to choose high-quality brands.", "To create a win-win situation for elephants and tea farms."], "answer": "D", "passageRef": "112-P6", "explain": "上文問「大象是否可能與蓬勃的茶產業共存？」，接著說 Elephant Friendly Tea 這個組織致力於「讓這件事（it）成為可能」，也就是让大象与茶产业「雙贏共存」，對應 (D) To create a win-win situation for elephants and tea farms。(A)(B)(C) 都只是文章提到的具體做法（認證、獎勵茶農、鼓勵消費者），並非 it 所指涉的整體目標，故選 (D)。", "keyPoint": "閱讀理解：代名詞指涉", "skip": false}, {"id": "U112-43", "year": 112, "no": 43, "type": "閱讀測驗", "stem": "Which of the following is true about the earliest traders in Zanzibar?", "options": ["The earliest traders arrived around 900 AD.", "Most of the earliest merchants came from Africa.", "Asian merchants arrived centuries before the African settlers.", "Traders from Persia settled down permanently around 1000 AD."], "answer": "C", "passageRef": "112-P7", "explain": "文章寫道「Traders from Asia had already visited the islands 900 years before the arrival of its first permanent settlers from the African mainland (around 1000 AD)」，意即亞洲商人比非洲移民早了整整900年抵達，故選 (C) Asian merchants arrived centuries before the African settlers。(A) 誤把非洲移民的時間當成最早貿易商的時間；(B)(D) 也與原文的先後順序不符。", "keyPoint": "閱讀理解：時間先後（最早的貿易商）", "skip": false}, {"id": "U112-44", "year": 112, "no": 44, "type": "閱讀測驗", "stem": "According to the passage, where is Zanzibar most likely located on the following map? (地圖題：Zanzibar 位於非洲東岸、印度洋上，選對應標記位置)", "options": ["A", "B", "C", "D"], "answer": "B", "passageRef": "112-P7", "explain": "（本題須參照原卷圖片，此處僅供對答案）文章開頭說 Zanzibar「Situated off the coast of Tanzania and washed by the warm, clean waters of the Indian Ocean」，也就是位於坦尚尼亞外海、印度洋上的群島，依地圖上標示東非外海印度洋的位置選 (B)。", "keyPoint": "閱讀理解：地圖定位題", "skip": true}, {"id": "U112-45", "year": 112, "no": 45, "type": "閱讀測驗", "stem": "Which of the following can be inferred from the passage about Zanzibar?", "options": ["For centuries, Zanzibar has been a heaven for beach lovers.", "Cloves, vanilla, and cinnamon are common spices in Zanzibar.", "Besides spices, Zanzibar is well known for a great variety of jewelry.", "Vasco da Gama was Zanzibar's first foreign ruler during the Age of Exploration."], "answer": "B", "passageRef": "112-P7", "explain": "文章末段提到「scented with the aroma of cloves, vanilla, and cinnamon floating in the air」，可推知丁香、香草、肉桂是 Zanzibar 常見的香料，故選 (B)。(A) 文章重點在於歷史上的貿易地位，而非「一直以來」都是海灘天堂（近代才因海灘聞名）；(C) 文章講的是香料而非珠寶，jewels 只是比喻用法；(D) Vasco da Gama 只是航海家，並未統治 Zanzibar，故排除其餘選項。", "keyPoint": "閱讀理解：推論題", "skip": false}, {"id": "U112-46", "year": 112, "no": 46, "type": "閱讀測驗", "stem": "Which set of words is used in the passage to refer to Zanzibar?", "options": ["islands, settlements, posts, crossroads", "islands, posts, jewels, destination", "archipelago, islands, jewels, destination", "archipelago, settlements, paths, islands"], "answer": "C", "passageRef": "112-P7", "explain": "文章中用來指稱 Zanzibar 的詞包括 archipelago（群島，開頭）、islands（群島）、jewels（如「these jewels on the Indian Ocean」比喻）、destination（如「popular beach destination」），四者合起來對應 (C) archipelago, islands, jewels, destination。其餘選項摻入了 settlements（聚落）、posts（貿易站）、paths（途徑）、crossroads（十字路口）等詞，這些指的是「當地的聚落／貿易活動」，並非用來稱呼 Zanzibar 本身，故不選。", "keyPoint": "閱讀理解：同義詞彙統整（指稱 Zanzibar 的字）", "skip": false}, {"id": "U112-49", "year": 112, "no": 49, "type": "閱讀測驗", "stem": "From (A) to (H) in the above chatroom discussions, which ones show that GreenBurger can be a choice for the chatroom participants themselves only under certain circumstances?（多選題）", "options": ["Olivia (tasted awful, a firm NO)", "Smith (hasn't tried; meat is a better deal)", "Mika (tastes too much like meat; never interested)", "Thomas (a carnivore, but OK once in a while just for a change)", "Rico (surprised it had more calories)", "Linda (liked it fine but not the price; trying to eat less beef)", "Ablo (whole family loves it; can have it every day)", "Alexander (highly processed; a killer if eaten regularly)"], "answer": "D", "passageRef": "112-P8", "explain": "題目問哪些人「只在特定情況下」才會把 GreenBurger 當作自己的選擇。Thomas（D）明講自己是肉食主義者（carnivore），但「偶爾換換口味」時不排斥吃一次，屬於有條件的接受；Linda（F）表示喜歡口味，但因為想少吃牛肉，才願意選擇它，也是附帶條件（想減少吃牛肉）才選用。其餘選項則不符合「有條件才選擇」：Olivia（A）、Mika（C）完全排斥、不會選；Smith（B）根本沒試過且認為肉更划算；Rico（E）只是意外發現熱量更高、語氣中立無明確條件；Ablo（G）是全家人無條件、每天都可以吃；Alexander（H）雖然承認調味後好吃，但強調「不健康、常吃是致命的」，整體語氣是反對而非「有條件接受」。因此正解為 (D)(F)，即 Thomas 與 Linda。", "keyPoint": "混合題／多選：找出「有條件才會選擇」的發言者", "skip": true}, {"id": "U111-1", "year": 111, "no": 1, "type": "詞彙", "stem": "When Jeffery doesn't feel like cooking, he often orders pizza online and has it ______ to his house.", "options": ["advanced", "delivered", "offered", "stretched"], "answer": "B", "passageRef": null, "explain": "訂披薩線上下單後「送到」家裡，要用 have it delivered（被動：使某物被送達）。deliver 有「運送、投遞」的意思，最貼切。其餘：advanced 是「先進的／進階的」（動詞 advance 才有提前、預付之意），offered 提供的，stretched 被拉長的，語意都兜不起來。", "keyPoint": "字義：deliver 外送/送達", "skip": false}, {"id": "U111-2", "year": 111, "no": 2, "type": "詞彙", "stem": "Jane is the best ______ I have ever had. I cannot imagine running my office without her help.", "options": ["assistant", "influence", "contribution", "politician"], "answer": "A", "passageRef": null, "explain": "後句「無法想像沒有她的幫忙要怎麼管理辦公室」，可知 Jane 是我 的得力「助理」assistant。influence 影響力、contribution 貢獻、politician 政治人物，都不是「人」在辦公室協助的角色，語意不合。", "keyPoint": "字義：assistant 助理", "skip": false}, {"id": "U111-3", "year": 111, "no": 3, "type": "詞彙", "stem": "The temple celebrated Mazu Festival by hosting ten days of lion dances, Taiwanese operas, and traditional hand ______ shows.", "options": ["chat", "quiz", "puppet", "variety"], "answer": "C", "passageRef": null, "explain": "廟會活動中提到獅陣、歌仔戲，接著提到傳統的「手 ___ 戲」，指的正是布袋戲，用 puppet（木偶、戲偶）最合適，hand puppet show＝布袋戲表演。chat 聊天、quiz 益智問答、variety 綜藝，都與傳統廟會表演無關。", "keyPoint": "字義：hand puppet 布袋戲(手偶)", "skip": false}, {"id": "U111-4", "year": 111, "no": 4, "type": "詞彙", "stem": "The new vaccine was banned by the Food and Drug Administration due to its ______ fatal side effects.", "options": ["potentially", "delicately", "ambiguously", "optionally"], "answer": "A", "passageRef": null, "explain": "疫苗被禁用是因為它「潛在的」致命副作用，副詞 potentially（潛在地、有可能地）修飾 fatal，語意通順。delicately 精緻地、ambiguously 含糊地、optionally 可選擇地，都無法合理修飾「致命的副作用」。", "keyPoint": "字義：potentially 潛在地", "skip": false}, {"id": "U111-5", "year": 111, "no": 5, "type": "詞彙", "stem": "______ the photos with dates and keywords help you sort them easily in your file.", "options": ["Tagging", "Flocking", "Rolling", "Snapping"], "answer": "A", "passageRef": null, "explain": "用日期和關鍵字「標記」照片，方便日後整理歸檔，tagging（動名詞，標記）最符合語意，是常見的攝影/檔案管理用詞。flocking 群聚、rolling 滾動、snapping 快速拍下，都與「加標籤整理」無關。", "keyPoint": "字義：tag 標記", "skip": false}, {"id": "U111-6", "year": 111, "no": 6, "type": "詞彙", "stem": "An ______ person is usually pleasant and easy to get along with, but don't expect that he or she will always say \"yes\" to everything.", "options": ["enormous", "intimate", "agreeable", "ultimate"], "answer": "C", "passageRef": null, "explain": "句子說這種人「通常很好相處」，但也不會每件事都說 yes，可知是形容個性隨和、好商量的 agreeable。enormous 巨大的、intimate 親密的、ultimate 終極的，語意都不符「個性溫和好相處」。", "keyPoint": "字義：agreeable 隨和的", "skip": false}, {"id": "U111-7", "year": 111, "no": 7, "type": "詞彙", "stem": "Hidden deep in a small alley among various tiny shops, the entrance of the Michelin star restaurant is barely ______ to passersby.", "options": ["identical", "visible", "available", "remarkable"], "answer": "B", "passageRef": null, "explain": "餐廳藏在巷弄小店之間，對路人而言「幾乎看不見」入口，故用 visible（可見的）最合理，barely visible＝幾乎不可見。identical 相同的、available 可取得的、remarkable 顯著的，都不是「能否被看見」的概念。", "keyPoint": "字義：visible 看得見的", "skip": false}, {"id": "U111-8", "year": 111, "no": 8, "type": "詞彙", "stem": "The original budget for my round-island trip was NT$5,000, but the ______ cost is likely to be 50 percent higher.", "options": ["moderate", "absolute", "promising", "eventual"], "answer": "D", "passageRef": null, "explain": "原本預算五千元，但「最終」花費可能高五成，eventual（最終的、結果的）正好對應 original 的對比。moderate 適度的、absolute 絕對的、promising 有前景的，都與「最後結果的花費」語意不合。", "keyPoint": "字義：eventual 最終的", "skip": false}, {"id": "U111-9", "year": 111, "no": 9, "type": "詞彙", "stem": "After watching a TV program on natural history, Adam decided to go on a ______ for dinosaur fossils in South Dakota.", "options": ["trial", "route", "strike", "quest"], "answer": "D", "passageRef": null, "explain": "看完恐龍紀錄片後決定去南達科他州「尋找」恐龍化石，quest（探索、尋求之旅）最貼切，go on a quest for＝展開尋找…的旅程。trial 試驗、route 路線、strike 罷工，皆不符合「去尋找化石」的語境。", "keyPoint": "字義：quest 探索/尋求", "skip": false}, {"id": "U111-10", "year": 111, "no": 10, "type": "詞彙", "stem": "With pink cherry blossoms blooming everywhere, the valley ______ like a young bride under the bright spring sunshine.", "options": ["bounces", "blushes", "polishes", "transfers"], "answer": "B", "passageRef": null, "explain": "櫻花盛開的山谷在春陽下「像年輕新娘一樣」，用擬人化的 blushes（臉紅、泛紅）最傳神，呼應新娘害羞臉紅的意象。bounces 彈跳、polishes 擦亮、transfers 轉移，都無法呈現「泛紅、嬌羞」的畫面。", "keyPoint": "字義：blush 臉紅", "skip": false}, {"id": "U111-11", "year": 111, "no": 11, "type": "綜合測驗", "stem": "The concept was (11) by Richard Booth, who opened the first second-hand bookshop...", "options": ["initiated", "represented", "acknowledged", "manipulated"], "answer": "A", "passageRef": "111-P1", "explain": "Richard Booth 開了第一間二手書店，是他「發起」了書鎮這個概念，initiated（發起、創始）最符合文意。represented 代表、acknowledged 承認、manipulated 操縱，都不是「首創某概念」的意思。", "keyPoint": "字義：initiate 發起", "skip": false}, {"id": "U111-12", "year": 111, "no": 12, "type": "綜合測驗", "stem": "Since the 1970s, book towns like Hay-on-Wye (12) up all over the world.", "options": ["spring", "sprang", "had sprung", "have been springing"], "answer": "D", "passageRef": "111-P1", "explain": "句首 Since the 1970s 表示動作從過去持續到現在，且仍在發生（世界各地不斷冒出書鎮），須用現在完成進行式 have been springing up。spring/sprang 是現在式/過去式單一動作，had sprung 是過去完成，時態都對不上 since 引導的持續語境。", "keyPoint": "時態：現在完成進行式(since+過去到現在持續)", "skip": false}, {"id": "U111-13", "year": 111, "no": 13, "type": "綜合測驗", "stem": "...that's where the similarities (13) . Each of these towns shows unique features of its own.", "options": ["form", "count", "end", "matter"], "answer": "C", "passageRef": "111-P1", "explain": "前面說「所有書鎮都有很多書店」，接著「相似之處僅止於此」，即 that's where the similarities end（相似點到此結束），下一句也接著說每個書鎮都有自己的特色，呼應 end。form 形成、count 算數、matter 重要，都無法表達「相似點的極限、終點」。", "keyPoint": "字義：end 到此為止", "skip": false}, {"id": "U111-14", "year": 111, "no": 14, "type": "綜合測驗", "stem": "...hosts authors to discuss their latest (14) .", "options": ["trends", "releases", "agendas", "announcements"], "answer": "B", "passageRef": "111-P1", "explain": "作者受邀討論他們「最新的作品」，releases 在此指新出版/發行的書籍作品，符合書市場景。trends 趨勢、agendas 議程、announcements 宣布，都不是指「作家的最新出版品」。", "keyPoint": "字義：release (作品的)發行/新作", "skip": false}, {"id": "U111-15", "year": 111, "no": 15, "type": "綜合測驗", "stem": "...book towns like Hay-on-Wye are particularly important to (15) .", "options": ["get their worldwide fame", "conform to the new mode", "make their visitors satisfied", "keep the printed word alive"], "answer": "D", "passageRef": "111-P1", "explain": "整段強調數位閱讀興起下，書鎮讓人重新感受紙本書的觸感、氣味與歷史感，呼應「保存實體書的重要性」，故選 keep the printed word alive（讓文字/紙本書存續）。其餘選項（成名、順應新潮流、讓遊客滿意）都偏離段落強調「紙本書 vs. 數位閱讀」的核心對比。", "keyPoint": "主旨呼應：保存紙本書", "skip": false}, {"id": "U111-16", "year": 111, "no": 16, "type": "綜合測驗", "stem": "...they actually were designed for reasons (16) aesthetics.", "options": ["contrary to", "except for", "more of", "other than"], "answer": "D", "passageRef": "111-P2", "explain": "圓窗雖然好看，但設計理由是「美觀以外的」原因（其實是為了安全），reasons other than aesthetics＝除了美觀之外的理由，符合下文安全考量的鋪陳。contrary to 與…相反、except for 通常接名詞例外項、more of 較偏向於，語感或語法都不如 other than 自然貼切。", "keyPoint": "片語：other than 除了…之外(=besides)", "skip": false}, {"id": "U111-17", "year": 111, "no": 17, "type": "綜合測驗", "stem": "In the early days of aviation, plane windows (17) square in shape.", "options": ["used to be", "were to be", "would have been", "must have been"], "answer": "A", "passageRef": "111-P2", "explain": "早期飛機窗戶「過去曾是」方形（現在已改成圓形），used to be 表示過去的狀態現在已不存在，正好呼應下文方窗被淘汰的敘述。were to be 表安排/命運、would have been 是與過去事實相反的假設、must have been 是對過去的推測，皆不符合單純敘述過去事實。", "keyPoint": "文法：used to+原V 表過去的習慣/狀態(現已不同)", "skip": false}, {"id": "U111-18", "year": 111, "no": 18, "type": "綜合測驗", "stem": "The problem is (18) when airplanes fly at higher altitudes...", "options": ["disguised", "understood", "confronted", "intensified"], "answer": "D", "passageRef": "111-P2", "explain": "飛得越高，機艙內外壓力差越大，使原本的（尖角應力集中）問題「更加惡化」，intensified（加劇的）最合文意。disguised 被偽裝、understood 被理解、confronted 被面對，都無法表達「問題變得更嚴重」。", "keyPoint": "字義：intensify 加劇", "skip": false}, {"id": "U111-19", "year": 111, "no": 19, "type": "綜合測驗", "stem": "When subjected to repeated pressurization high in the sky, the four corners on a square window may (19) .", "options": ["cause conflict", "rebuild strength", "spell disaster", "endure shock"], "answer": "C", "passageRef": "111-P2", "explain": "方形窗角反覆承受加壓後可能「釀成災難」（即機身裂開），spell disaster 是「導致嚴重後果」的慣用說法，呼應前文三架飛機在空中解體的悲劇。cause conflict 引起衝突、rebuild strength 重建力量、endure shock 承受衝擊，語意都不符合「窗角破裂釀禍」的情境。", "keyPoint": "片語：spell disaster 招致災難", "skip": false}, {"id": "U111-20", "year": 111, "no": 20, "type": "綜合測驗", "stem": "...and therefore can (20) extreme differences in pressure inside and outside of an aircraft.", "options": ["tolerate", "improve", "justify", "obtain"], "answer": "A", "passageRef": "111-P2", "explain": "圓形窗因應力分散均勻、抗變形能力強，因此能「承受」機艙內外極端的壓力差，tolerate（忍受、承受）最貼切。improve 改善、justify 使正當化、obtain 獲得，都不是「承受壓力差」的意思。", "keyPoint": "字義：tolerate 承受", "skip": false}, {"id": "U111-21", "year": 111, "no": 21, "type": "文意選填", "stem": "第21格：...daring actions that are deemed too (21) for the regular actor to perform...", "options": ["possible", "sensation", "risky", "cost", "witnessed", "professional", "called for", "tried out", "necessity", "career"], "answer": "C", "passageRef": "111-P3", "explain": "空格前 too，後接 for the regular actor to perform，需要形容詞，且語意是「太危險」讓一般演員無法執行的特技動作，故選 risky（危險的）。這格若選 possible 或 professional 詞性雖可能但語意不通，故從語意判斷唯有「危險」符合特技工作的定義。", "keyPoint": "文意選填：risky 危險的(形容詞)", "skip": false}, {"id": "U111-22", "year": 111, "no": 22, "type": "文意選填", "stem": "第22格：Stunt work emerged out of (22) over time.", "options": ["possible", "sensation", "risky", "cost", "witnessed", "professional", "called for", "tried out", "necessity", "career"], "answer": "I", "passageRef": "111-P3", "explain": "emerged out of ___，out of necessity 是固定用法，意為「出於需要」，說明特技這行是因應「需求」而自然發展出來的，語意通順且詞性（介系詞後接名詞）也吻合。", "keyPoint": "文意選填：necessity 需要/必要性(名詞)", "skip": false}, {"id": "U111-23", "year": 111, "no": 23, "type": "文意選填", "stem": "第23格：There were, however, no (23) crew members to perform impressive stunts at that time.", "options": ["possible", "sensation", "risky", "cost", "witnessed", "professional", "called for", "tried out", "necessity", "career"], "answer": "F", "passageRef": "111-P3", "explain": "空格修飾 crew members（工作人員），指當時「沒有專業的」工作人員能做特技，professional（專業的）恰好符合形容詞位置與早期電影業缺乏專業特技人員的背景說明。", "keyPoint": "文意選填：professional 專業的(形容詞)", "skip": false}, {"id": "U111-24", "year": 111, "no": 24, "type": "文意選填", "stem": "第24格：...so they often (24) things for the first time during the actual shooting.", "options": ["possible", "sensation", "risky", "cost", "witnessed", "professional", "called for", "tried out", "necessity", "career"], "answer": "H", "passageRef": "111-P3", "explain": "句意是這些沒受過訓練的人常常在正式拍攝時「第一次嘗試」做這些危險動作，tried out（嘗試著做）符合語境，且與後面 for the first time 呼應。", "keyPoint": "文意選填：try out 嘗試(過去式tried out)", "skip": false}, {"id": "U111-25", "year": 111, "no": 25, "type": "文意選填", "stem": "第25格：They had to learn from their own mistakes, which (25) some their lives...", "options": ["possible", "sensation", "risky", "cost", "witnessed", "professional", "called for", "tried out", "necessity", "career"], "answer": "D", "passageRef": "111-P3", "explain": "從自己的錯誤中學習，這樣的代價「使得」一些人付出了性命，which cost some their lives 是「花費/使…付出」的固定句型（cost sb. sth.），與後文「幾乎所有人都受傷」呼應。", "keyPoint": "文意選填：cost 使付出代價(過去式同形cost)", "skip": false}, {"id": "U111-26", "year": 111, "no": 26, "type": "文意選填", "stem": "第26格：...serial action movies, which (26) the use of dedicated stunt people...", "options": ["possible", "sensation", "risky", "cost", "witnessed", "professional", "called for", "tried out", "necessity", "career"], "answer": "G", "passageRef": "111-P3", "explain": "連續動作片流行，「促使/需要」專職特技演員的出現，called for（需要、要求）符合serial action movies對特技需求增加的因果關係。", "keyPoint": "文意選填：call for 需要/要求(過去式called for)", "skip": false}, {"id": "U111-27", "year": 111, "no": 27, "type": "文意選填", "stem": "第27格：...many cowboys with masterful skills on horseback found a new (27) as a stunt person.", "options": ["possible", "sensation", "risky", "cost", "witnessed", "professional", "called for", "tried out", "necessity", "career"], "answer": "J", "passageRef": "111-P3", "explain": "許多善於騎馬的牛仔找到了「新的職業」──當特技演員，found a new career as，career（職業生涯）符合語意與詞性(a new + 名詞)。", "keyPoint": "文意選填：career 職業生涯(名詞)", "skip": false}, {"id": "U111-28", "year": 111, "no": 28, "type": "文意選填", "stem": "第28格：The 1960s and '70s (28) the development of most modern stunt technology...", "options": ["possible", "sensation", "risky", "cost", "witnessed", "professional", "called for", "tried out", "necessity", "career"], "answer": "E", "passageRef": "111-P3", "explain": "1960、70年代「見證了」大部分現代特技技術的發展，witnessed（見證）是常見用法：某個時代見證某項發展，符合句子主詞為時間段(The 1960s and '70s)的用法。", "keyPoint": "文意選填：witness 見證(過去式witnessed)", "skip": false}, {"id": "U111-29", "year": 111, "no": 29, "type": "文意選填", "stem": "第29格：...and it is now (29) to create very lifelike scenes without using real stunt people.", "options": ["possible", "sensation", "risky", "cost", "witnessed", "professional", "called for", "tried out", "necessity", "career"], "answer": "A", "passageRef": "111-P3", "explain": "現在利用CGI「有可能」創造出逼真的畫面而不需真人特技演員，it is now possible to V 是常見句型，possible（可能的）完全符合語意與句型 it is + adj. + to V。", "keyPoint": "文意選填：possible 可能的(形容詞)", "skip": false}, {"id": "U111-30", "year": 111, "no": 30, "type": "文意選填", "stem": "第30格：...there will always be a demand for the realism and thrilling (30) of an actual stunt.", "options": ["possible", "sensation", "risky", "cost", "witnessed", "professional", "called for", "tried out", "necessity", "career"], "answer": "B", "passageRef": "111-P3", "explain": "真人特技帶來的寫實感與刺激的「感官震撼」永遠有市場需求，thrilling sensation（刺激的感官體驗）修飾得當，sensation 作名詞與 thrilling 形容詞搭配自然。", "keyPoint": "文意選填：sensation 感官刺激/轟動感(名詞)", "skip": false}, {"id": "U111-31", "year": 111, "no": 31, "type": "篇章結構", "stem": "第31格：Obon...honors the spirits of the dead. (31) The festival usually lasts for four to five days in August.", "options": ["Some people also visit the cemetery to clean up the family graves and pray for their ancestors.", "Such festive activities are usually held in parks, temples, and other public places around Japan.", "Obon concludes with another bonfire, okuribi, lighting up the sky to see the ancestors' spirits off.", "Originating from the Chinese Ghost Festival, this annual event has evolved into a time of family reunion."], "answer": "D", "passageRef": "111-P4", "explain": "此段開頭先定義 Obon 是紀念亡靈的節日，緊接選項D「源自中國中元節，演變成家族團聚的節日」提供起源背景，並自然銜接後句「這節日通常持續四到五天…人們回鄉與家人團聚」，因為D句已先點出「family reunion」的主題。", "keyPoint": "篇章結構：補充起源背景，承接下句", "skip": false}, {"id": "U111-32", "year": 111, "no": 32, "type": "篇章結構", "stem": "第32格：...to guide spirits upon their return back home. (32) Food offerings are presented at house altars and temples.", "options": ["Some people also visit the cemetery to clean up the family graves and pray for their ancestors.", "Such festive activities are usually held in parks, temples, and other public places around Japan.", "Obon concludes with another bonfire, okuribi, lighting up the sky to see the ancestors' spirits off.", "Originating from the Chinese Ghost Festival, this annual event has evolved into a time of family reunion."], "answer": "A", "passageRef": "111-P4", "explain": "前句講述人們點迎火(mukaebi)引導祖靈返家，選項A「有些人也會去掃墓、祭拜祖先」是另一項與迎接祖先相關的活動，銜接下一句「在家中神壇與寺廟供奉食物」，三者都屬於迎接與供奉祖靈的一系列習俗。", "keyPoint": "篇章結構：承接迎靈儀式，補充相關活動", "skip": false}, {"id": "U111-33", "year": 111, "no": 33, "type": "篇章結構", "stem": "第33格：(33) Paper lanterns and offerings are sent floating down rivers to accompany the ancestors back to their resting place.", "options": ["Some people also visit the cemetery to clean up the family graves and pray for their ancestors.", "Such festive activities are usually held in parks, temples, and other public places around Japan.", "Obon concludes with another bonfire, okuribi, lighting up the sky to see the ancestors' spirits off.", "Originating from the Chinese Ghost Festival, this annual event has evolved into a time of family reunion."], "answer": "C", "passageRef": "111-P4", "explain": "後句描述「紙燈籠與供品被放入河中漂流，護送祖先返回安息之處」，正是送靈儀式的具體做法，因此前面需先由選項C「Obon以另一場篝火okuribi(送火)點亮夜空、送別祖靈」點出這是節慶尾聲的送別環節，前後呼應完整。", "keyPoint": "篇章結構：引出送靈儀式(okuribi)", "skip": false}, {"id": "U111-34", "year": 111, "no": 34, "type": "篇章結構", "stem": "第34格：...are encouraged to dance to the music around the stage. (34) Originally dedicated to the deceased, the dances have now become a symbol of the summer festival themselves.", "options": ["Some people also visit the cemetery to clean up the family graves and pray for their ancestors.", "Such festive activities are usually held in parks, temples, and other public places around Japan.", "Obon concludes with another bonfire, okuribi, lighting up the sky to see the ancestors' spirits off.", "Originating from the Chinese Ghost Festival, this annual event has evolved into a time of family reunion."], "answer": "B", "passageRef": "111-P4", "explain": "前面描述人們在舞台周圍隨音樂起舞，選項B「這類慶祝活動通常在公園、寺廟等公共場所舉行」補充說明盆舞舉辦的地點，接著承接下句「原本是獻給亡者的舞蹈，如今已成為夏日祭典本身的象徵」，做出總結性的轉折。", "keyPoint": "篇章結構：概述舞蹈舉辦場所，承接結尾感想", "skip": false}, {"id": "U111-35", "year": 111, "no": 35, "type": "閱讀測驗", "stem": "Which of the following pictures best represents the image of a typical Maasai warrior?", "options": ["(圖A)", "(圖B)", "(圖C)", "(圖D)"], "answer": "B", "passageRef": "111-P5", "explain": "文章描述馬賽戰士的典型形象是身披紅色格紋/條紋披肩(shúkà)、手持長矛與盾牌(spear and shield)，且紅色是最受喜愛、象徵團結與勇氣的顏色。四張圖中最符合「紅色披肩＋持矛盾」形象的是圖B，其餘圖片若缺少長矛盾牌或顏色/服裝不符文中敘述則不選。", "keyPoint": "主旨題", "skip": true}, {"id": "U111-36", "year": 111, "no": 36, "type": "閱讀測驗", "stem": "What can we learn from the passage about the Maasai people?", "options": ["They have been urged by governments to leave behind their traditions.", "They resist foreign influence because they were enslaved in the past.", "A boy has to kill a lion by himself before becoming an adult.", "A Maasai woman is usually good at beadwork and farming."], "answer": "A", "passageRef": "111-P5", "explain": "文章明確寫道馬賽人「抵抗了肯亞與坦尚尼亞政府要他們採用更現代生活方式的勸說」(resisted the urging of...governments to adopt a more modern lifestyle)，這代表政府確實曾「敦促」他們放棄傳統，故選A。B錯在馬賽人是抵抗奴隸制而非曾被奴役；C的「必須獨自殺獅」文中用 up until recently 表示這已是過去的作法，非現今普遍規定；D珠飾工藝是女性專長，但文中並未提到務農，屬過度延伸。", "keyPoint": "細節理解：政府曾勸說馬賽人現代化", "skip": false}, {"id": "U111-37", "year": 111, "no": 37, "type": "閱讀測驗", "stem": "Which of the following is true about Maasai clothing and beadwork?", "options": ["Striped and patterned cloth is preferred by young adults.", "Young men cannot wear black until they become warriors.", "Colorful glass jewelry became popular after the 19th century.", "The color of the shúkà represented one's importance in the tribe."], "answer": "C", "passageRef": "111-P5", "explain": "文中說「與歐洲人貿易之前用天然材料，19世紀後這些材料被色彩繽紛的玻璃珠取代」，可知玻璃珠飾在19世紀之後才流行，對應選項C。A錯在條紋花布是女性偏好而非泛指「年輕人」；B錯在黑衣是割禮後的服裝，與「成為戰士」無直接對應；D錯在shúkà顏色與年齡性別地域有關，並非代表地位重要性。", "keyPoint": "細節理解：19世紀後玻璃珠流行", "skip": false}, {"id": "U111-38", "year": 111, "no": 38, "type": "閱讀測驗", "stem": "Why does the author quote Blixen's comment at the end of the third paragraph?", "options": ["To explain how Maasai warriors hunt for deer in the wild.", "To exemplify the types of weapons used by Maasai warriors.", "To emphasize that weapons are an inseparable part of a Maasai warrior's outfit.", "To show the similarities between the behavior of a Maasai warrior and that of a male deer."], "answer": "C", "passageRef": "111-P5", "explain": "Blixen 的話「他們的武器與裝飾就像雄鹿的角一樣，是他們存在本身的一部分」，用鹿角天生長在鹿身上比喻武器對馬賽戰士而言是與生俱來、密不可分的一部分，用來強調武器的重要性與不可分割性，故選C。並非在講獵鹿方式(A)、列舉武器種類(B)，也不是比較戰士與鹿「行為」的相似(D，引文其實是講「屬性/存在」而非「行為」)。", "keyPoint": "作者引用用意：凸顯武器是戰士身分不可分割的一部分", "skip": false}, {"id": "U111-39", "year": 111, "no": 39, "type": "閱讀測驗", "stem": "Which of the following aspects about hard hats is NOT discussed in the passage?", "options": ["Their functions.", "Their appearances.", "Their materials.", "Their limitations."], "answer": "D", "passageRef": "111-P6", "explain": "全文談到安全帽的功能(保護頭部)、外觀(顏色代表角色)、材質(帆布皮革→鋁→玻璃纖維→熱塑材料)，卻從未提到安全帽有什麼「限制/缺點」，因此答案為D「限制」，是文章沒有討論到的面向。", "keyPoint": "細節理解：文章未提及安全帽的限制", "skip": false}, {"id": "U111-40", "year": 111, "no": 40, "type": "閱讀測驗", "stem": "In what order did the following protective hats appear? a. fiberglass hats  b. hats with see-through shields  c. hats with canvas and leather  d. hats with tar over them", "options": ["dcab", "cdba", "cbad", "dcba"], "answer": "A", "passageRef": "111-P6", "explain": "依文章時間軸：戰前工人用煤焦油塗抹帽子（d, tar）→1919年Bullard發明帆布皮革材質的Hard Boiled Hat（c）→之後材質演進到鋁、玻璃纖維（a）→近期才加裝透明面罩(b, see-through shields)，正確順序為 d→c→a→b，對應選項A「dcab」。", "keyPoint": "順序理解：安全帽材質/配件演進史", "skip": false}, {"id": "U111-41", "year": 111, "no": 41, "type": "閱讀測驗", "stem": "According to the passage, which of the following statements is true about the hard hat?", "options": ["Global sales have doubled every ten years.", "The inspiration came from the inventor's wartime experience.", "It was standard equipment for construction workers in the 1920s.", "Different colors are used in different industries to signal the roles of people on site."], "answer": "B", "passageRef": "111-P6", "explain": "文中明確說Bullard「剛從一戰歸來」，且「見證了金屬頭盔在戰爭中救命的力量」後決定研發安全帽，證實發明靈感源於他的戰時經歷，對應B。A文中僅提到2016與2025的預估銷售額，並無「每十年翻倍」的說法；C安全帽1919年才發明，1920年代尚非標準配備，直到1931、1933年重大工程才強制規定；D顏色代碼是用來辨識「同一工地」上的角色，而非跨產業辨識，敘述過度擴大。", "keyPoint": "細節理解：發明靈感來自戰爭經驗", "skip": false}, {"id": "U111-42", "year": 111, "no": 42, "type": "閱讀測驗", "stem": "Which of the following words are used in the passage to refer to the hard hat? a. tool  b. code  c. device  d. helmet  e. accessory  f. headgear", "options": ["a, b, d, e", "a, c, d, f", "c, d, e, f", "a, d, e, f"], "answer": "B", "passageRef": "111-P6", "explain": "文章中曾以 tool（安全工具，number one safety tool）、device（頭部保護裝置，head protection device）、helmet（頭盔，A hard hat is a helmet）、headgear（頭戴裝備，the headgear）等詞稱呼安全帽，故選a,c,d,f，對應選項B。b「code」是指顏色代碼(color code)本身而非安全帽的代稱，e「accessory」文中指的是加裝在安全帽上的「配件」(如收音機、感應器)，並非用來稱呼安全帽本體，故不列入。", "keyPoint": "同義詞彙比對：文中稱呼安全帽的用詞", "skip": false}, {"id": "U111-43", "year": 111, "no": 43, "type": "閱讀測驗", "stem": "What can we learn about zebrafish from the passage?", "options": ["How they should be studied in labs.", "Where they derive their regenerative ability.", "Why they share humans' genetic code.", "What they may offer in medical advancements."], "answer": "D", "passageRef": "111-P7", "explain": "全文重點在斑馬魚驚人的自我修復能力（心臟、視網膜再生），以及科學家希望這項研究未來能幫助人類治療失明、器官損傷等，整體聚焦於「斑馬魚研究可能帶來的醫療進展」，對應D。文章並非在教導如何在實驗室研究牠們(A)，也沒有詳述其再生能力「從何而來」的機制根源(B較偏機制細節而非全文主旨)，更沒有解釋「為何」人類與斑馬魚基因相似(C，文中只是陳述事實未解釋原因)。", "keyPoint": "主旨理解：斑馬魚研究對醫療的啟示", "skip": false}, {"id": "U111-44", "year": 111, "no": 44, "type": "閱讀測驗", "stem": "Which of the following statements is true regarding GABA in zebrafish?", "options": ["Increasing GABA level facilitates neuron activities.", "There is a high level of GABA in the brain of zebrafish.", "Lowering GABA levels in the brain can stimulate retina regrowth.", "GABA contains chemical elements that trigger the growth of neurons."], "answer": "C", "passageRef": "111-P7", "explain": "文章明白指出「降低斑馬魚體內的GABA濃度可以觸發視網膜再生，而高濃度的GABA會抑制再生過程」，對應C。A錯誤，因GABA是「降低」神經活動的物質，並非「促進」；B文中並未說明斑馬魚腦中GABA濃度本身偏高，只講濃度高低對再生的影響；D錯誤，GABA的作用是抑制神經活性，並非刺激神經生長。", "keyPoint": "細節理解：降低GABA可刺激視網膜再生", "skip": false}, {"id": "U111-45", "year": 111, "no": 45, "type": "閱讀測驗", "stem": "Which of the following is closest in meaning to \"replicated\" in the third paragraph?", "options": ["Reproduced.", "Reassembled.", "Recycled.", "Restored."], "answer": "A", "passageRef": "111-P7", "explain": "文中「若這個過程能在人類身上被 replicated（複製、重現）」，意指讓同樣的再生機制在人體重現，最接近 Reproduced（重現、複製），故選A。Reassembled 重新組裝、Recycled 回收再利用、Restored 恢復，語意都與「複製某個過程」不同。", "keyPoint": "字義：replicate ≈ reproduce 複製/重現", "skip": false}, {"id": "U111-46", "year": 111, "no": 46, "type": "閱讀測驗", "stem": "According to the passage, which of the following is an opinion, but NOT a fact?", "options": ["Humans and zebrafish have 70 percent of genes in common.", "Zebrafish can quickly recover vision after damage to the retina.", "Scientists are testing if the GABA theory works on mice as it does on zebrafish.", "Understanding regeneration in zebrafish may allow humans to regrow their organs."], "answer": "D", "passageRef": "111-P7", "explain": "選項D「了解斑馬魚的再生機制『或許』(may)有一天能讓人類重新長出器官」帶有推測、期望的語氣，屬於尚未證實的「意見/希望」，而非已驗證的事實。相較之下，A(基因相似70%)、B(斑馬魚視網膜受損後數週內恢復視力)、C(科學家正在小鼠身上測試GABA理論)都是文中陳述的既定事實或研究進展，並非推測。", "keyPoint": "事實 vs. 意見：帶有推測語氣(may)的敘述屬於意見", "skip": false}, {"id": "U111-49", "year": 111, "no": 49, "type": "閱讀測驗", "stem": "請從下列(A)到(F)中，選出對Yusra Mardini 和 Popole Misenga都正確的選項。（多選題）", "options": ["Being an Olympic medalist.", "Growing up in an orphanage.", "Joining the Olympic Games more than once.", "Leaving his/her hometown because of war.", "Showing talent in sports after going to a foreign country.", "Traveling through several countries before securing protection."], "answer": "C", "passageRef": "111-P8", "explain": "Yusra 曾參加2016里約與2021東京兩屆奧運，Popole 同樣參加了這兩屆奧運，故C「不只一次參加奧運」兩人皆符合；Yusra因敘利亚內戰逃離家園，Popole的祖國內戰奪走母親性命並使他流離失所，兩人都是「因戰爭離開家鄉」，故D也皆符合。A兩人皆未提及獲得奧運獎牌；B僅Popole曾待在收容失依兒童的中心，Yusra並未在孤兒院長大；E運動天分的展現時間點兩人不同（Yusra原本在敘利亚就已受訓游泳，並非到外國才展現天分；Popole是在剛果國內的收容中心才接觸柔道，也非在外國）；F只有Yusra輾轉經過黎巴嫩、土耳其、希臘等多國才獲得庇護，Popole主要在巴西一地尋求庇護，並未經過「多國」輾轉，故F不成立。正確答案為CD。", "keyPoint": "多選：兩位難民運動員的共同點", "skip": true}, {"id": "U110-1", "year": 110, "no": 1, "type": "詞彙", "stem": "Tom is really a naughty boy. He likes to ___ and play jokes on his younger sister when their parents are not around.", "options": ["alert", "spare", "tease", "oppose"], "answer": "C", "passageRef": null, "explain": "頑皮的弟弟趁父母不在時對妹妹「逗弄、開玩笑」，所以選 tease（捉弄）最符合語境。alert 是「警覺的」，spare 是「饒恕；騰出(時間)」，oppose 是「反對」，三者都不符合對妹妹惡作劇的情境。", "keyPoint": "字義:tease 逗弄、捉弄", "skip": false}, {"id": "U110-2", "year": 110, "no": 2, "type": "詞彙", "stem": "Elderly shoppers in this store are advised to take the elevator rather than the ___, which may move too fast for them to keep their balance.", "options": ["airway", "operator", "escalator", "instrument"], "answer": "C", "passageRef": null, "explain": "句意是「老人家最好搭電梯而非___，因為它移動太快讓人站不穩」，能讓人站不穩、速度快的正是手扶梯 escalator。airway 是「航線、氣道」，operator 是「操作員」，instrument 是「儀器、樂器」，都與交通工具無關。", "keyPoint": "字義:escalator 手扶梯", "skip": false}, {"id": "U110-3", "year": 110, "no": 3, "type": "詞彙", "stem": "Upon hearing its master's call, the dog wagged its tail, and followed her out of the room ___.", "options": ["obediently", "apparently", "logically", "thoroughly"], "answer": "A", "passageRef": null, "explain": "狗聽到主人呼喚就搖尾巴跟著離開房間，表現出「聽話、順從」的樣子，所以選 obediently（順從地）。apparently 是「顯然地」，logically 是「合乎邏輯地」，thoroughly 是「徹底地」，都不能形容狗聽話跟隨的動作。", "keyPoint": "字義:obediently 順從地", "skip": false}, {"id": "U110-4", "year": 110, "no": 4, "type": "詞彙", "stem": "Since many of our house plants are from humid jungle environments, they need ___ air to keep them green and healthy.", "options": ["moist", "stale", "crisp", "fertile"], "answer": "A", "passageRef": null, "explain": "句子說家中植物來自濕熱叢林，需要「潮濕」的空氣才能保持翠綠健康，故選 moist（潮濕的）。stale 是「不新鮮、悶的」，crisp 是「清脆乾爽的」，fertile 是「肥沃的」(通常形容土壤而非空氣)，皆不符合叢林濕氣的語境。", "keyPoint": "字義:moist 潮濕的", "skip": false}, {"id": "U110-5", "year": 110, "no": 5, "type": "詞彙", "stem": "The skydiver managed to land safely after jumping out of the aircraft, even though her ___ failed to open in midair.", "options": ["glimpse", "latitude", "segment", "parachute"], "answer": "D", "passageRef": null, "explain": "跳傘者從飛機跳下後即使「___在空中未能打開」仍安全著陸，能打開、用來減速降落的裝置就是降落傘 parachute。glimpse 是「一瞥」，latitude 是「緯度」，segment 是「部分、區段」，都與跳傘裝備無關。", "keyPoint": "字義:parachute 降落傘", "skip": false}, {"id": "U110-6", "year": 110, "no": 6, "type": "詞彙", "stem": "The invention of the steam engine, which was used to power heavy machines, brought about a ___ change in society.", "options": ["persuasive", "harmonious", "conventional", "revolutionary"], "answer": "D", "passageRef": null, "explain": "蒸汽機的發明為社會帶來了「革命性」的改變，選 revolutionary（革命性的）最貼切，呼應「brought about a ___ change」。persuasive 是「有說服力的」，harmonious 是「和諧的」，conventional 是「傳統的」，都與劇烈變革的語意相反或不搭。", "keyPoint": "字義:revolutionary 革命性的", "skip": false}, {"id": "U110-7", "year": 110, "no": 7, "type": "詞彙", "stem": "To encourage classroom ___, the teacher divided the class into groups and asked them to solve a problem together with their partners.", "options": ["operation", "interaction", "adjustment", "explanation"], "answer": "B", "passageRef": null, "explain": "老師把班級分組、讓學生一起合作解題，目的是鼓勵「課堂互動」interaction。operation 是「操作、運作」，adjustment 是「調整」，explanation 是「解釋」，都不是分組合作要達成的目標。", "keyPoint": "字義:interaction 互動", "skip": false}, {"id": "U110-8", "year": 110, "no": 8, "type": "詞彙", "stem": "Lisa ___ onto the ground and injured her ankle while she was playing basketball yesterday.", "options": ["buried", "punched", "scattered", "tumbled"], "answer": "D", "passageRef": null, "explain": "Lisa 打籃球時摔倒在地並傷到腳踝，「摔倒」對應 tumbled。buried 是「埋葬」，punched 是「用拳頭打」，scattered 是「散落、分散」，皆不符合摔倒受傷的畫面。", "keyPoint": "字義:tumbled 跌倒、摔倒", "skip": false}, {"id": "U110-9", "year": 110, "no": 9, "type": "詞彙", "stem": "Hundreds of residents received free testing ___ from the city government to find out if their water contained any harmful chemicals.", "options": ["kits", "trials", "zones", "proofs"], "answer": "A", "passageRef": null, "explain": "市政府提供居民「免費的檢測___」來檢驗水中是否含有害化學物質，這種一整套的檢測用具正是 testing kits（檢測套組）。trials 是「試驗、審判」，zones 是「區域」，proofs 是「證明」，都不是可拿到手上的實體用品。", "keyPoint": "字義:kits 成套用品/工具組", "skip": false}, {"id": "U110-10", "year": 110, "no": 10, "type": "詞彙", "stem": "The 2011 Nobel Peace Prize was awarded ___ to three women for the efforts they made in fighting for women's rights.", "options": ["actively", "earnestly", "jointly", "naturally"], "answer": "C", "passageRef": null, "explain": "2011 年諾貝爾和平獎「共同」頒給三位女性，強調獎項由多人一起獲得，故選 jointly（共同地）。actively 是「積極地」，earnestly 是「誠懇認真地」，naturally 是「自然地」，都無法表達「共同獲獎」的概念。", "keyPoint": "字義:jointly 共同地", "skip": false}, {"id": "U110-11", "year": 110, "no": 11, "type": "詞彙", "stem": "The company is ___ and making great profits under the wise leadership of the chief executive officer.", "options": ["applauding", "flourishing", "circulating", "exceeding"], "answer": "B", "passageRef": null, "explain": "公司在執行長帶領下「蓬勃發展」並獲利豐厚，flourishing（興盛的）最符合語境，與 and making great profits 語意一致。applauding 是「鼓掌」，circulating 是「流通」，exceeding 是「超過」，都不能形容公司經營良好的狀態。", "keyPoint": "字義:flourishing 繁榮興盛的", "skip": false}, {"id": "U110-12", "year": 110, "no": 12, "type": "詞彙", "stem": "It is absolutely ___ to waste your money on an expensive car when you cannot even get a driver's license.", "options": ["absurd", "cautious", "vigorous", "obstinate"], "answer": "A", "passageRef": null, "explain": "連駕照都沒有卻花大錢買昂貴的車，這種行為非常「荒謬」absurd。cautious 是「謹慎的」，vigorous 是「精力充沛的」，obstinate 是「固執的」，皆與句意不合。", "keyPoint": "字義:absurd 荒謬的", "skip": false}, {"id": "U110-13", "year": 110, "no": 13, "type": "詞彙", "stem": "The problem of illegal drug use is very complex and cannot be traced to merely one ___ reason.", "options": ["singular", "countable", "favorable", "defensive"], "answer": "A", "passageRef": null, "explain": "毒品問題很複雜，不能只歸咎於「單一」原因，singular（單一的）恰好呼應 merely one。countable 是「可數的」，favorable 是「有利的」，defensive 是「防衛性的」，都不符合「單一原因」的語意。", "keyPoint": "字義:singular 單一的", "skip": false}, {"id": "U110-14", "year": 110, "no": 14, "type": "詞彙", "stem": "The non-profit organization has ___ $1 million over five years to finance the construction of the medical center.", "options": ["equipped", "resolved", "committed", "associated"], "answer": "C", "passageRef": null, "explain": "非營利組織「承諾投入」100萬美元、分五年資助醫療中心興建，committed 常用於「committed + 金額」表示承諾提供資金。equipped 是「裝備」，resolved 是「解決；下定決心」，associated 是「聯繫、關聯」，用法都不符。", "keyPoint": "字義:committed 承諾投入(資金)", "skip": false}, {"id": "U110-15", "year": 110, "no": 15, "type": "詞彙", "stem": "One week after the typhoon, some bridges were finally opened and bus service ___ in the country's most severely damaged areas.", "options": ["departed", "resumed", "transported", "corresponded"], "answer": "B", "passageRef": null, "explain": "颱風後橋樑修復開通，公車服務也跟著「恢復」運行，resumed（恢復）最貼切。departed 是「出發、離開」，transported 是「運送」，corresponded 是「相符、通信」，都不能表達「服務恢復」的意思。", "keyPoint": "字義:resumed 恢復", "skip": false}, {"id": "U110-16", "year": 110, "no": 16, "type": "綜合測驗", "stem": "a visit to a major European city just would not be the same (16) encountering them", "options": ["as", "for", "though", "without"], "answer": "D", "passageRef": "110-P1", "explain": "句意是「若沒有遇見這些鴿子，逛歐洲城市就不會一樣」，without + Ving 表示「若無、缺少」，構成與現在事實相反的假設語氣，故選 without。as(如同)、for(因為)、though(雖然)在文法或語意上都接不起來。", "keyPoint": "介系詞:without 表「若無」的假設語氣", "skip": false}, {"id": "U110-17", "year": 110, "no": 17, "type": "綜合測驗", "stem": "the birds are now threatening to (17) the city's historic center", "options": ["set up", "hang on", "take over", "break down"], "answer": "C", "passageRef": "110-P1", "explain": "鴿子在巴塞隆納歷史中心到處便溺，等於「佔據、接管」了這個區域，take over 正好表達鴿子氾濫、鵲巢鳩占的威脅感。set up 是「設立」，hang on 是「堅持、稍等」，break down 是「故障、拆毀」，都不符合「威脅要占據市中心」的語意。", "keyPoint": "片語:take over 佔據、接管", "skip": false}, {"id": "U110-18", "year": 110, "no": 18, "type": "綜合測驗", "stem": "The city council originally proposed (18) the pigeon population by gathering the birds and shooting them", "options": ["counting", "reducing", "displaying", "maintaining"], "answer": "B", "passageRef": "110-P1", "explain": "propose（提議）後面接動名詞，語意是市府原本提議「減少」鴿子數量(用抓捕、射殺的方式)，故選 reducing。counting 是「計算」，displaying 是「展示」，maintaining 是「維持」，都與「用捕殺降低數量」的原意不符。", "keyPoint": "動名詞當受詞:propose + Ving", "skip": false}, {"id": "U110-19", "year": 110, "no": 19, "type": "綜合測驗", "stem": "the government was finally persuaded to consider another (19) effective method", "options": ["nearly", "shortly", "precisely", "similarly"], "answer": "D", "passageRef": "110-P1", "explain": "前面提到抓捕射殺的方法引發抗議，後來政府被說服考慮「另一個同樣有效」的方法，similarly effective 意指「同樣有效但手段不同」(即節育)。nearly 是「幾乎」，shortly 是「不久」，precisely 是「精確地」，語意都兜不起來。", "keyPoint": "副詞:similarly 同樣地", "skip": false}, {"id": "U110-20", "year": 110, "no": 20, "type": "綜合測驗", "stem": "the pills were placed in 40 bird feeders (20) throughout the city", "options": ["installing", "installed", "to install", "having installed"], "answer": "B", "passageRef": "110-P1", "explain": "藥丸被放進「被安裝在」全市 40 個餵鳥器裡，feeders 與 install 是被動關係(餵鳥器是被安裝的)，故用過去分詞 installed 修飾 bird feeders。installing 是主動進行式不合邏輯，to install/having installed 則不符合此處單純的形容詞修飾用法。", "keyPoint": "分詞當形容詞:installed 修飾 feeders", "skip": false}, {"id": "U110-21", "year": 110, "no": 21, "type": "綜合測驗", "stem": "the odds of being hit by lightning are 1 in 3,000, (21) the probability of being struck seven different times", "options": ["if it isn't", "as you can see", "not to mention", "with regard to"], "answer": "C", "passageRef": "110-P2", "explain": "一生被閃電擊中一次的機率是三千分之一，「更不用說」被擊中七次的機率有多低，not to mention 正是「更別提…」的慣用語，用來加強語氣。if it isn't(若不是)、as you can see(如你所見)、with regard to(關於)在文法及語意上都接不上。", "keyPoint": "片語:not to mention 更不用說", "skip": false}, {"id": "U110-22", "year": 110, "no": 22, "type": "綜合測驗", "stem": "Sullivan was struck by lightning seven times—and (22) each shock!", "options": ["piloted", "rejected", "survived", "tracked"], "answer": "C", "passageRef": "110-P2", "explain": "Sullivan 被閃電擊中七次，而且每次都「活了下來」，survived each shock 表示每次雷擊都倖存。piloted 是「駕駛」，rejected 是「拒絕」，tracked 是「追蹤」，都不符合「挺過雷擊」的意思。", "keyPoint": "字義:survived 倖存、活過", "skip": false}, {"id": "U110-23", "year": 110, "no": 23, "type": "綜合測驗", "stem": "But after strike four, Sullivan became (23) death and took precautions during lightning strikes", "options": ["fearful of", "critical of", "doubtful about", "positive about"], "answer": "A", "passageRef": "110-P2", "explain": "第四次被雷擊後 Sullivan 開始「害怕」死亡，並在打雷時採取預防措施，fearful of death 正好呼應後面 took precautions(採取防範)。critical of 是「批評」，doubtful about 是「懷疑」，positive about 是「對…正面樂觀」，都與「開始防範雷擊」的心態相反或不搭。", "keyPoint": "片語:fearful of 害怕…的", "skip": false}, {"id": "U110-24", "year": 110, "no": 24, "type": "綜合測驗", "stem": "Sullivan, while surveying a campground, felt that a cloud was (24) him", "options": ["coming after", "getting over", "holding on to", "watching out for"], "answer": "A", "passageRef": "110-P2", "explain": "Sullivan 覺得有一朵雲在「追著」他跑，他想盡辦法逃跑但還是被擊中，coming after 表示雲朵像在追逐他。getting over 是「克服」，holding on to 是「抓住不放」，watching out for 是「注意、提防」，都無法表達「雲在追人」的畫面。", "keyPoint": "片語:coming after 追趕、跟著", "skip": false}, {"id": "U110-25", "year": 110, "no": 25, "type": "綜合測驗", "stem": "\"If he was, the first bolt (25) enough.\"", "options": ["was", "had been", "would be", "would have been"], "answer": "D", "passageRef": "110-P2", "explain": "這句話的意思是「如果上帝真的要對付我，第一次雷擊就會夠了(但事實是打了七次)」，屬於與過去事實相反的假設，主要子句要用 would have + p.p.，故選 would have been。was/had been/would be 在時態邏輯上都不符合這個與過去事實相反的推論。", "keyPoint": "文法:與過去事實相反的假設 would have been", "skip": false}, {"id": "U110-26", "year": 110, "no": 26, "type": "綜合測驗", "stem": "some mountain ranges of South America, Africa, and Indonesia are also (26) glaciers and ice sheets", "options": ["home to", "covers of", "roofs over", "room for"], "answer": "A", "passageRef": "110-P3", "explain": "南美、非洲、印尼的一些山脈也是冰河與冰原的「家鄉、棲息地」，be home to 常用來表示某地擁有/孕育某種事物，故選 home to。covers of、roofs over、room for 都是拼湊字面卻不成慣用語，語意不通。", "keyPoint": "片語:home to 是…的棲息地", "skip": false}, {"id": "U110-27", "year": 110, "no": 27, "type": "綜合測驗", "stem": "rising temperatures are posing an (27) threat to the last tropical glaciers", "options": ["occasional", "elaborate", "immediate", "offensive"], "answer": "C", "passageRef": "110-P3", "explain": "氣溫上升對熱帶冰河造成「立即、迫切」的威脅，呼應下文冰層正快速融化(五倍速度)的急迫性，故選 immediate threat。occasional 是「偶爾的」，elaborate 是「精心製作的」，offensive 是「冒犯的」，都不符合「迫在眉睫的威脅」語意。", "keyPoint": "字義:immediate 立即的、迫切的", "skip": false}, {"id": "U110-28", "year": 110, "no": 28, "type": "綜合測驗", "stem": "(28) already shrunk by 85% to a mere 0.5 square kilometers, Papua's glaciers will completely disappear within a decade", "options": ["Have", "Had", "Having", "Having been"], "answer": "C", "passageRef": "110-P3", "explain": "還原成完整句應是 As the ice sheets have already shrunk by 85%...，主詞與 shrink 是主動關係，且動作先於主要子句，因此用完成式分詞構句 Having (already) shrunk。Have 不是分詞形式，Had 不能單獨當分詞構句起頭，Having been 是被動形式但 shrink 是不及物動詞不能用被動，故都不對。", "keyPoint": "文法:Having + p.p. 完成式分詞構句(主動)", "skip": false}, {"id": "U110-29", "year": 110, "no": 29, "type": "綜合測驗", "stem": "The disappearance of the glaciers will also leave a significant (29) impact", "options": ["cultural", "moral", "political", "environmental"], "answer": "A", "passageRef": "110-P3", "explain": "下文解釋原住民巴布亞人視冰河為神聖象徵(山谷是神的四肢、冰河是頭)，這說明冰河消失留下的是「文化上」的衝擊，故選 cultural impact。moral(道德的)、political(政治的)、environmental(環境的，且下文並非談生態衝擊而是信仰文化)都不如 cultural 貼切。", "keyPoint": "字義:cultural 文化的", "skip": false}, {"id": "U110-30", "year": 110, "no": 30, "type": "綜合測驗", "stem": "Papua's glaciers are only the \"first to go\" if greenhouse gases are (30) and temperatures continue rising", "options": ["kept balanced", "made released", "seen dismissed", "left unchecked"], "answer": "D", "passageRef": "110-P3", "explain": "如果溫室氣體「被放任不管」持續排放，氣溫就會持續上升，left unchecked 意指「未受控制、放任」，被動語態符合「溫室氣體被人類放任」的邏輯。kept balanced(保持平衡)、made released(文法不通)、seen dismissed(文法不通)都不符合語意或文法。", "keyPoint": "片語:left unchecked 放任不管", "skip": false}, {"id": "U110-31", "year": 110, "no": 31, "type": "文意選填", "stem": "Research shows that (31) amounts of exercise—even just 15 minutes a day—helps ease depression", "options": ["means", "soreness", "point to", "argue", "demanding", "abide by", "fanatic", "current", "make time", "modest"], "answer": "J", "passageRef": "110-P4", "explain": "空格後面接 amounts of exercise，且用破折號補充「一天僅 15 分鐘」，表示「適度、不多」的運動量就有幫助，形容詞 modest(適度的)修飾 amounts 最貼切。", "keyPoint": "文意選填:modest 適度的", "skip": false}, {"id": "U110-32", "year": 110, "no": 32, "type": "文意選填", "stem": "you don't have to be a fitness (32) to do it", "options": ["means", "soreness", "point to", "argue", "demanding", "abide by", "fanatic", "current", "make time", "modest"], "answer": "G", "passageRef": "110-P4", "explain": "you don't have to be a fitness ___，句意是「不必成為健身狂熱者」也能做運動，fanatic 當名詞指「狂熱愛好者」，符合 a fitness fanatic(健身狂)的用法。", "keyPoint": "文意選填:fanatic 狂熱者", "skip": false}, {"id": "U110-33", "year": 110, "no": 33, "type": "文意選填", "stem": "make \"start slow and have fun\" a motto to (33)", "options": ["means", "soreness", "point to", "argue", "demanding", "abide by", "fanatic", "current", "make time", "modest"], "answer": "F", "passageRef": "110-P4", "explain": "make... a motto to ___，意思是把「慢慢開始、樂在其中」當作一句要「遵守、奉行」的座右銘，abide by(遵守)後面常接規則、原則或座右銘，用法吻合。", "keyPoint": "文意選填:abide by 遵守", "skip": false}, {"id": "U110-34", "year": 110, "no": 34, "type": "文意選填", "stem": "In fact, (34) health studies prove that exercise doesn't have to hurt to be effective", "options": ["means", "soreness", "point to", "argue", "demanding", "abide by", "fanatic", "current", "make time", "modest"], "answer": "H", "passageRef": "110-P4", "explain": "In fact, ___ health studies prove that...，形容詞需修飾 health studies(健康研究)，current(當前的、最新的)符合「近期的研究證實」的語意，呼應上一段 old-fashioned(過時)的對比。", "keyPoint": "文意選填:current 當前的", "skip": false}, {"id": "U110-35", "year": 110, "no": 35, "type": "文意選填", "stem": "You might (35) that if working out doesn't give you pain, it isn't working", "options": ["means", "soreness", "point to", "argue", "demanding", "abide by", "fanatic", "current", "make time", "modest"], "answer": "D", "passageRef": "110-P4", "explain": "You might ___ that if working out doesn't give you pain, it isn't working，空格後接 that 子句表達某種看法，argue that...(主張、認為)正好帶出「你可能會認為沒痛就沒效」這個(作者要反駁的)觀點。", "keyPoint": "文意選填:argue 主張", "skip": false}, {"id": "U110-36", "year": 110, "no": 36, "type": "文意選填", "stem": "physically (36) exercises may make you breathe heavily and your muscles may ache temporarily", "options": ["means", "soreness", "point to", "argue", "demanding", "abide by", "fanatic", "current", "make time", "modest"], "answer": "E", "passageRef": "110-P4", "explain": "physically ___ exercises may make you breathe heavily...，形容詞修飾 exercises，demanding(要求高、費力的)符合「讓人喘氣、肌肉痠痛」的高強度運動描述。", "keyPoint": "文意選填:demanding 費力的", "skip": false}, {"id": "U110-37", "year": 110, "no": 37, "type": "文意選填", "stem": "In fact, if it is, it may (37) an injury or muscle strain", "options": ["means", "soreness", "point to", "argue", "demanding", "abide by", "fanatic", "current", "make time", "modest"], "answer": "C", "passageRef": "110-P4", "explain": "if it is (painful), it may ___ an injury or muscle strain，意思是疼痛可能「顯示、指向」有受傷或拉傷，point to(指向、暗示)後接名詞的用法完全符合。", "keyPoint": "文意選填:point to 指向、顯示", "skip": false}, {"id": "U110-38", "year": 110, "no": 38, "type": "文意選填", "stem": "get results without the (38) or discomfort some people associate with exercise", "options": ["means", "soreness", "point to", "argue", "demanding", "abide by", "fanatic", "current", "make time", "modest"], "answer": "B", "passageRef": "110-P4", "explain": "get results without the ___ or discomfort，空格與 discomfort(不適)並列，需要一個名詞表示運動帶來的不舒服感，soreness(痠痛)正好呼應前文 muscles may ache(肌肉痠痛)。", "keyPoint": "文意選填:soreness 痠痛", "skip": false}, {"id": "U110-39", "year": 110, "no": 39, "type": "文意選填", "stem": "even short periods of low-impact exercise serve as a powerful (39) to improve your health", "options": ["means", "soreness", "point to", "argue", "demanding", "abide by", "fanatic", "current", "make time", "modest"], "answer": "A", "passageRef": "110-P4", "explain": "serve as a powerful ___ to improve your health，serve as a means to V 是固定用法，means 當名詞指「方法、手段」，符合「輕度運動是改善健康的有力手段」的語意。", "keyPoint": "文意選填:means 方法、手段", "skip": false}, {"id": "U110-40", "year": 110, "no": 40, "type": "文意選填", "stem": "try to (40) for exercise every day, like a 15-minute walk with your dog", "options": ["means", "soreness", "point to", "argue", "demanding", "abide by", "fanatic", "current", "make time", "modest"], "answer": "I", "passageRef": "110-P4", "explain": "try to ___ for exercise every day，make time for + N 是固定片語，意思是「為某事騰出時間」，呼應後面例子「每天遛狗 15 分鐘」這種擠出時間運動的行為。", "keyPoint": "文意選填:make time 撥出時間", "skip": false}, {"id": "U110-41", "year": 110, "no": 41, "type": "閱讀測驗", "stem": "What is the purpose of this passage?", "options": ["To argue for the benefits of nopales.", "To introduce a new source of energy.", "To predict the future agriculture policy of Mexico.", "To change people's ideas about energy consumption."], "answer": "B", "passageRef": "110-P5", "explain": "全文從仙人掌在墨西哥的文化地位一路談到科學家如何利用仙人掌廢棄外皮開發生質能發電機，重點在介紹一種「新能源」的產生方式，故選 B「介紹一種新能源」。A、C、D 都只是文章的部分內容或未提及的推測，不是全文核心目的。", "keyPoint": "主旨題:文章目的", "skip": false}, {"id": "U110-42", "year": 110, "no": 42, "type": "閱讀測驗", "stem": "Which of the following is NOT mentioned as a function of the prickly pear?", "options": ["For treating illnesses.", "For personal hygiene.", "For food and beverage.", "For gardening and landscaping."], "answer": "D", "passageRef": "110-P5", "explain": "文章第一段提到仙人掌被拿來吃、喝、做藥品(medicines)和洗髮精(shampoos)，分別對應食物飲料(C)、藥用(A)、個人衛生(B)，唯獨「園藝景觀用途」(D) gardening and landscaping 全文完全沒提到，故選 D。", "keyPoint": "細節題:NOT mentioned", "skip": false}, {"id": "U110-43", "year": 110, "no": 43, "type": "閱讀測驗", "stem": "Which of the following statements about the prickly pear cactus is true?", "options": ["Its soft inner part is often discarded.", "It was not discovered until the modern era.", "It turns into 200,000 tons of waste in Mexico each year.", "It appears in a prominent place on Mexico's national flag."], "answer": "D", "passageRef": "110-P5", "explain": "文章開頭明白寫道 the prickly pear cactus... occupies a prime spot on Mexico's national flag，直接對應選項 D「在墨西哥國旗上占有顯著位置」。A 說內部軟肉常被丟棄，但文章說內部軟肉才是被食用留下來的部分，是外皮才被當廢棄物，故錯；B 說「近代才被發現」與文章「自古被阿茲特克人視為神聖」矛盾；C 的 20 萬噸是仙人掌年產量而非「廢棄物」總量，敘述有誤。", "keyPoint": "細節題:仙人掌與墨西哥國旗", "skip": false}, {"id": "U110-44", "year": 110, "no": 44, "type": "閱讀測驗", "stem": "What advantage does the prickly pear cactus have over other biofuel crops?", "options": ["It generates more energy.", "It will not influence food prices.", "It may replace feed for livestock.", "It can increase global food production."], "answer": "B", "passageRef": "110-P5", "explain": "文章明確指出仙人掌只取外皮做燃料、內部軟肉仍保留食用，因此「不會對糧食價格造成壓力」(will not put pressure on food prices)，對應選項 B。A(產生更多能源)、C(可取代牲畜飼料)、D(可提升全球糧食產量)文章中都沒有提到，屬過度推論。", "keyPoint": "細節題:仙人掌生質燃料優勢", "skip": false}, {"id": "U110-45", "year": 110, "no": 45, "type": "閱讀測驗", "stem": "How is the information in the passage organized?", "options": ["In order of time.", "By cause and effect.", "In order of importance.", "By definition and illustration."], "answer": "A", "passageRef": "110-P6", "explain": "文章依序介紹西元前450年波斯的 Nehemiah、中世紀伊斯蘭哈里發的 bara'a、中世紀歐洲的旅行文件、英王亨利五世發明真正的護照、16世紀「passport」一詞出現，到第一次世界大戰才普及使用，明顯是按時間先後鋪陳，故選 A「依時間順序」。", "keyPoint": "文章結構題:依時間順序", "skip": false}, {"id": "U110-46", "year": 110, "no": 46, "type": "閱讀測驗", "stem": "Which of the following statements is true about the earliest travel document?", "options": ["It was issued by the king of Judah.", "It was given to an official of Persia.", "It appeared more than three thousand years ago.", "It served to invite people to travel beyond the river."], "answer": "B", "passageRef": "110-P6", "explain": "文章提到最早可辨識的護照記載是 Nehemiah(尼希米)向波斯亞達薛西王請求前往猶大的許可，國王給了他一封信，Nehemiah 是「serving King Artaxerxes of ancient Persia」的官員，故選 B「發給一位波斯的官員」。A 錯在信是波斯王給的不是猶大王給的；C 時間描述不精確(約450 B.C.距今約2400多年，非三千年以上)；D 該信是要求「安全通行」而非邀請旅行，用詞不符。", "keyPoint": "細節題:最早的旅行文件", "skip": false}, {"id": "U110-47", "year": 110, "no": 47, "type": "閱讀測驗", "stem": "When did the term \"passport\" start being used?", "options": ["In about 450 B.C.", "During World War I.", "In the 16th century.", "During King Henry V's reign."], "answer": "C", "passageRef": "110-P6", "explain": "文章說最早提到這類文件是在15世紀的一項國會法案中，而「passport」這個詞則是「about a century later」才開始使用，15世紀之後一百年即16世紀，故選 C。A 是最早旅行文件出現的時間(不是「passport」這個詞)；B 是護照普及使用的年代；D 是亨利五世發明護照的年代，皆非「passport」這個詞出現的時間。", "keyPoint": "細節題:passport 一詞何時出現", "skip": false}, {"id": "U110-48", "year": 110, "no": 48, "type": "閱讀測驗", "stem": "Which of the following is NOT mentioned in the passage as a form of passport?", "options": ["A letter.", "A receipt.", "A proof of identity.", "A list of seaports."], "answer": "D", "passageRef": "110-P6", "explain": "文中提到的護照形式有：Nehemiah 拿到的信(letter，對應A)、伊斯蘭哈里發時期的完稅收據 bara'a(receipt，對應B)、亨利五世發明用來證明身分的文件(proof of identity，對應C)；而「seaports 名單」文章只說中世紀歐洲文件列的是可通行的城鎮清單，且提到「不需要文件就能到海港」，並沒有「海港名單」這種護照形式，故選 D。", "keyPoint": "細節題:NOT mentioned 作為護照形式", "skip": false}, {"id": "U110-49", "year": 110, "no": 49, "type": "閱讀測驗", "stem": "Which of the following is the closest illustration of Benjamin Franklin's invention? (原題為四張圖片選項A-D)", "options": ["圖A", "圖B", "圖C", "圖D"], "answer": "D", "passageRef": "110-P7", "explain": "（本題須參照原卷圖片，此處僅供對答案）此題原考卷提供四張圖片供考生比對，依文章描述玻璃琴是由數十個大小不同的玻璃半球，用一根鐵棒串成由大到小排列，並以腳踏板控制旋轉、手指觸碰邊緣發聲，最符合此構造描述的圖片為官方公布的正解圖D，其餘三張圖與此結構不符。", "keyPoint": "圖片對應題:玻璃琴外觀", "skip": true}, {"id": "U110-50", "year": 110, "no": 50, "type": "閱讀測驗", "stem": "Which of the following statements is true about how the glass armonica works?", "options": ["Water has to be poured into the glass hemispheres.", "Colored paint makes it sound better and last longer.", "An iron rod is used to strike the thicker glass hemispheres.", "The performer's fingers have to be slightly wet when playing it."], "answer": "D", "passageRef": "110-P7", "explain": "文章寫道 Franklin moistened his fingers and held them against the rims of the glass hemispheres，明確指出演奏者要先把手指「沾濕」才能演奏，對應選項 D。A 錯在是手指沾濕而非把水倒入玻璃半球中；B 上色是為了標示音符方便辨識，與音質好壞或耐用度無關；C 鐵棒是用來串連、旋轉玻璃半球，不是用來「敲擊」它們。", "keyPoint": "細節題:玻璃琴演奏方式", "skip": false}, {"id": "U110-51", "year": 110, "no": 51, "type": "閱讀測驗", "stem": "According to the passage, why did the glass armonica lose its popularity?", "options": ["The skill of playing the glass armonica was very hard to master.", "Famous musicians like Beethoven had problems composing for it.", "Concert halls became too big for its music to be heard by the audience.", "Reviewers in that time indicated that it was clumsy and not fashionable."], "answer": "C", "passageRef": "110-P7", "explain": "文章第三段說音樂廳越蓋越大(19世紀的大型音樂廳)，玻璃琴聲音太小、沒有擴音設備就聽不到，因而逐漸被淘汰，對應選項 C「音樂廳變得太大，觀眾聽不到它的聲音」。A、B、D 文章中都沒有提到，D 甚至與文章「評論惋惜它聲音美妙、只是聽不到」相反。", "keyPoint": "細節題:玻璃琴為何式微", "skip": false}, {"id": "U110-52", "year": 110, "no": 52, "type": "閱讀測驗", "stem": "What does the highlighted \"they\" in the second paragraph refer to?", "options": ["Iron rods.", "Hemispheres.", "Colored notes.", "Musical pitches."], "answer": "B", "passageRef": "110-P7", "explain": "原句是 Franklin ran an iron rod through a hole in the top of each hemisphere so that they could nest together from largest to smallest，they 承接前面的 each hemisphere(玻璃半球)，指的是這些半球可以由大到小串在一起，故選 B「玻璃半球」。", "keyPoint": "代名詞指涉:they = hemispheres", "skip": false}, {"id": "U110-53", "year": 110, "no": 53, "type": "閱讀測驗", "stem": "What is the passage mainly about?", "options": ["The new addition to Morgan's Wonderland.", "The establishment and features of a special theme park.", "The advanced technological devices in Morgan's Wonderland.", "The needs of people who suffer from physical and mental disabilities."], "answer": "B", "passageRef": "110-P8", "explain": "全文從創辦人 Gordon Hartman 的女兒 Morgan 談起，介紹這座無障礙主題樂園的成立緣由、開幕、各項設施與擴建，主題是「一座特殊主題樂園的建立與特色」，故選 B。A 只是文章一小部分(2017年新擴建)，C、D 也只是文章中的細節或背景，並非全文主旨。", "keyPoint": "主旨題:文章主題", "skip": false}, {"id": "U110-54", "year": 110, "no": 54, "type": "閱讀測驗", "stem": "What does \"ultra-accessible\" in the second paragraph imply?", "options": ["It's easy for all visitors to use the facilities.", "Admission is free for people young and old.", "Wheelchairs are provided for every featured attraction.", "Morgan's Wonderland is situated in a convenient location."], "answer": "A", "passageRef": "110-P8", "explain": "第二段接著說門票對身障者免費、一般民眾也優惠折扣，讓「所有年齡與能力的人都能一起同樂」，可見 ultra-accessible 強調的是「所有訪客都能輕易使用園內設施」，故選 A。B 談的是票價而非「無障礙」本身；C、D 文章並未特別強調每項設施都配輪椅或地點方便。", "keyPoint": "字義推論:ultra-accessible 極度無障礙", "skip": false}, {"id": "U110-55", "year": 110, "no": 55, "type": "閱讀測驗", "stem": "Which of the following is NOT mentioned as a fun activity in the park?", "options": ["Fishing.", "Driving.", "Hiking.", "Picnicking."], "answer": "C", "passageRef": "110-P8", "explain": "文章提到 catch-and-release fishing lake(釣魚，對應A)、Off-Road Adventure 讓遊客體驗開越野車(駕駛，對應B)、picnic areas(野餐，對應D)，但全文並未提到「健行 hiking」這項活動，故選 C。", "keyPoint": "細節題:NOT mentioned 的遊樂活動", "skip": false}, {"id": "U110-56", "year": 110, "no": 56, "type": "閱讀測驗", "stem": "Which of the following statements is true about Morgan's Wonderland?", "options": ["Waterproof chairs enable visitors to roam all over the park.", "Morgan's Inspiration Island includes 25 acres of attractions.", "The success of the park is exactly what Morgan intended to achieve.", "GPS bands allow visitors to enjoy the convenience of the electronic devices."], "answer": "D", "passageRef": "110-P8", "explain": "文章說每位遊客可配戴 GPS Adventure Band，可以互相掌握彼此位置，還能參與電子互動活動(例如掃描手環在 Off-Road Adventure 拍照並寄到信箱)，對應選項 D「GPS手環讓遊客享受電子裝置的便利」。A 錯在防水椅是讓遊客轉換座椅玩水上設施，並非「在全園移動」；B 把 Morgan's Inspiration Island(2017年擴建)與 25 英畝主樂園面積搞混；C 文章未說樂園的成功完全符合 Morgan 本人的預期，屬過度推論。", "keyPoint": "細節題:GPS Adventure Band 功能", "skip": false}], "passages": [{"pid": "115-P1", "year": 115, "type": "綜合測驗", "text": "From the campfire to the café, people have always gathered together to share the latest news. White rhinoceroses, (11), do the same thing—only their choice of meeting place is a giant pile of poop.\n\nA new study indicates that rhinos have a smelly way to (12). Scientists studying white rhinos in South Africa have found that these animals leave messages in their poop. In particular, they leave their poop in the same place for all the other members in the group to smell—just like humans leaving messages on social media. Furthermore, different rhinos leave different chemicals in their poop, which provide important (13) about the age, sex, general health, and reproductive conditions of each specific rhino. This is of great significance for the peace and harmony in the group. When all members in a group know what's going on with each other, it is (14) that they will fight.\n\nThe researchers have even made \"fake poop\" to see how different rhinos would react. They find that dominant males are particularly (15) the \"fake poop\" that carries chemicals from females ready to mate. The males sniff it for longer duration and come back to the same spot more frequently, a clear sign that they are gathering information about mating opportunities from the poop.", "bank": null}, {"pid": "115-P2", "year": 115, "type": "綜合測驗", "text": "The history of dim sum stretches back to the early days of the Silk Road, an ancient network of trade routes connecting the East and the West. Those who traveled along the routes through China needed places to rest. Teahouses thus sprang up to (16) the weary travelers, offering them a cup of tea to help them regain energy. But the culinary art of dim sum (17), for it was considered inappropriate to pair tea with food. Centuries later, the ability of tea to aid in digestion finally became known. Teahouse owners therefore began providing bite-sized snacks as an accompaniment, and the tradition of these Cantonese delicacies was born.\n\nDim sum is more than just an example of Chinese cuisine. It is (18) an enjoyable dining experience that can span hours. The small portions were designed to merely \"touch the heart,\" as the name literally means, and (19) were first enjoyed as snacks. The small size allows the customer to order a great variety of dishes, creating a banquet of different tastes and flavors. It is customary for big groups to enjoy simple dishes together as (20). Ultimately, dim sum—the food—is only a small part of the dim sum experience.", "bank": null}, {"pid": "115-P3", "year": 115, "type": "文意選填", "text": "Are you feeling a little guilty about your daily mid-afternoon snooze? Well, you don't need to. Taking a nap in the middle of the day is by no means (21). In fact, you are giving your brain and your body some time to recharge and turn up refreshed.\n\nResearch has shown that napping is linked with brain size and (22); specifically, it can boost our cognition and memory. In our early 20s, our brain starts shrinking, which gradually slows cognition and increases dementia (23) in later life. The brain size of habitual nappers, however, is found to be better preserved. This suggests that napping may significantly (24) age-related brain shrinkage, and thus lower the possibility of developing dementia. Neurologists also confirm that naps can enhance memory and learning. For students cramming for college exams, napping will help (25) acquired knowledge and learned skills.\n\nUnderstanding how to perfect your nap is vital for reaping its benefits. To begin with, you need to find out the ideal length of a nap. Some studies recommend napping for 20 to 40 minutes, while others (26) shorter naps, such as 15 to 20 minutes. The best nap length, however, may (27) a person's physical condition and fatigue level. For some people, even a five-minute nap can bring about surprisingly (28) benefits.\n\nFurthermore, the environment where naps are taken also plays an important role. A dark space with little distraction is ideal for napping. So, find yourself a quiet place with (29) light or with blackout curtains. If you can't find a dark room, consider wearing a sleep mask. You can also add some soothing nature sounds to create a relaxing (30), which can make your naps more effective.", "bank": ["retain", "depend on", "atmosphere", "delay", "unproductive", "risk", "function", "minimal", "dramatic", "point to"]}, {"pid": "115-P4", "year": 115, "type": "篇章結構", "text": "Smiling is a gesture that many people engage in dozens of times a day without thought. Most people believe that smiling is an expression of good feelings, a simple way to show happiness and friendliness. But does this hold true across time and cultures?\n\n(31) In the West, for example, portraits of men and women before the 1700s typically depicted them with a serious, unsmiling expression. The absence of smiles stemmed partly from the attempt to hide their decayed teeth caused by poor dental hygiene. More importantly, smiling and laughter had long been perceived in the society as manifestations of a lack of self-control and good manners. Paintings with white-toothed smiles emerged after the 1700s, with the gradual rise of a culture that valued perception and responsiveness.\n\nRecent studies also show that interpretations of smiling may vary from culture to culture. While in most cultures smiling is associated with positive emotions, in certain cultures the same person can be judged as less intelligent when smiling. (32)\n\nThe amount people smile is culturally influenced as well. People smile more when they are from countries that are high in individualism and low in population. These are often places where the needs and rights of the individual take precedence over those of the group. (33) Newcomers from different parts of the world are found to smile more. Without a shared language, they often resort to smiling to get along with others. For them, smiling is a straightforward way to indicate that one is reliable and trustworthy.\n\n(34) As many psychologists now point out, this simple gesture is in fact far more complicated than it may appear.", "bank": ["Another crucial factor is a society's immigration diversity.", "Various factors have thus contributed to the phenomenon of smiling.", "For most of recorded human history, the open smile has been deeply unfashionable.", "A genuine smile indicates contentment, while a forced smile suggests underlying distress.", "In fact, there is a well-known Russian proverb that goes, \"Smiling with no reason is a sign of stupidity.\""]}, {"pid": "115-P5", "year": 115, "type": "閱讀測驗", "text": "In March 2022, the Endurance—the lost vessel of the famed polar explorer Ernest Shackleton—was found in Antarctica, 107 years after it sank. The news made headlines around the world, not only for the incredible achievement of the search team, but because the discovery marked the final chapter in a legendary story of extraordinary courage and perseverance.\n\nOn August 4, 1914, Sir Ernest Shackleton, along with a skilled crew of 27, set sail on the Endurance toward the South Pole, hoping to make the first land crossing over Antarctica. From Plymouth, UK, the team arrived in Buenos Aires, Argentina, and on November 5 reached South Georgia Island, the last settlement of civilization en route to Antarctica. There, the real challenge began. Two days after leaving South Georgia in December, the Endurance encountered floating ice, and was soon completely trapped in pack ice.\n\nThe worthy vessel held up for nine months, drifting down south slowly and then pushed northward by the ice. Gradually, the pressure from the ice buckled the planks. Freezing water rushed in and exacerbated the situation. On October 27, 1915, Shackleton ordered his crew to abandon the ship, pitching tents on the ice a mile and a half away. Weeks later, they watched the Endurance sink beneath the Weddell Sea.\n\nThe next five months, the crew camped out on the pack ice as it drifted north, surviving on penguins, seals, and seaweed. Finally, the ice broke up enough for them to escape in lifeboats. For seven days, they sailed more than a hundred miles to the uninhabited Elephant Island. But the crew couldn't survive long there. So, Shackleton made a dangerous attempt to get help: With five crew members, he sailed 800 miles over 16 days across freezing, stormy seas to South Georgia Island. Then the group hiked for 36 hours across the island to reach a whaling station.\n\nHelp was almost at hand, but ice and bad weather hindered their return. On August 30, 1916, Shackleton finally got back to Elephant Island with a ship big enough to rescue the rest of his men. All the members of the expedition team survived, but the Endurance remained lost under the sea until its discovery in 2022.", "bank": null}, {"pid": "115-P6", "year": 115, "type": "閱讀測驗", "text": "In many old castles in Europe, visitors often find a fantastic spiral staircase, which provides a captivating focal point as it winds up the building. This prominent structure actually has a long and rich heritage.\n\nIn the Old Testament, reference is made to spiral staircases in the Temple of Solomon, suggesting that they were already in use by around 1,000 BC. The oldest spiral staircase still standing today is at Trajan's Column in Rome. The staircase was built in 113 AD, with a total of 185 steps carved in stone and marble. Around this time, spiral staircases began to find much wider use in Roman architecture and across Europe.\n\nThroughout the Middle Ages, winding staircases became a well-established feature of European castles, mainly for their advantages in helping to defend against attackers. To begin with, these staircases were quite narrow, so attackers would have to ascend one at a time, making it impossible to launch a mass attack. Also, the stairs were designed to turn clockwise upwards. This means that ascenders would have their right hand tight against the narrowest part of the staircases, close to the central pole, and as a result were unable to use their sword effectively. The attackers' challenge was further complicated by the uneven steps of the staircase, often strategically designed by the castle owners. The defenders, living in the castles, were familiar with the stair pattern and could retreat up them very swiftly; while the attackers were much more likely to stumble and fall, particularly in the dimly lit confines of the staircase.\n\nBeing associated with medieval castles and kings, spiral staircases gradually won popularity in European architecture, with new materials emerging to cope with customers' needs. In Victorian times, cast iron spiral staircases were popular for public buildings and homes for the rich. In the latter half of the 20th century, steel frames became cost-effective, and thus affordable for a much wider staircase market. Then, steel spiral staircases as fire escape stairs appeared in many buildings. Today, spiral staircases come in a wide variety of materials: steel, wood, concrete, and recently even glass. The timeless appeal of their classical design makes spiral staircases a much-desired feature in luxury homes, offices, and public buildings nowadays.", "bank": null}, {"pid": "115-P7", "year": 115, "type": "閱讀測驗", "text": "Have you ever wondered why north comes at the top of a map? Well, north may seem a natural choice for the top spot today, but that wasn't always the case.\n\nDocuments from ancient times indicate that many maps in early ages were pointing to the east, where the sun rose. In ancient India, for example, maps were most likely oriented to the east. Though there is no physical evidence to support this, the word dakshina \"south\" in Indian languages also means \"right,\" suggesting that ancient Indians were oriented toward the east, and therefore south was on their right-hand side. Ample evidences from the Old Testament also suggest that east was at the top of maps in pre-Biblical and Biblical eras, a reason why east is still referred to as the \"Orient\" today.\n\nIn the oldest surviving maps, south is at the top, and north points down. Early Egyptian maps showed south on top, most likely because the Nile, vital to Egyptian livelihood, originated in the south. As rivers were believed to flow downward, \"up\" was therefore south. Map makers in Arabia also drew maps with south on top since the earliest Muslims lived north of Mecca, and a south-oriented map would show the followers looking up toward their holy city.\n\nThe preference for north arose during the European age of exploration. At the time, sailors relied on the North Star to find their way across the Mediterranean and later the Atlantic. By the 16th century, when Europe's search for trading routes was at its peak, maps became Eurocentric, with north on top. The expansion of European imperialism in the following centuries further established the \"north up\" practice as the standard.\n\nToday, map orientation is taking on a new perspective. In perhaps our most common interaction with maps—the use of GPS systems on our phones and in our cars, directions have ceased to be as important. The layouts are dynamic, oriented toward our travel path.\n\nSo, perhaps the north-on-top practice is less a rule and more a blip. After centuries of technological advancements, it seems we've ended up right where we began in ancient times: with ourselves in the middle, and our destinations at the top.", "bank": null}, {"pid": "115-P8", "year": 115, "type": "閱讀測驗", "text": "Located along the sparkling coastline of the Pacific Ocean, Wonder Village is a famous indigenous district in eastern Taiwan. The historic village exhibits the traditional way of life of the tribe there. However, it does not live in the past. As numerous new restaurants and shops have sprung up in recent years, it has become not only a cultural center but also a unique commercial zone. The following six shops are examples of some of the specialty stores there.\n\nA. Oh Eco\nGreatly concerned about the presence of fake \"green\" products on the market, Alice Bao decided to open this shop. She sells environmentally friendly items such as reusable bottles, bamboo toothbrushes, and soy candles. \"Here everyone looks out for each other and the neighborhood,\" she says. \"There's a sense of community in the area.\"\n\nB. After Work\nNeighborhood beer lovers rejoiced when After Work moved in last summer. \"We knew we were coming into a really cool neighborhood,\" says co-owner Joey Ma. Aside from handcrafted beer, the menu boasts hand-made gourmet pizzas such as the Yummy Duck n' Cheese, loaded with roast duck and, yes, creamy delicious cheese. A truly unique blend!\n\nC. Aroma Paradise\nThe fragrances at this scent shop are largely customized to meet the individual shopper's taste. Owner Joseph Tang says he knew the idea would work well in this unique district: \"Each store is one of a kind in Wonder Village,\" he states. \"Aroma Paradise wants to create a paradise for those who are looking for fragrance made for their special preferences.\"\n\nD. Something Different\nLooking for something unique? Yes, at this tiny antique store you can always find, as promised, something different. Open since 1996, the store features traditional-style home accessories, ranging from cabinets and chairs to picture frames and decorative mirrors.\n\nE. Beyond World\nOwner Foting Mayaw opened this boutique in what he calls \"the most fascinating area in Taiwan.\" The shop focuses on selling various \"good goods\" that showcase the skill and spirit of neighborhood artisans. From fashion items to rice snacks, it carries products only from local makers and small businesses owned by indigenous people.\n\nF. The Pinery\nThis restaurant got its name from the pineapple farms that once populated the area. Indeed, the fruit appears in some innovative menu items (e.g., pineapple jam on the burger). \"Wonder Village is much more than just a tourist destination,\" says owner Carol Hon. \"It is a place where the old meets the new: diverse, unique, and always full of surprises.\"", "bank": null}, {"pid": "114-P1", "year": 114, "type": "綜合測驗", "text": "In 1995, a group of business and academic leaders met at the home of Juanita Brown and David Isaacs in Mill Valley, California. None of them had any idea they were about to create a social innovation that (11) rapidly around the world.\n\nThe group was supposed to have a large-circle discussion in their beautiful garden. Unfortunately, it started pouring. With their plan (12) by the rain, the two dozen participants squeezed into the living room. They broke into small, intimate table conversations, recording their insights on paper tablecloths. They periodically stopped their conversations to switch tables so the insights and ideas might (13) and deepen. As they moved from one table to another, they noticed new ideas emerging from the discussions. This in turn enriched subsequent rounds of conversation. Over the course of the morning, the innovative discussion process (14) a new form of collective effort that transformed the depth, scope, and quality of their discussion.\n\nThe World Café was (15) created. Since that rainy morning in Mill Valley, the World Café approach has been applied to multi-group discussions and cooperative actions by businesses, industries, and educational institutions around the world.", "bank": null}, {"pid": "114-P2", "year": 114, "type": "綜合測驗", "text": "If you have ever been sick to your stomach on a rocking boat or a bumpy car ride, you know the discomfort of motion sickness. It can (16) suddenly, progressing from a feeling of uneasiness to a cold sweat. Soon, it can lead to dizziness, nausea, and vomiting.\n\nMotion sickness occurs when the signals your brain receives from your eyes, ears, and body (17). Your brain doesn't know whether you are stationary or moving when these parts send conflicting information: One part of your balance-sensing system detects that your body is moving, but the other parts (18). Your brain's confused reaction makes you feel sick. You may experience the discomfort from the motion of cars, boats, or amusement park rides. You may also get sick from playing video games, or looking through a microscope.\n\nYou can take some (19) to help avoid the discomfort. If you are traveling, reserve seats where motion is felt the least, such as the front row of a car or forward cars of a train. Looking out into the distance from the vehicle can help (20). You can also take medicine before your ride to avoid or reduce nausea and vomiting.", "bank": null}, {"pid": "114-P3", "year": 114, "type": "文意選填", "text": "The Notre-Dame de Paris is one of the most famous cathedrals in Europe. Located at the heart of Paris, this medieval cathedral is (21) for its intricate architecture, stunning stained glass windows, and, above all, its bells.\n\nMounted in the two tall towers of the cathedral, Notre-Dame's bells have been ringing for over 800 years. In fact, there is documented (22) to the ringing of bells even before the cathedral's construction was completed, dating as far back as the 12th century. The 10 bells vary in size, each (23) a name. The largest one, named \"Emmanuel,\" weighs over 13 tons. It is the only one of the whole group that (24) the French Revolution, while the rest were melted down for weapons. The melted bells were recast in the late 19th century. But due to their poor acoustic quality, all of the bells were replaced in 2013—except for Emmanuel, which (25) its renowned, excellent sound. This particular bell, ringing in F sharp, is considered one of the most harmonically beautiful in Europe.\n\nOver centuries, the bells have become a (26) part of life in Paris, where they are known as \"the cathedral's voice.\" They have been used to mark the hours of the day, to call the (27) to prayer, and to signal emergency situations such as fires and invasions. They have also rung in times of (28) and of mourning, announcing such events as royal weddings and coronations of kings, as well as funerals of heads of state.\n\nHowever, after the devastating fire that damaged the cathedral in 2019, the bells fell (29). The building went through a complex and time-consuming process of (30), and the famous monument was finally reopened on December 8, 2024. The sounds of Notre-Dame bells once again filled the air in Paris, and will be heard for generations to come.", "bank": ["reference", "bearing", "familiar", "retained", "faithful", "survived", "celebration", "restoration", "noted", "silent"]}, {"pid": "114-P4", "year": 114, "type": "篇章結構", "text": "A capsule hotel, also known as a pod hotel, is a unique type of basic, affordable accommodation. Originated in Japan, these hotels were initially meant for business professionals to stay close to populated business districts without spending a lot. (31)\n\nA typical room of a capsule hotel is roughly the length and width of a single bed, with sufficient height for a guest to crawl in and sit up on the bed. The walls of each capsule may be made of wood, metal or any rigid material, but are often fiberglass or plastic. (32) Each capsule is equipped with a comfortable mattress, a small light, and sometimes a television or other entertainment options. Such minimalist design is what makes these hotels both inexpensive and efficient, providing only the essential elements for a good night sleep.\n\nThe first capsule hotel, the Capsule Inn Osaka, opened in 1979. Since then, capsule hotels have quickly spread to other cities and countries. Chains have emerged in Taiwan, Singapore, and even on resort islands like Bali. Pod hotels are also seen in Europe and North America, especially in big cities like New York, London, and Paris. (33) Instead of the traditional bare pod-sized style, new chains now feature interior design that appeals to digitally connected travelers from around the world. Guests may enjoy facilities such as free Wi-Fi, mobile charging, and even a soundless alarm system that raises the sleeping guests into a seated position while gradually brightening the lights.\n\nWhile offering budget-conscious travelers a unique option, capsule hotels may not be suitable for everyone. Some hotels may not provide air conditioning in the capsules, leading to poor air flow. (34) Also, you may have to share common facilities (such as bathrooms) with other guests. And, if you're worried about feeling claustrophobic in small spaces, you'd better think twice before making a reservation.", "bank": ["In response to rising demands, these hotels are embracing a wave of innovation.", "The room's thin plastic walls easily transmit the sound of snoring made by neighboring guests.", "The chambers are stacked side-by-side, two units high, with the upper rooms reached by a ladder.", "Today, they provide low-budget, overnight lodging in commerce centers in large cities worldwide."]}, {"pid": "114-P5", "year": 114, "type": "閱讀測驗", "text": "While waiting to cross the street at busy intersections, have you ever wondered who invented the traffic light? Most people credit the first traffic light to Nottingham engineer John Peake Knight. A railway manager, Knight specialized in designing the signaling system for Britain's growing railway network in the 1860s. He saw no reason why this could not be adapted for use on the busy London intersections. Thus, he proposed a signaling system based on the railway movable-arm signal: Arms extending horizontally commanded drivers to stop, whereas arms lowered to a 45-degree angle told drivers to move on, resembling a traffic director's gestures. Red and green gas lamps were added to the signal for use at night. A police officer was stationed by the side to operate the system.\n\nKnight's traffic signal was installed near London's Westminster Bridge in December 1868, but the system was short-lived. A gas leak one month later caused an explosion in the lights, injuring the policeman operating it. Deemed a public hazard, the project was immediately dropped, and traffic lights were banned until their return in 1929 back to the British streets.\n\nIn the early 1900s, versions of the British traffic lights appeared in big cities in America, where traffic was on a sharp rise. Systems using movable arms were popular in Chicago, while those using the red and green lights were adopted in San Francisco. Patents with innovations on Knight's ideas were filed nationwide. A major breakthrough was the yellow light invented by a Detroit police officer William Potts. Installed in Detroit in 1920, Potts' three-color system allowed for the added signal \"proceed with caution\" to be displayed.\n\nNow, with the emergence of self-driving cars, researchers have begun to suggest that traffic signals are no longer necessary. Intersections will operate in a way that cars automatically adjust their speed to cross through, while maintaining safe distances from other vehicles. In the near future, we may experience a brand new form of traffic management!", "bank": null}, {"pid": "114-P6", "year": 114, "type": "閱讀測驗", "text": "Typically featuring zombies and serial killers, horror movies are too frightening to be fun for some people. But many others enjoy a good fear spectacle, and line up to see the latest scary movie. Given the variations in preferences, new studies have started to untangle the benefits and risks of horror movies.\n\nOne benefit of horror movies revolves around the concept of so-called \"safe fear.\" When watching a frightening film, people are in the comfort of their own home or theater seats rather than under the threat of any real danger. In a controlled environment, these films may actually reduce the negative impact on viewers and help them become tougher. Secondly, as people are drawn into the story, they tend to take the perspective of the characters and rehearse the plot unconsciously. Researchers believe that viewers are learning vicariously this way, picking up tips on how to handle threats in the real world. In addition, studies show that the thrill and excitement linked with scary films can be therapeutic: It allows viewers to release bottled-up emotions and experience a sense of relief after the movie is over. This probably explains why during the COVID-19 pandemic, horror and pandemic thrillers were the most-watched movies on digital movie apps.\n\nHowever, researchers also find that horror movies can have negative effects on some people. People who are more sensitive to anxiety can panic after viewing a thriller. For those with unpleasant experiences, trauma may be triggered by the themes and images in the movies, which could make their symptoms worse. Furthermore, watching horror movies can disturb sleep patterns, as the residual fear and anxiety they evoke may keep people awake all night, thus leading to fatigue and irritability the following day. Finally, specialists warn that frightening films can have a negative impact on children. Children under 14 who watch horror movies have a greater chance of developing anxiety later in adulthood. Worse yet, exposure to graphic violence and bloodshed can make them less sensitive to real-life violence and more accepting of aggression.", "bank": null}, {"pid": "114-P7", "year": 114, "type": "閱讀測驗", "text": "Russia is widely portrayed as the most alcohol-dependent country in the world. Critics of the country say that drinking is almost an inherent trait of the Russian people. However, there is more to the story.\n\nThe consumption of alcoholic beverages was unusual in ancient Russia. Before the adoption of Christianity in Russia (10th century), there were no vineyards and therefore no wine. People only drank beverages with low alcohol content. Vodka, Russia's national drink, was not a Russian invention. The liquid was originally a grape alcohol introduced from France in the late 14th century. The first Russian-made vodka appeared in the 15th century, and the drink remained relatively low in alcohol content until the mid-18th century.\n\nThere is contradictory information about Russians' inclination toward alcohol in the 15th and 16th centuries. Some documents noted that Russians \"indulge in excessive drinking whenever the occasion arises,\" while others claimed that Russians \"rarely drink wine.\" The heaviest drinkers in medieval Europe were actually Germans. There were many sayings about their desire for alcohol, such as \"drunk as a German.\"\n\nThe Russian state played a significant role in the spread of alcohol consumption in the country. In the 19th century, the emperors began to establish a state monopoly, largely due to the rise of illegal production of low-quality vodka. Thus, only the government was permitted to produce the alcohol. This soon filled the state treasury with huge revenues, but it also encouraged vodka consumption. The situation worsened when the industrial production of vodka began in the country, causing its prices to drop sharply and making it available to even low-income citizens.\n\nMeanwhile, a powerful anti-alcohol movement started in the 19th century. Government policies were made and public organizations established to prevent the spread of alcoholism in the country. The movement continued over the years; however, the problem remains. Although Russia does not occupy first place when it comes to alcohol consumption per capita, it is still close to the top.", "bank": null}, {"pid": "114-P8", "year": 114, "type": "閱讀測驗", "text": "A zoo is a place where animals in captivity are put on display for humans to see. While early zoos put emphasis on displaying as many unusual creatures as possible, most modern zoos now focus on conservation and education. Still, many animal rights activists believe the cost of confining animals outweighs the benefits. What are your opinions? Feel free to share your ideas on this forum.\n\nA. Amy: Personally I'm against zoos, though I do understand some of the arguments why they should exist. I don't agree with caging animals for our entertainment.\nB. Ben: What gives humans the right to capture, confine, or breed other species? Even if an animal is endangered, does that justify restricting its freedom?\nC. Cathy: Zoos are a tradition, and a visit to a zoo is a wholesome family activity. Wildlife encounters are unforgettable experiences for children and adults alike.\nD. Daniel: To me, a zoo can be a good place for endangered species which have difficulty finding suitable mates in the wild.\nE. Eddie: My childhood memory of a polar bear pacing back and forth in a very small space in a zoo keeps haunting me. Is it a good idea to keep animals in sites not suited to them?\nF. Frank: Well, if zoos are an inevitability, zoo keepers must provide the best possible conditions for the animals that live in captivity—to say the least!\nG. George: Zoos have an educational aspect to it. It's easier to learn about an animal by seeing them in person.\nH. Henry: Most animals in zoos are not endangered, nor are they being prepared for release into natural habitats. In fact, it is nearly impossible to release captive-bred animals.\nI. Irene: Fostering empathy…By seeing an animal up close, the public could be encouraged to be more sensitive and compassionate to a species that is facing extinction in the wild.\nJ. Jack: In making a case for or against zoos, both sides argue that they're saving animals. Whether or not zoos benefit the animal community, they certainly do make money. Like it or not, zoos will continue to exist as long as there is a demand for them.", "bank": null}, {"pid": "113-P1", "year": 113, "type": "綜合測驗", "text": "Mystery shoppers are paid consumers who are hired to shop in stores and collect data. They are sent to a wide variety of service-based businesses, including stores, restaurants, and banks—potentially anywhere customers are served. Sometimes referred to as secret shoppers, mystery shoppers (11) regular customers to purchase items, eat in restaurants, make inquiries, or return items. They grade and report on the quality of products, customer service, and environment of the stores (12) they are assigned.\n\nWhen evaluating a business, mystery shoppers have to follow certain standard procedures to avoid (13). They are often given a checklist that provides directions on what to observe or look out for to ensure consistency. Sometimes these shoppers collect data about their \"normal\" observations, such as cleanliness of the store or timeliness of the service. They may also pretend to be (14) customers, arguing with a salesperson without a good reason. With the data they collect, mystery shoppers can identify areas for (15) and thereby help enhance the quality of products and services. In this way, these secret shoppers may help a business gain a competitive edge.", "bank": null}, {"pid": "113-P2", "year": 113, "type": "綜合測驗", "text": "The modern worker rolls out of bed, groans, and turns off an alarm clock before reluctantly getting up for the day's work. But how did people get to work on time before alarm clocks were widely used?\n\nDuring the second Industrial Age, people toiled at unusual hours in mines or factories and often had to get up for work early in the morning. They (16) alarm clocks because adjustable alarms had been invented by the mid-19th century. But the new device was still relatively expensive and unreliable. British workers thus relied on a human alarm clock known as a \"knocker-up.\" (17) sticks or pea shooters, the human alarms would tour the streets, tap on windows, or blast them with dried peas, trying to wake paying customers in time for work.\n\nWhether they wielded rods or pea shooters, knockers-up became (18) throughout the United Kingdom. Every morning, these people, often older in age, were seen in big streets and small alleys, waking up their customers professionally. They usually would not leave people's houses until they were sure their customers were awake.\n\nWhile the practice continued in some parts of the country until the 1970s, it (19) as alarm clocks became more widespread and affordable. Today, beeping alarm clocks and smartphones that play morning music are surely simpler and more convenient. However, they cannot (20) the personal attention coming from the distinctive tap of a pea shooter.", "bank": null}, {"pid": "113-P3", "year": 113, "type": "文意選填", "text": "On a hilltop overlooking the 2011-tsunami hit Otsuchi Town in northeastern Japan, there is a white phone booth standing all alone in the wind. The lonely \"wind phone\" serves to connect family members to their (21) loved ones who died in the tsunami that claimed 18,000 lives. People come to speak to those they have lost, to say the words they never got to say on that (22) day.\n\nThe idea for the wind phone was first (23) by a Japanese garden designer named Itaru Sasaki, who was grieving over the death of his cousin in 2010, before the tsunami. Feeling that he needed a private space to help him navigate through the (24), Sasaki positioned a booth where he could \"speak\" to the dead relative. The booth he built (25) only an old dial phone with a disconnected phone line. When he stepped into the booth, he could pick up the phone to call his cousin, telling him how he was, and how he missed him. Sasaki stated in an interview: \"Because my thoughts couldn't be (26) through a regular phone line, I wanted them to be carried on the wind.\" Hence, the wind phone allows Sasaki to create a one-way conversation with deep, soulful personal meaning, and renders the grieving process more (27) for him.\n\nSasaki opened his wind phone to the public in 2011, after the devastating tsunami. News about the phone gradually spread, and the booth has become a (28) between the living and the dead. Phones resembling the wind phone have since been built around the world. Some were even set up to allow people to call their loved ones lost in the COVID-19 pandemic.\n\nGrieving is a natural (29) for coping with loss of a loved one, and people grieve in various ways. For those who speak into the wind phone, (30) is always there: They believe that their messages will—through some unknown way—reach the deceased.", "bank": ["passed on", "bridge", "sorrow", "hope", "departed", "mechanism", "housed", "manageable", "fateful", "brought forth"]}, {"pid": "113-P4", "year": 113, "type": "篇章結構", "text": "While Dr. Weinstein, a surgeon at Dartmouth College, was trying to lift a heavy box, he twisted his back. The pain was agonizing. The surgeon could not sit, and when he lay down he could barely get up. So he decided to go out for a run. He took an aspirin, iced the injured area, and off he went. When he returned, he felt \"pretty good.\"\n\n(31) When people have sprained a muscle or tendon, they are usually advised not to go right back to exercising until the pain goes away. But Dr. Weinstein says that approach is outdated and counterproductive. In fact, when active people consult him, he usually tells them to just keep exercising.\n\nDr. Weinstein is not alone in his treatment of sports injury, but the specific advice can differ from specialist to specialist. (32) They nevertheless caution that a cutback may be necessary, such as running shorter distances or going more slowly. Others say the patients may need to engage in sports outside of their usual, main sport (that is, to cross-train), at least some of the time. Still others say the safest thing to do is cross-train all the time until the pain is gone. (33) Their consensus, however, is that unless the injury involves something as serious as a broken bone or a ripped muscle, moderate exercise can actually speed healing.\n\n(34) Thus, more and more patients are now advised to keep moving despite the pain. The rule of thumb, however, is to see a doctor first and get an accurate diagnosis. If a serious injury is ruled out and the pain is not getting worse after exercising, then the exercise \"makes a lot of sense.\"", "bank": ["For example, an injured runner might end up cycling and swimming instead of running.", "Over time, researchers have come to realize the importance of exercising when injured.", "Many suggest that most patients can continue with the sport they love.", "This seems to run counter to the common practice."]}, {"pid": "113-P5", "year": 113, "type": "閱讀測驗", "text": "One fine morning in 1941, Swiss engineer George de Mestral went for a walk in the woods with his dog. Upon their return home, he found a lot of burrs (from plants) stuck to the dog's fur and his pants. He immediately rushed to his microscope and examined the burrs attached on his pants—feeling a lightbulb moment coming on.\n\nUpon closer examination, de Mestral observed that the burrs, which appeared straight to the naked eye, actually contained many small hooks that clung firmly to the loops in the fabric of his pants. He determined that if he could recreate the same thing, making hooks-and-loops that bind to each other firmly, he could produce a strong fastener with many uses.\n\nDe Mestral's first challenge was finding a fabric for a strong bonding system. He first tried cotton, but it proved too soft and could not withstand repeated openings and closures. After years of research and testing, he learned that synthetics worked best and eventually settled on heat-treated nylon, a strong and durable substance. By 1955, he had completed an improved version of the product, with each square inch of material containing 300 hooks, which made it stay fastened and yet easy enough to pull apart when needed. Named \"Velcro,\" from the French words velours (velvet) and crochet (hook), the new product received a patent from the Swiss government in 1955. De Mestral thus began mass-producing Velcro, opening plants in Europe and eventually into Canada and the United States.\n\nInitially Velcro did not fare well. As most fashion critics considered it ugly and cheap-looking, the use of Velcro was limited to athletic equipment. In the early 1960s, the product received a huge boost in popularity when NASA began using it in a lot of equipment that went into space along with astronauts. Today, de Mestral's design is found almost everywhere: clothing and footwear, toys, airline seat cushions, blood pressure cuffs and surgeons' gowns. Most impressively, the magical fastener was used in the first human artificial heart transplantation to hold together parts of the device.", "bank": null}, {"pid": "113-P6", "year": 113, "type": "閱讀測驗", "text": "Thomas Moran, a famous painter in the 19th century, played an important role in the establishment of American national parks. His vivid paintings brought the splendor of the extraordinary landscapes before the eyes of American people, thus setting the stage for the regions to be widely recognized and officially established as national parks.\n\nMoran came to the United States at age 7 with his family and settled in Philadelphia. They came from northwest England, the blackened heart of the Industrial Revolution: Its main street was \"a dark, unattractive hole\" and the river running through it was a string of dirty water. That was all the nature that Moran knew. Moran began painting by age 15, inspired by the landscape paintings of the British master J.M.W. Turner. There was plenty of landscape for him to paint in America, much different from his hometown. Showing great talent in painting, Moran was soon hired as an illustrator at Scribner's Monthly, and later appointed chief illustrator by age 34. In 1871, he was appointed to illustrate The Wonders of Yellowstone, a story by Nathaniel P. Langford, who had participated in an expedition to Yellowstone. Captivated by the utterly fantastic sights Langford described, Moran became eager to see this odd territory for himself.\n\nIn 1871 Moran joined the first US government survey of the Yellowstone region with photographer William Henry Jackson. For two weeks he filled his sketchbook with the landscape's most stunning sights. Moran's watercolors—the first color renderings of the area—as well as Jackson's photos and the survey results were presented to the Congress. His powerful images of Yellowstone fired the imagination of Congress members. In March 1872, lawmakers officially made Yellowstone a national park, the world's first.\n\nBefore Moran arrived, Yellowstone in the popular imagination was a harsh, wild place with hot water and steam coming out of hellish holes in the ground. Since the painter's work appeared, Yellowstone National Park has come to be known as a picturesque wonderland. By the time Moran died, he had painted a dozen other areas that would become national parks or monuments.", "bank": null}, {"pid": "113-P7", "year": 113, "type": "閱讀測驗", "text": "In 2020, Petur Oddsson, a power station worker in Iceland, was struck by a 60,000-volt current. The electrical shock burned almost half of his body and melted layers of his skin off. Such deep and extensive burns can be fatal. But Oddsson's life was saved by a creative invention: transplanting codfish skins onto human bodies.\n\nA triumph for medical technology, Oddsson's fish skin transplantation was actually part of the astonishing achievement of \"100% Fish,\" an ambitious task in promoting environmental efficiency. The Icelandic project, from which this pioneering procedure emerged, strives for making a fundamental change in the marine industry. It aims to encourage full utilization of each fish caught, and to strengthen innovation in seafood products.\n\nReducing waste of fish catch has become a serious issue today, when many countries are faced with food crises. According to a 2003 study, about 60% of a codfish caught in Iceland was lost or wasted during the production process for human consumption. Under the guidance of 100% Fish, however, Icelanders are now using almost 95% of a cod. Cod skin, for example, is made into calcium supplement and energy drinks, and even as material for skin transplantation as in Oddsson's case. Dried fish heads and spines are exported to West Africa, where they are used as the base of a protein-rich soup. Other groundbreaking products, including Omega-3 capsules, cold virus pretreatment sprays, and dog snacks are made from what was once cod catch detritus.\n\nThe Icelandic success is accomplished largely through cooperative efforts across various industries. 100% Fish takes the initiative to show seafood companies the importance of collaboration, and facilitate valuable connections between fishing companies and other participants of the project, including academia, start-ups, and research and development teams. By sharing knowledge and information, the different sectors are able to come up with improved processing and handling, through which creation of various innovative products was made possible. The project not only helps Icelanders to get 30% more value from each cod than most developed countries, but also provides an effective model to promote resource efficiency worldwide.", "bank": null}, {"pid": "113-P8", "year": 113, "type": "閱讀測驗", "text": "Many animals are known to live and move in groups to secure food and avoid predators. Over the years, people have been curious about the way they deal with disturbances arising from the environment, and the operations underlying their responses as a group. Studies on jackdaws and turtle ants may provide some insights into the issue.\n\nJackdaws are birds in the crow family often found in the English countryside. They are highly social birds and often travel in large flocks. Normally, the birds enjoy a smooth flight together as a group when \"commuting\" between two locations, such as from their nesting site to their feeding ground. However, if a predator (such as a fox) is present, the pattern of their flight will change immediately. Instead of paying attention to all the other members and following the group pattern, they now focus only on the birds within a fixed distance from them, based on information coming from other members. By doing so, the flock members are able to keep a safe distance between themselves, and thus avoid crashing into each other while they flee from the predator.\n\nTurtle ants often live in the cavities of dead branches in American forests. They have evolved search strategies to link their food source to their nests. They travel entirely along tree branches and vines, laying down trails of pheromone (a chemical substance) behind them so that other ants can follow. The trails connect the ants' colonies and sources of food, forming a sort of communication network. However, since these trails can easily be broken by wind or rain, the ants have to find new paths to get around the broken points and reestablish the network. Often they have to work together to explore alternative routes many times before they finally settle on the most efficient one. By working collectively, the ants are able to improve the efficiency of their network and adapt to their ever-changing environment.", "bank": null}, {"pid": "112-P1", "year": 112, "type": "綜合測驗", "text": "In certain forests, when you look up you will see a network of cracks formed by gaps between the outermost edges of tree branches. It looks like a precisely engineered jigsaw puzzle, each branch growing just perfectly so it almost, (11), touches the neighboring tree. This beautiful phenomenon is called crown shyness.\n\nScientists have been discussing crown shyness since the 1920s, proposing (12) explanations for the phenomenon. Some researchers point out that as trees often grow close together, treetops can easily collide and break when swayed by the wind. In order to protect their branches from breakage, trees maintain \"shyness gaps\"—spaces large enough to prevent them from touching their neighbors.\n\nOther scientists suggest that plants, like animals, (13) resources—nutrients, water, space, and light. In forested areas with thick tree crowns, there is intense struggle for these resources. Gaps in the treetops resulting from crown shyness may allow trees to increase their (14) light and enhance photosynthesis. Additionally, by having branches that do not touch those of their neighbors, trees may be able to limit the spread of leaf-eating insects, and potentially also the transmission of diseases from tree to tree. (15) decades of investigation, there is no consensus on exactly what causes the beautiful and mysterious phenomenon of crown shyness.", "bank": null}, {"pid": "112-P2", "year": 112, "type": "綜合測驗", "text": "Gravity has been at the top of the science agenda since the start of Mars missions. In the earlier days of space travel, scientists tried to overcome the force of gravity so that a rocket could shoot (16) Earth's pull in order to land humans on the moon. Today, they are more interested in how reduced gravity affects the astronauts' (17) condition.\n\nOur bodies have evolved to exist within Earth's gravity (1 g), not in the weightlessness of space (0 g) or the microgravity of Mars (0.3 g). When on Earth, we have more fluids in our lower body because they are pulled down by Earth's gravity. However, with the absence of gravity in the outer space, our body fluids (18), shifting toward the upper body and the head. As a result, the astronauts have swollen, puffy faces, very much resembling that of the round-headed Charlie Brown in the famous comic strip. This \"Charlie Brown effect\" will be more (19) when the astronauts go on their Mars missions, which will take about three years to complete, much longer than missions to the moon. Moreover, the effect is often (20) space motion sickness, headaches, and nausea. Such a syndrome is considered the top health risk for the astronauts, and scientists are still trying to figure out how it may be prevented.", "bank": null}, {"pid": "112-P3", "year": 112, "type": "文意選填", "text": "Water makes up more than half of our body weight. To sustain this amount of fluid in our bodies, plain water is considered our best choice, for it contains no sugar and no calories. Yet, is water always the healthiest drink we can (21)? Well, it depends on who and where we are, and what we're doing.\n\nObviously, a physically (22) person with an outdoor job under the sun will need to drink more fluid than a desk-bound person who lives and works in an air-conditioned place. But there's more to it than that. When a person sweats, he loses water and salt, so he needs to replace both. Replacing lost fluid with just plain water means the body has too much water and not enough salt. To (23) things out, the body will get rid of water by producing urine. For this reason, milk can actually be more (24) than drinking water. Milk naturally contains salt and lactose, a sugar which the human body needs in small amounts to help stimulate water (25). Coconut water, which contains salt and carbohydrates, is also more functional than water at restoring and maintaining a normal fluid (26) after exercise.\n\nFor the average person, however, water remains a very good (27) for keeping hydrated—if you know how to drink it. The secret is: Never wait until the body is telling you you're thirsty, since there must already have been significant changes in your body for it to eventually (28) your consciousness. At that point, it might be well past the best moment to take in fluid. Also, drinking a lot of liquid in one go can cause more water to (29) the body quickly and come out as urine. To (30) this, you need to drink water throughout the day to maintain your hydration levels.", "bank": ["absorption", "active", "alert", "combat", "option", "effective", "even", "status", "pass through", "reach for"]}, {"pid": "112-P4", "year": 112, "type": "篇章結構", "text": "Have you ever thought of \"coloring\" the names of the days of the week? When you listen to someone speaking, do you see a rainbow of colors? Or perhaps Mozart's music tastes like an apple pie to you? If so, it is very likely that you have synesthesia.\n\nSynesthesia is a condition in which people's senses intermix. In some cases, people with synesthesia may experience colors when they hear, read, or even think of letters and numbers. In others, words can trigger a real sensation of taste on their tongue.\n\n(31) In the early 1990s, however, scientists noticed that synesthetic colors do not change over time. When asked what color is evoked by a letter or number, synesthetic people would persistently give the same answer even if tested months or years apart. (32) The most compelling support, however, comes from brain scans, which show that color processing areas in the brain light up when these people listen to certain words.\n\nIs synesthesia genetically inherited or acquired after birth? Scientists agree that synesthesia has a genetic basis, because it frequently runs in families. But an actual synesthesia gene (or genes) has not been identified yet. (33) For example, the flavors people with taste-word synesthesia experience are usually childhood flavors, such as chocolate or strawberries. Also, people with color-music synesthesia more often than not have had early musical training.\n\nOnce thought to be extremely rare, synesthesia is now found to affect about one to four percent of the population. (34) As is often observed, most of us tend to associate lower notes with darker colors and higher notes with brighter colors. Researchers further point out that in most people synesthesia is active only during the first months of their infancy, while this ability remains forever in certain individuals.", "bank": ["This consistency serves as a proof that synesthesia is real.", "Meanwhile, environmental influences seem to shape a person's synesthesia.", "People with synesthesia used to be accused of making their experiences up.", "Some studies even show that people may all be synesthetic to some degree."]}, {"pid": "112-P5", "year": 112, "type": "閱讀測驗", "text": "When did people first experience the joy of the hula hoop? Although the term did not emerge until the 18th century, toy hoops twirled around the waist, limbs, or neck can be traced back to ancient times. As early as 1000 BC, Egyptian children played with hoop toys of dried grapevine. They threw, jumped, and slung them around their bodies as we do today. They also struck them with sticks to roll them down the road. Hoop rolling was also popular in ancient Greece. Their hoops, often made of metal, were not merely toys for Greek children but served as exercise devices as well.\n\nIn the 14th century, hoops were popular as a form of recreation in Great Britain. The craze for hoops even resulted in dislocated backs and heart attacks, according to medical records. The term \"hula,\" however, did not enter the English language until the 1700s, when British sailors first witnessed hula dancing in the Hawaiian Islands. Though no hoops were used, the movements of the ritual dances looked very similar to those in hooping. Thus \"hula\" and \"hoop\" came together, resulting in the term \"hula hooping.\"\n\nHoops spun their way through the cultures of pre-colonial America as well. Often considered as representing the circle of life, hoops featured prominently in the ritual dances of Native Americans. Dancers used small reed hoops as symbolic representations of animals such as eagles or snakes. With very rapid movements, they used the hoops to construct the symbolic forms around their bodies.\n\nThe hula hoop gained international popularity in the late 1950s, when a plastic version was successfully marketed by California's Wham-O toy company. Twenty-five million plastic hoops were sold in less than four months. The hula hoop \"fad\" is still going strong today.", "bank": null}, {"pid": "112-P6", "year": 112, "type": "閱讀測驗", "text": "When you enjoy your morning cup of tea, you are probably not aware that those tea leaves can mean injury, or even death, for Asian elephants roaming Indian tea gardens.\n\nIn the Indian state of Assam, growing numbers of tea farms are destroying the Asian elephant's habitats and endangering their population. Much of the forest land where tea is grown in Assam is flat and thus farmers must dig drainage trenches to prevent water from accumulating and hurting the shrubs. The trenches, however, can be death traps for the elephants. Since the elephants need to use tea plantations as landmarks when navigating forests, they almost inevitably have to move through the farms. Moreover, because there are fewer humans around, pregnant females often use tea-growing areas as safe shelters to give birth. But baby elephants, not used to negotiating rough ground, may easily fall into the trenches and get hurt; and once injured, they might not be able to climb out. When mothers try to dig their babies out, both may be trapped and smothered by thick mud. Furthermore, elephants are known to resist leaving their sick or dying behind, and a herd may linger at a trench with a trapped baby for hours, reluctant to move on until all hope is lost.\n\nIs it possible for elephants to coexist with the prosperous tea business? Elephant Friendly Tea is an organization that takes the initiative to make it possible. The organization encourages consumers to choose brands that take precautions to protect elephants and has set up a certification program to reward tea growers who are doing it right. Until now, only smaller tea brands have been certified, but awareness is growing. The organization believes that people may be motivated to buy elephant-friendly brands when they know more about the risk tea can pose to these endangered animals.", "bank": null}, {"pid": "112-P7", "year": 112, "type": "閱讀測驗", "text": "Situated off the coast of Tanzania and washed by the warm, clean waters of the Indian Ocean, Zanzibar is a tropical archipelago comprised of several scattered islands. This popular beach destination is now famous for its white sand beaches, slender palms, and turquoise seas. But few people know that in the past, control of Zanzibar meant access to unimaginable wealth.\n\nFrom ancient times, Zanzibar has been a trading hotspot, thanks to its location on the trade route between Arabia and Africa. Traders from Asia had already visited the islands 900 years before the arrival of its first permanent settlers from the African mainland (around 1000 AD). In the 8th century, Persian merchants built settlements here, which grew over the next four centuries into their trading posts. Between the 12th and 15th centuries, trade increased between Arabia, Persia, and Zanzibar, bringing the archipelago both wealth and power.\n\nDuring the Age of Exploration, commerce in Zanzibar quickly boomed, largely due to the rise of the spice trade. At the close of the 15th century, Europeans' craze for spices gave rise to the Spice Route, a network of sea lanes joining Europe with the Far East, where most spices came from. In 1498, Portuguese explorer Vasco da Gama made the first sea voyage to India, via the southernmost tip of Africa. In 1499, he arrived at Zanzibar, an archipelago sitting at the crossroads of the Spice Route. The islands soon attracted traders from different lands. Hundreds of ships sailing the Spice Route docked here, bringing spices and goods for transaction, and Zanzibar became one of the biggest trading centers in the world.\n\nSince the 16th century, Zanzibar has come under the rule of the Portuguese, the Arabians, and then the British, each leaving a mark on the place. The paths of various religions also crossed here: Muslims have lived peacefully with Christians and Buddhists on the islands for centuries. The unique cultural intersections, scented with the aroma of cloves, vanilla, and cinnamon floating in the air, give these jewels on the Indian Ocean an amazing charm that goes far beyond tropical beach fun.", "bank": null}, {"pid": "112-P8", "year": 112, "type": "閱讀測驗", "text": "Even if you're not a vegetarian, there's a good chance you've heard of plant-based meat. These meat substitutes are often advertised as beneficial for the environment. But do the customers really like them? Read the following chatroom discussions about GreenBurger, a product using alternative-meat patties.\n\n(A) Olivia: That's a firm NO! I tried one when I was a prep cook for Next Level Burgers…tasted awful, just like mashed peas gone to rot.\n\n(B) Smith: I haven't tried them. I just don't see the point. They are heavily processed with more calories and sodium than meat and are more expensive too! Unless you are a strict vegetarian and eschew meat for ethical reasons, meat is surely a better deal.\n\n(C) Mika: Not really. It tastes too much like actual meat. If I wanted to eat a dead cow, I would go for real burgers. Being vegan means I try to stick to plant food. But this is just not something that will ever interest me.\n\n(D) Thomas: GreenBurger just tastes \"beany\" to me, so I think that whatever form it comes in, it works better in recipes that would usually contain beans, such as in a rice bowl (as ground meat substitute). That being said, I'm definitely a carnivore and prefer meat, but I don't see anything wrong with choosing one of the fakey-fakey meaty things once in a while—just for a change.\n\n(E) Rico: I finally tried one last week. It didn't taste that bad, but I was surprised to find it had 40 more calories than the meat version! Isn't it supposed to be a healthy choice?\n\n(F) Linda: I liked it fine. I did NOT like the price, though. Hopefully that will come down. I'm trying to eat less beef.\n\n(G) Ablo: Yes! My whole family does. We've been mostly vegan 90% of the time for the last 6 years and we cannot thank GreenBurger enough! Especially when a burger craving hits…a GreenBurger does the trick. I've tried all kinds of vegan \"burgers,\" and GreenBurgers are closer to what I'm looking for. In fact, I can have them every day—vegan or not!\n\n(H) Alexander: Well, they taste good if you add plenty of spices and sauces. Good for you? No, not at all. They're highly processed and contain no vegetables. They also contain a very large amount of processed coconut oil, which is even worse than lard. It's a killer for sure if eaten regularly. So why risk your life?", "bank": null}, {"pid": "111-P1", "year": 111, "type": "綜合測驗", "text": "A book town is a rural town in which second-hand and antiquarian bookshops are concentrated. The concept was (11) by Richard Booth, who opened the first second-hand bookshop in Hay-on-Wye, UK in 1961. Following him, many local people opened their own bookshops, and the small town soon became a model of sustainable rural development and tourism. Since the 1970s, book towns like Hay-on-Wye (12) up all over the world.\n\nAlthough all book towns have a great number of bookshops, that's where the similarities (13) . Each of these towns shows unique features of its own. Some have many small private shops, while others have organizations steered by volunteers. Some even run regular activities to attract visitors. For example, an annual book festival is held in Hay-on-Wye. Clunes, in Australia, holds a monthly book talk that hosts authors to discuss their latest (14) .\n\nAs digital reading is changing our traditional way of reading, book towns like Hay-on-Wye are particularly important to (15) . The feel of a book, the smell, the weight, and the knowledge that a particular book might be more than a hundred years old—all these highlight the importance of preserving the physical book as a complement to technology.", "bank": null}, {"pid": "111-P2", "year": 111, "type": "綜合測驗", "text": "Airline passengers may have noticed that all plane windows have rounded edges, instead of the hard corners commonly found in our house. The round windows are indeed pleasant to the eye, but they actually were designed for reasons (16) aesthetics.\n\nIn the early days of aviation, plane windows (17) square in shape. Then as commercial air travel became popular in the 1950s and airplanes began flying higher and faster, three planes mysteriously broke apart in midair. The cause? Square windows. Scientists found that sharp corners are natural weak spots where stress concentrates. The problem is (18) when airplanes fly at higher altitudes, where the difference between the inside and outside pressure increases, causing added stress. When subjected to repeated pressurization high in the sky, the four corners on a square window may (19) .\n\nCurved windows, on the other hand, distribute stress around more evenly, reducing the likelihood of cracks or breaks. Circular shapes are also stronger and resist deformation, and therefore can (20) extreme differences in pressure inside and outside of an aircraft.\n\nThus, round windows are a major safety innovation that keeps planes from disintegrating mid-flight. They are also used on ships and spacecraft for their greater structural integrity.", "bank": null}, {"pid": "111-P3", "year": 111, "type": "文意選填", "text": "A stunt person is a man or a woman who performs dangerous acts, usually in the television or movie industry. In this line of work, the person is paid to do daring actions that are deemed too (21) for the regular actor to perform, including jumping from heights, crashing cars, or fighting with weapons.\n\nStunt work emerged out of (22) over time. In the early days of the film industry, actors themselves shot acrobatic acts and dangerous scenes, until they began to get injured. There were, however, no (23) crew members to perform impressive stunts at that time. If something dangerous needed to be done for a scene, the producers would hire anyone crazy or desperate enough to do it. These people were not trained to perform stunts, so they often (24) things for the first time during the actual shooting. They had to learn from their own mistakes, which (25) some their lives, and almost all suffered light or severe injuries.\n\nBeginning around 1910, audiences developed a taste for serial action movies, which (26) the use of dedicated stunt people to perform in dangerous scenes. Such demand increased with the rise of western movies, and many cowboys with masterful skills on horseback found a new (27) as a stunt person. Tom Mix and Yakima Canutt were among the most famous. The 1960s and '70s (28) the development of most modern stunt technology, like air rams and bullet squibs. That technology has continued to evolve into the present.\n\nToday, CGI (computer generated imagery) is widely used in filmmaking, and it is now (29) to create very lifelike scenes without using real stunt people. However, CGI has difficulties of its own, and there will always be a demand for the realism and thrilling (30) of an actual stunt. So the stunt industry is probably in no immediate danger of dying off.", "bank": ["possible", "sensation", "risky", "cost", "witnessed", "professional", "called for", "tried out", "necessity", "career"]}, {"pid": "111-P4", "year": 111, "type": "篇章結構", "text": "Obon, or the Bon Festival, is a Japanese holiday that honors the spirits of the dead. (31) The festival usually lasts for four to five days in August. During this period, many people travel back to their hometowns and spend time with loved ones, both past and present.\n\nThough not a national holiday, Obon is surely one of the most traditional events of the year. Celebration often begins with mukaebi (welcoming fire), during which people make a small bonfire in front of their house to guide spirits upon their return back home. (32) Food offerings are presented at house altars and temples. Some regions prepare horses made of cucumbers and cows made of eggplants, hoping that the spirits will come back to Earth quickly, on a horse, and leave slowly, riding the cow.\n\n(33) Paper lanterns and offerings are sent floating down rivers to accompany the ancestors back to their resting place. Many areas will also organize bon-odori dances. The style of the dances varies from region to region but is normally based on the rhythms of taiko drums. Performers usually play on a tall stage with lanterns and banners strung all around. Participants, often dressed in light cotton kimonos, are encouraged to dance to the music around the stage. (34) Originally dedicated to the deceased, the dances have now become a symbol of the summer festival themselves.", "bank": ["Some people also visit the cemetery to clean up the family graves and pray for their ancestors.", "Such festive activities are usually held in parks, temples, and other public places around Japan.", "Obon concludes with another bonfire, okuribi, lighting up the sky to see the ancestors' spirits off.", "Originating from the Chinese Ghost Festival, this annual event has evolved into a time of family reunion."]}, {"pid": "111-P5", "year": 111, "type": "閱讀測驗", "text": "Standing proud in the savannah with their red blankets and painted shields, the Maasai people are one of the widely known symbols of East Africa. Their unique style, as remarked by Karen Blixen, author of Out of Africa, \"has grown from the inside, and is an expression of the race and its history.\"\n\nThe Maasai are a semi-nomadic group in Kenya and northern Tanzania, wandering in bands and living almost entirely on the meat, blood, and milk of their herds. Over the years, the fearless tribesmen have stood strong against slavery, and resisted the urging of the Kenyan and Tanzanian governments to adopt a more modern lifestyle. In fact, they are one of the few tribes that have retained most of their traditions. Up until recently, the only way for a Maasai boy to achieve warrior status was to single-handedly kill a lion with his spear.\n\nMaasai clothing varies with age, gender, and place. The most recognizable piece of clothing is the shúkà, a sheet of fabric worn wrapped around the body. Red is a popular color, and women generally opt for checked, striped, or patterned pieces of cloth. Young men wear black for several months after their circumcision, a ritual signifying their coming of age. A Maasai warrior is rarely seen without his spear and shield. In Blixen's words, \"their weapons and finery are as much a part of their being as are a stag's antlers\" (a male deer's horns).\n\nBeadwork is an important part of Maasai culture. Beaded jewelry is made by women, and is famous for its complexity. Natural materials such as clay, shells, and ivory were used before trading with the Europeans in the 19th century. They were then replaced by colorful glass beads, allowing for more detailed beadwork and color patterns. Multicolored beadwork is popular among both men and women. Each color holds a special meaning: White stands for peace, green for land and production, while red—the most favored color among the Maasai—is the symbol of unity and bravery.", "bank": null}, {"pid": "111-P6", "year": 111, "type": "閱讀測驗", "text": "A hard hat is a helmet used mostly at worksites to protect the head from injuries due to falling objects. Since its introduction in the early 20th century, the headgear has saved countless lives and is considered the number one safety tool for construction workers.\n\nThe hard hat was invented in 1919 by Edward W. Bullard, who had just returned from World War I. Before the war, workers used to smear their hats with coal tar for protection of their head. Bullard, having witnessed the life-saving power of the metal helmet in the War, decided to produce a head protection device that was affordable for every worker and lightweight enough to be worn all day long. The Hard Boiled Hat was thus born, using steamed canvas and leather, covered with black paint, and featuring a suspension system to reduce impact. Soon, hard hats became widely used. The headgear was later made mandatory at construction sites in major construction projects, such as the Hoover Dam in 1931 and the Golden Gate Bridge in 1933.\n\nOver the past century, hard hats have advanced considerably, evolving from canvas and leather to aluminum, fiberglass, and, eventually, to thermoplastic. Recently, new models have been introduced and accessories added to meet the needs of laborers working on various job sites. For instance, a ventilated hard hat was developed to keep wearers cooler, and see-through face shields were attached to better see the hazards lurking above. Today, attachments include radios, sensors, cameras, and a lot more. A common color code has also been developed for recognizing people and their roles on site. Yellow is used for general laborers and contractors, white (or sometimes black) for supervisors and managers, and green for inspectors and new workers.\n\nNew products continue to expand the market. Global sales of hard hats totaled USD 2.1 billion in 2016, and are expected to reach USD 3.19 billion in 2025.", "bank": null}, {"pid": "111-P7", "year": 111, "type": "閱讀測驗", "text": "Zebrafish, named for their characteristic stripes, have been a popular test subject for researchers. Only a few centimeters in length, the fish breed easily in captivity, grow quickly, and their transparent body makes it easy to study their organs. Above all, they possess some amazing \"self-healing\" power. When part of their heart is removed, they can grow it back in a matter of weeks. When blinded, they can quickly regain the ability to see.\n\nRecent studies show that humans and zebrafish have the same major organs and share 70 percent of the genes. Moreover, 84 percent of human genes associated with disease find a counterpart in zebrafish. Scientists thus hope that understanding the self-healing mystery of the fish may one day allow humans to regenerate such organs as eyes, hearts, and spines.\n\nResearchers at Vanderbilt University are particularly interested in zebrafish retina regeneration. They have learned that damage of retina can cause blindness in zebrafish, yet it only takes about three to four weeks before vision is restored. The structure and cell types of zebrafish retinas are almost identical to those of humans. If the process can be replicated in humans, it may give rise to new treatments for blindness caused by retinal damage.\n\nIn order to know exactly how zebrafish retina is regenerated, the team looked at the neurotransmitter gamma-aminobutyric acid (GABA), a chemical messenger in the brain that reduces the activity of neurons. They found that lowering GABA levels in zebrafish can trigger retina regeneration, while a high level of GABA concentration will suppress the regeneration process. This suggested that GABA plays an important role in the fish's ability to regain their sight.\n\nThe team is beginning to test the GABA theory on mice. If that works, human trials will be next on the agenda. If the research proves successful in humans, some of the nearly 40 million blind people worldwide may one day have a tiny, striped fish to thank.", "bank": null}, {"pid": "111-P8", "year": 111, "type": "閱讀測驗", "text": "To support refugees and people facing crises around the world, the International Olympic Committee created the Refugee Olympic Team. Refugee athletes have been invited to compete in the Olympic Games since 2016. Here are two refugee athletes and their stories.\n\nYusra Mardini is a swimmer who grew up in the war-torn country of Syria. Due to the unstable political situation there, Yusra sometimes had to train in pools under roofs that had been blown open by bombings. In 2015 when she was just a 17-year-old, her house was destroyed in the civil war, so she decided to flee her home country. She managed to reach Turkey through Lebanon. From Turkey, she boarded a small boat that held 20 people and set sail into the deep waters of the Aegean Sea. But 30 minutes later, the engine stopped and the boat began to sink. Yusra dove into the cold water, and—with the help of her sister and two men—swam and pushed the boat for over three hours to reach the Greek island of Lesbos. They saved everyone aboard. Yusra eventually settled in Germany and has since worked to inspire others to pursue their dreams. Her incredible story and superior swimming skills won her the opportunity to participate in the Olympic Games. She was a member of the Refugee Olympic Team for both the 2016 Rio Games and 2021 Tokyo Games.\n\nPopole Misenga was born in the Democratic Republic of the Congo. When he was nine, the country's civil war claimed the life of his mother and left him homeless. Escaping from the war zone, he wandered alone for a week in a rainforest before being rescued and taken to a center for displaced children in the capital, Kinshasa. There, Popole discovered judo, from which he gained strength in body and mind. \"Judo helped me by giving me serenity, discipline, commitment—everything,\" he said. He trained hard and became a professional judoka. However, each time he lost a competition, his coaches would lock him in a cage for days, feeding him only coffee and bread. Finally, when he was cruelly abused for not winning medals at the 2013 World Championships in Brazil, he decided to seek protection. Popole was granted asylum in 2014 by Brazilian government and later continued judo training at a youth facility. He made his Olympic debut at Rio 2016. He also represented the Refugee Olympic Team in 2021 Tokyo Games.", "bank": null}, {"pid": "110-P1", "year": 110, "type": "綜合測驗", "text": "Street pigeons are a common sight in many European cities. In fact, a visit to a major European city just would not be the same (16) encountering them: bathing in fountains, perching on historic buildings, and flocking in public squares. In Barcelona, however, the birds are now threatening to (17) the city's historic center, pooping on monuments, buildings, and even tourists.\n\nThe city council originally proposed (18) the pigeon population by gathering the birds and shooting them. But that idea led to strong protests from numerous animal rights groups. After heated debates and discussions, the government was finally persuaded to consider another (19) effective method: giving the pigeons birth control.\n\nIn 2016, the city council decided to put its 85,000 pigeon population on a birth control pill to block the formation of eggs in birds. Starting from April 2017, the pills were placed in 40 bird feeders (20) throughout the city. It was predicted that there would be a decrease of 20 percent in the pigeon population in the first year and between 70 and 80 percent in four or five years.", "bank": null}, {"pid": "110-P2", "year": 110, "type": "綜合測驗", "text": "Being hit by lightning is a rare event. Over the course of an 80-year life span, the odds of being hit by lightning are 1 in 3,000, (21) the probability of being struck seven different times. Roy Sullivan, a park ranger in the United States, was struck by lightning more recorded times than any other human being. Over his 36-year career, Sullivan was struck by lightning seven times—and (22) each shock!\n\nStrikes one, two, and three were pure bad luck, he thought. But after strike four, Sullivan became (23) death and took precautions during lightning strikes. Strike five occurred in 1973 when Sullivan was on patrol. A storm cloud \"chased\" him until he was struck. The same thing happened again in 1976. Sullivan, while surveying a campground, felt that a cloud was (24) him, and tried all he could to run—but it got him anyway. Finally, on June 1977, a seventh and final bolt struck Sullivan as he was fishing in a pond. \"I don't believe God is after me,\" he theorized. \"If he was, the first bolt (25) enough. Best I can figure is that I have some chemical, some mineral, in my body that draws lightning. I just wish I knew.\"", "bank": null}, {"pid": "110-P3", "year": 110, "type": "綜合測驗", "text": "Glaciers are usually associated with colder climates. But some mountain ranges of South America, Africa, and Indonesia are also (26) glaciers and ice sheets. These tropical glaciers serve as a major source of water supply to one-sixth of the world's population.\n\nA newly published study, however, revealed that rising temperatures are posing an (27) threat to the last tropical glaciers in Indonesia's Papua region. The ice sheets, which once spanned 20 square kilometers, are thinning over five times as quickly compared to a few years ago. (28) already shrunk by 85% to a mere 0.5 square kilometers, Papua's glaciers will completely disappear within a decade, researchers have predicted.\n\nThe disappearance of the glaciers will also leave a significant (29) impact. For many indigenous Papuans, the ice sheets represent a sacred symbol. \"The mountains and valleys are the arms and legs of their god and the glaciers are the head,\" explained the head researcher.\n\nThe study warned that Papua's glaciers are only the \"first to go\" if greenhouse gases are (30) and temperatures continue rising. And this is certainly a serious warning about the depressing fate of other glaciers around the world.", "bank": null}, {"pid": "110-P4", "year": 110, "type": "文意選填", "text": "If you cannot find ways to fit exercise into your busy daily schedule, don't worry! Exercise doesn't always have to be laborious. Research shows that (31) amounts of exercise—even just 15 minutes a day—helps ease depression, enhance self-image, relieve stress, and much more. That's right. Doing exercise makes you happy, and you don't have to be a fitness (32) to do it. What you need to do is to make \"start slow and have fun\" a motto to (33). Then you'll be well on your way to using physical activity as a tool to make you feel better every day.\n\nThe \"no pain, no gain\" view of exercise is now considered old-fashioned. In fact, (34) health studies prove that exercise doesn't have to hurt to be effective. You might (35) that if working out doesn't give you pain, it isn't working. According to fitness trainers, physically (36) exercises may make you breathe heavily and your muscles may ache temporarily, but exercise should not be painful. In fact, if it is, it may (37) an injury or muscle strain. Many great forms of exercise—like walking, swimming, or gentle stretching—get results without the (38) or discomfort some people associate with exercise.\n\nFor the sake of your health, it is time to make regular exercise a part of your life. Keep in mind that even short periods of low-impact exercise serve as a powerful (39) to improve your health. So, no matter how busy you are, try to (40) for exercise every day, like a 15-minute walk with your dog. Your body will thank you in many ways.", "bank": ["means", "soreness", "point to", "argue", "demanding", "abide by", "fanatic", "current", "make time", "modest"]}, {"pid": "110-P5", "year": 110, "type": "閱讀測驗", "text": "The prickly pear cactus is such a powerful symbol in Mexico that it occupies a prime spot on Mexico's national flag. The plant was considered sacred by the ancient Aztecs, and modern-day Mexicans eat it, drink it, and even use it in medicines and shampoos. Now scientists have come up with a new use for the bright green plant: producing renewable energy.\n\nKnown locally as nopal, the prickly pear is farmed on a massive scale in Mexico. Over the years, only the edible soft inner flesh has been used. The cactus's thick outer layer (i.e., husk), with all those spines, had always been viewed as a waste product until researchers developed a biogas generator to turn the husks into electricity.\n\nThe pilot project dedicated to developing the cactus biogas generator began in the south of Mexico City. The area produces 200,000 tons a year of prickly pear cactus—up to 10 tons of which ends up as waste on the floor of the cactus market each day. Then, a local green energy startup company got the idea to turn that waste into energy. The generator is now in place at the cactus market, where the vendors are enthusiastic about this new way to utilize the tons of cactus husks that once went directly into the trash.\n\nThe prickly pear has a number of advantages over other biofuel crops, such as wheat, sugarcane, and soybeans. For one thing, only the husk of the cactus is used for generating biofuel, while its inner flesh is still preserved for food. Therefore, using the plant as a fuel source will not put pressure on food prices. Moreover, the cactus requires minimum water, and thus is not grown on traditional agricultural pasture. This means that no increased competition arises for the water or land presently used for food production.\n\nThe project in Mexico City has brought new hope to reducing the use of fossil fuels. If it can be expanded, the prickly pear could be the key to Mexico's energy future.", "bank": null}, {"pid": "110-P6", "year": 110, "type": "閱讀測驗", "text": "The concept of a travel document, which shows a person is under a ruler's protection while in a foreign land, has probably existed since rulers and states were first invented. But the earliest mention of an object which we might recognize as a passport appeared in about 450 B.C. The Hebrew Bible states that Nehemiah, an official serving King Artaxerxes of ancient Persia, asked permission to travel to Judah. The King agreed and gave Nehemiah a letter \"to the governors of the province beyond the river,\" requesting safe passage for him as he travelled through their lands.\n\nLater, in the medieval Islamic Caliphate, a form of passport was the bara'a, a receipt for taxes paid. Only people who paid their taxes were permitted to travel to different regions of the Caliphate. In medieval Europe, on the other hand, travel documents were issued by local authorities, and generally contained a list of towns and cities which the document holder was permitted to enter or pass through. On the whole, documents were not required for travel to seaports, which were considered open trading points, but documents were required to travel inland from seaports.\n\nKing Henry V of England is credited with having invented the first true passport, as a way of helping his subjects prove who they were in foreign lands. The earliest reference to these documents is found in a 15th-century Act of Parliament, while the term \"passport\" came into use about a century later. Nevertheless, passports were not generally required for international travel until the First World War. It was at this time that passports as we would recognize them today began to be used.", "bank": null}, {"pid": "110-P7", "year": 110, "type": "閱讀測驗", "text": "Benjamin Franklin, one of the Founding Fathers of the United States, was not only a great politician but also a highly accomplished scientist and inventor. Of his many achievements, probably the least well-known are his accomplishments in music. He invented an instrument for which both Mozart and Beethoven composed music—the glass armonica.\n\nIn 1761, while living in England, Franklin heard a performer playing musical glasses. Franklin was charmed by the music, but felt that there was a better way to create the same sound. He had a glassmaker create thirty-seven hemispheres made of glass, with each being a different size and thickness to produce different pitches. The glass hemispheres were color coded with paint to identify the notes. Franklin ran an iron rod through a hole in the top of each hemisphere so that they could nest together from largest to smallest. He linked all of this to a device shaped like a spinning wheel, with a foot control that turned the rod, making the glass hemispheres rotate. Franklin moistened his fingers and held them against the rims of the glass hemispheres as they turned, producing a unique sound. He mastered the instrument and took it to parties and gatherings to play for his friends and acquaintances. The instrument became so popular that thousands were built and sold.\n\nBut musical fashions changed. Music was moving out of the relatively small halls of Mozart's day into the large concert halls of the 19th century, and without amplification, the glass armonica simply couldn't be heard. Concert reviews from the period mourned the fact that the armonica sounded wonderful—only when it could be heard. So, alas, Franklin's marvelous invention was ultimately abandoned. The popularity of the instrument faded early in the 19th century, but it is still played occasionally today.", "bank": null}, {"pid": "110-P8", "year": 110, "type": "閱讀測驗", "text": "Morgan's Wonderland, located in San Antonio, Texas, is a theme park geared mainly toward mentally or physically disabled children. The park was built by Gordon Hartman, a former real estate developer. The creation of the park was inspired by his daughter, Morgan, who suffers from severe cognitive delay and physical challenges.\n\nThe world's first ultra-accessible family fun park, Morgan's Wonderland opened in the spring of 2010. Admission for guests with special needs is free, and fees for the general public are set at a much discounted price so that people of all ages and abilities can come together and play in a fun and safe environment.\n\nCompletely wheelchair-accessible, the park features 25 acres of attractions including rides, playgrounds, a catch-and-release fishing lake, and picnic areas throughout the park. The rides are custom-designed to accommodate wheelchair riders so that every family member can enjoy the fun. The adapted rides include the Off-Road Adventure, where guests can test their driving skills in sporty vehicles. Moreover, each visitor is offered the option to wear a GPS Adventure Band, which allows them to keep track of each other while in the park. The band also enables them to take part in electronic activities. For example, when the riders scan the band at the Off-Road Adventure, a photo will be taken and sent to their email.\n\nIn June 2017, Morgan's Wonderland celebrated the opening of Morgan's Inspiration Island. The new expansion is composed of five themed splash pads and a River Boat Adventure Ride. The wheelchair guests can transfer out of their chairs into unique, waterproof chairs and enjoy the splash park without risking damage to their personal wheelchairs.\n\n\"Morgan taught me that there's more to life in many ways than what I saw before,\" said Hartman. \"The blessing that Morgan has brought is beyond anything that I ever could have imagined and could explain.\"", "bank": null}], "meta": {"src": "大學入學考試中心 學測英文 110–115", "multiExcluded": 5, "qaFixed": "round1"}, "lecture": {"hardWords": [{"word": "tight", "pos": "adj.", "zh": "緊的；緊繃的；(時間/金錢)吃緊的", "theme": "描述形容"}, {"word": "amateur", "pos": "n./adj.", "zh": "業餘者；業餘的、非專業的", "theme": "其他"}, {"word": "vacancy", "pos": "n.", "zh": "空缺；空房；職缺", "theme": "抽象名詞"}, {"word": "initially", "pos": "adv.", "zh": "起初；最初", "theme": "其他"}, {"word": "consumption", "pos": "n.", "zh": "消耗；消費(量)", "theme": "抽象名詞"}, {"word": "dreads", "pos": "v.", "zh": "害怕；畏懼(dread 的三單)", "theme": "情緒態度"}, {"word": "passion", "pos": "n.", "zh": "熱情；熱愛", "theme": "情緒態度"}, {"word": "assaulted", "pos": "v.", "zh": "攻擊；襲擊(assault 過去式)", "theme": "動作"}, {"word": "elbow", "pos": "n./v.", "zh": "手肘；用手肘推擠", "theme": "動作"}, {"word": "grave", "pos": "adj./n.", "zh": "嚴重的；嚴肅的；墳墓", "theme": "描述形容"}, {"word": "container", "pos": "n.", "zh": "容器；貨櫃", "theme": "其他"}, {"word": "produce", "pos": "v./n.", "zh": "生產、製造；(不可數)農產品", "theme": "動作"}, {"word": "blurring", "pos": "v.", "zh": "使模糊；界線變模糊(blur 進行式)", "theme": "動作"}, {"word": "offensive", "pos": "adj.", "zh": "冒犯的；令人反感的；攻擊性的", "theme": "描述形容"}, {"word": "draft", "pos": "n./v.", "zh": "草稿；徵召；起草", "theme": "其他"}, {"word": "vacant", "pos": "adj.", "zh": "空的；空缺的；(神情)茫然的", "theme": "描述形容"}, {"word": "enormous", "pos": "adj.", "zh": "巨大的；龐大的", "theme": "描述形容"}, {"word": "halted", "pos": "v.", "zh": "(使)停止(halt 過去式)", "theme": "動作"}, {"word": "graced", "pos": "v.", "zh": "使增光；為…增添光彩(grace 過去式)", "theme": "動作"}, {"word": "verbally", "pos": "adv.", "zh": "口頭上地；用言語地", "theme": "其他"}, {"word": "slender", "pos": "adj.", "zh": "苗條的；纖細的；微薄的", "theme": "描述形容"}, {"word": "emerging", "pos": "adj./v.", "zh": "新興的；正浮現的", "theme": "描述形容"}, {"word": "due", "pos": "adj.", "zh": "到期的；預定的；應得的", "theme": "其他"}, {"word": "humidity", "pos": "n.", "zh": "濕度；潮濕", "theme": "學術"}, {"word": "stand", "pos": "n./v.", "zh": "立場；攤位；忍受；站立", "theme": "其他"}, {"word": "compulsory", "pos": "adj.", "zh": "強制的；義務的；必修的", "theme": "描述形容"}, {"word": "credit", "pos": "n./v.", "zh": "信用；學分；讚揚；歸功於", "theme": "抽象名詞"}, {"word": "promises", "pos": "n./v.", "zh": "承諾；保證(promise 複數/三單)", "theme": "抽象名詞"}, {"word": "appeal", "pos": "n./v.", "zh": "吸引力；呼籲；上訴", "theme": "抽象名詞"}, {"word": "randomly", "pos": "adv.", "zh": "隨機地；任意地", "theme": "其他"}, {"word": "sticky", "pos": "adj.", "zh": "黏的；棘手的", "theme": "描述形容"}, {"word": "pose", "pos": "v./n.", "zh": "造成(問題)；擺姿勢；假冒", "theme": "動作"}, {"word": "ancestors", "pos": "n.", "zh": "祖先；祖宗", "theme": "其他"}, {"word": "bare", "pos": "adj.", "zh": "赤裸的；光禿的；空無一物的", "theme": "描述形容"}, {"word": "sincerity", "pos": "n.", "zh": "真誠；誠懇", "theme": "情緒態度"}, {"word": "recall", "pos": "v./n.", "zh": "回想；記起；召回", "theme": "動作"}, {"word": "counter", "pos": "n./v.", "zh": "櫃檯；反駁；抵制", "theme": "其他"}, {"word": "crippled", "pos": "v./adj.", "zh": "使殘廢；使嚴重受損(cripple 過去式)", "theme": "動作"}, {"word": "choked", "pos": "v.", "zh": "使窒息；哽住；哽咽(choke 過去式)", "theme": "動作"}, {"word": "supposedly", "pos": "adv.", "zh": "據說；按理說；照理", "theme": "其他"}, {"word": "delivered", "pos": "v.", "zh": "遞送；發表(演說)；分娩(deliver 過去式)", "theme": "動作"}, {"word": "assistant", "pos": "n.", "zh": "助理；助手", "theme": "其他"}, {"word": "puppet", "pos": "n.", "zh": "木偶；傀儡", "theme": "其他"}, {"word": "potentially", "pos": "adv.", "zh": "潛在地；可能地", "theme": "其他"}, {"word": "Tagging", "pos": "v.", "zh": "標記；加標籤(tag 動名詞)", "theme": "動作"}, {"word": "agreeable", "pos": "adj.", "zh": "令人愉快的；欣然同意的", "theme": "描述形容"}, {"word": "visible", "pos": "adj.", "zh": "看得見的；明顯的", "theme": "描述形容"}, {"word": "eventual", "pos": "adj.", "zh": "最終的；最後發生的", "theme": "其他"}, {"word": "quest", "pos": "n.", "zh": "追求；探索；尋求", "theme": "抽象名詞"}, {"word": "blushes", "pos": "v.", "zh": "臉紅；害臊(blush 三單)", "theme": "情緒態度"}, {"word": "tease", "pos": "v.", "zh": "取笑；戲弄；逗弄", "theme": "動作"}, {"word": "escalator", "pos": "n.", "zh": "手扶梯；電扶梯", "theme": "其他"}, {"word": "obediently", "pos": "adv.", "zh": "順從地；聽話地", "theme": "情緒態度"}, {"word": "moist", "pos": "adj.", "zh": "潮濕的；濕潤的", "theme": "描述形容"}, {"word": "parachute", "pos": "n.", "zh": "降落傘", "theme": "其他"}, {"word": "revolutionary", "pos": "adj.", "zh": "革命性的；劃時代的", "theme": "描述形容"}, {"word": "interaction", "pos": "n.", "zh": "互動；交互作用", "theme": "抽象名詞"}, {"word": "tumbled", "pos": "v.", "zh": "跌倒；翻滾；暴跌(tumble 過去式)", "theme": "動作"}, {"word": "kits", "pos": "n.", "zh": "成套工具；配件組(kit 複數)", "theme": "其他"}, {"word": "jointly", "pos": "adv.", "zh": "共同地；聯合地", "theme": "其他"}, {"word": "flourishing", "pos": "adj./v.", "zh": "繁榮的；興旺的；茂盛的", "theme": "描述形容"}, {"word": "absurd", "pos": "adj.", "zh": "荒謬的；荒唐的", "theme": "描述形容"}, {"word": "singular", "pos": "adj.", "zh": "單數的；非凡的；奇特的", "theme": "描述形容"}, {"word": "committed", "pos": "adj./v.", "zh": "投入的；堅定的；犯下(commit 過去式)", "theme": "描述形容"}, {"word": "resumed", "pos": "v.", "zh": "恢復；重新開始(resume 過去式)", "theme": "動作"}], "phrases": [{"phrase": "it turns out", "zh": "結果發現；原來(是)", "use": "引出出乎意料的事實，後常接 that 子句，是綜合測驗常見的轉折開場"}, {"phrase": "as such", "zh": "因此；就其本身而言", "use": "承上啟下，指「以這樣的身分/性質」而導致下文，屬正式因果連接語"}, {"phrase": "gave rise to", "zh": "引起；導致", "use": "give rise to + N 的固定因果搭配，主詞是原因、後接結果"}, {"phrase": "thus", "zh": "因此；從而", "use": "連接副詞，表推論或結果，前後常用逗號或分號，較正式"}, {"phrase": "less likely", "zh": "較不可能", "use": "比較級，常與 more likely 對比，後接 to V；判斷時要看語意方向"}, {"phrase": "responsive to", "zh": "對…有反應的；順應…的", "use": "be responsive to + N 的固定搭配，形容詞 + 介系詞 to"}, {"phrase": "meant to be", "zh": "註定；本應如此", "use": "be meant to V，表「原本用意」或「命中註定」，考點在被動與慣用法"}, {"phrase": "pose as", "zh": "假冒；冒充", "use": "動詞片語，假裝成某種身分；別和 pose a threat(造成)混淆"}, {"phrase": "had yet to develop", "zh": "(當時)尚未發展出", "use": "have yet to V = 還沒做某事；此處過去完成式表過去某時點前尚未發生"}, {"phrase": "not to mention", "zh": "更不用說", "use": "遞進語氣，在已有論點後再補一個更強的例證"}, {"phrase": "Despite", "zh": "儘管；縱使", "use": "介系詞，後接名詞或動名詞表讓步轉折；注意不可像 although 直接接句子"}, {"phrase": "free of", "zh": "免於；沒有", "use": "free of charge / free of + N，表「不含、免除」"}, {"phrase": "other than", "zh": "除了…之外", "use": "表排除，常用於否定句或 anything/nothing other than 結構"}, {"phrase": "spell disaster", "zh": "招致災難；意味著大麻煩", "use": "spell + 負面名詞，表「將帶來(某後果)」的慣用法"}, {"phrase": "take over", "zh": "接管；取代", "use": "動詞片語，指接手職務或被取而代之，科技類文章常見"}, {"phrase": "accompanied by", "zh": "伴隨著；隨…而來", "use": "be/come accompanied by + N，被動搭配，表同時發生"}, {"phrase": "similarly", "zh": "同樣地；相似地", "use": "類比連接副詞，帶出與前文相似的論點或例子"}, {"phrase": "fearful of", "zh": "害怕…；擔憂…", "use": "be fearful of + N/V-ing 的情緒形容詞搭配"}, {"phrase": "home to", "zh": "是…的所在地；棲息著", "use": "be home to + N，介紹某地擁有某事物或生物"}, {"phrase": "left unchecked", "zh": "若放任不管", "use": "過去分詞當條件 = if it is left unchecked，簡潔表假設後果"}, {"phrase": "exposure to", "zh": "接觸；暴露於", "use": "exposure to + N，名詞 + 介系詞 to 的固定搭配"}, {"phrase": "compete for", "zh": "競爭；爭奪", "use": "compete for + N(獎項/資源)；for 表爭取的目標"}, {"phrase": "as well", "zh": "也；同樣", "use": "置於句尾，補充附加訊息，語氣中性"}], "strategies": [{"type": "詞彙題", "tip": "先看空格前後的搭配詞判斷詞性：名詞前常有冠詞或形容詞，動詞要看時態與主詞。再讀整句抓語意方向(正面/負面、因果/對比)縮小範圍。四個選項通常同詞性，靠精準語意與慣用搭配取捨，千萬別被拼字相近或中文近義的字誤導。"}, {"type": "綜合測驗", "tip": "重點在邏輯與搭配。填連接詞(thus、despite、similarly)要先看前後句是因果、對比還是並列；填動詞或片語要看主詞和慣用搭配。務必整段讀完再回填，很多答案的線索在下一句而不是空格那一句。時態、單複數、主動被動也要一併對。"}, {"type": "文意選填", "tip": "先用文法結構判斷每個空格需要什麼詞性，把選項依詞性分堆。再靠語意和搭配一一對應，填一個就把用過的字劃掉(刪去法)。剩下難的空格用排除法反推。特別留意單複數、時態、主被動，這些常是正確與陷阱選項的差別。"}, {"type": "篇章結構", "tip": "這題考句子插入與段落銜接，關鍵是找「線索膠水」：代名詞(this、they、it)、指示詞、連接詞。插入的句子要和前後語意連貫、指涉一致。放進去後一定要回讀，確認前句提到的東西後句有承接，時間與邏輯順序不跳接。"}, {"type": "閱讀測驗", "tip": "先看題目再回文定位，不要盲目全文精讀。主旨題看首尾段和重複出現的關鍵字；細節題回原文找對應句；推論題要有文本依據、別過度腦補；字義題用上下文猜。小心 not/except 題和陷阱選項(偷換範圍、誇大、無中生有)。"}]}};